CREATE INDEX idx_items_name_cn ON items(item_name_cn) WHERE deleted_at IS NULL;
CREATE INDEX idx_items_type ON items(item_type) WHERE deleted_at IS NULL;

CREATE TRIGGER trigger_items_updated_at
