  ) THEN
    ALTER TABLE delivery_notes
      ADD CONSTRAINT delivery_notes_fulfilling_warehouse_id_fkey
      FOREIGN KEY (fulfilling_warehouse_id) REFERENCES warehouses(id);
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
