-- ============================================================================
-- Migration: 20260217123000_remove_legacy_warehouse_columns.sql
-- ============================================================================

-- Migration: Remove legacy SR/DN warehouse columns after canonical cutover
-- Date: 2026-02-17

BEGIN;

-- Recompile delivery-note posting functions to use canonical columns.
DO $$
DECLARE
  v_sig regprocedure;
  v_def text;
  v_new_def text;
BEGIN
  FOR v_sig, v_def IN
    SELECT
      p.oid::regprocedure,
      pg_get_functiondef(p.oid)
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = 'public'
      AND p.proname IN ('post_delivery_note_dispatch', 'post_delivery_note_receive')
  LOOP
    v_new_def := replace(v_def, 'source_entity_id', 'requesting_warehouse_id');
    v_new_def := replace(v_new_def, 'destination_entity_id', 'fulfilling_warehouse_id');

    IF v_new_def <> v_def THEN
      EXECUTE v_new_def;
    END IF;
  END LOOP;
END $$;

-- Remove compatibility triggers/functions from previous migration.
DROP TRIGGER IF EXISTS trg_sync_stock_requests_warehouse_columns ON stock_requests;
DROP TRIGGER IF EXISTS trg_sync_delivery_notes_warehouse_columns ON delivery_notes;
DROP TRIGGER IF EXISTS trg_sync_delivery_note_items_warehouse_columns ON delivery_note_items;

DROP FUNCTION IF EXISTS sync_stock_requests_warehouse_columns();
DROP FUNCTION IF EXISTS sync_delivery_notes_warehouse_columns();
DROP FUNCTION IF EXISTS sync_delivery_note_items_warehouse_columns();

-- Recreate stock request RLS policies against canonical column names.
DROP POLICY IF EXISTS bu_select_policy ON stock_requests;
CREATE POLICY bu_select_policy ON stock_requests
    FOR SELECT
    TO authenticated
    USING (
        business_unit_id IN (
            SELECT business_unit_id
            FROM user_business_unit_access
            WHERE user_id = auth.uid()
        )
        OR requesting_warehouse_id IN (
            SELECT w.id
            FROM warehouses w
            WHERE w.business_unit_id IN (
                SELECT business_unit_id
                FROM user_business_unit_access
                WHERE user_id = auth.uid()
            )
        )
        OR fulfilling_warehouse_id IN (
            SELECT w.id
            FROM warehouses w
            WHERE w.business_unit_id IN (
                SELECT business_unit_id
                FROM user_business_unit_access
                WHERE user_id = auth.uid()
            )
        )
    );

DROP POLICY IF EXISTS bu_update_policy ON stock_requests;
CREATE POLICY bu_update_policy ON stock_requests
    FOR UPDATE
    TO authenticated
    USING (
        business_unit_id IN (
            SELECT business_unit_id
            FROM user_business_unit_access
            WHERE user_id = auth.uid()
        )
        OR requesting_warehouse_id IN (
            SELECT w.id
            FROM warehouses w
            WHERE w.business_unit_id IN (
                SELECT business_unit_id
                FROM user_business_unit_access
                WHERE user_id = auth.uid()
            )
        )
        OR fulfilling_warehouse_id IN (
            SELECT w.id
            FROM warehouses w
            WHERE w.business_unit_id IN (
                SELECT business_unit_id
                FROM user_business_unit_access
                WHERE user_id = auth.uid()
            )
        )
    );

DROP POLICY IF EXISTS bu_delete_policy ON stock_requests;
CREATE POLICY bu_delete_policy ON stock_requests
    FOR DELETE
    TO authenticated
    USING (
        business_unit_id IN (
            SELECT business_unit_id
            FROM user_business_unit_access
            WHERE user_id = auth.uid()
        )
        OR requesting_warehouse_id IN (
            SELECT w.id
            FROM warehouses w
            WHERE w.business_unit_id IN (
                SELECT business_unit_id
                FROM user_business_unit_access
                WHERE user_id = auth.uid()
            )
        )
        OR fulfilling_warehouse_id IN (
            SELECT w.id
            FROM warehouses w
            WHERE w.business_unit_id IN (
                SELECT business_unit_id
                FROM user_business_unit_access
                WHERE user_id = auth.uid()
            )
        )
    );

DROP POLICY IF EXISTS bu_select_policy ON stock_request_items;
CREATE POLICY bu_select_policy ON stock_request_items
    FOR SELECT
    TO authenticated
    USING (
        EXISTS (
            SELECT 1 FROM stock_requests sr
            WHERE sr.id = stock_request_items.stock_request_id
            AND (
                sr.business_unit_id IN (
                    SELECT business_unit_id
                    FROM user_business_unit_access
                    WHERE user_id = auth.uid()
                )
                OR sr.requesting_warehouse_id IN (
                    SELECT w.id
                    FROM warehouses w
                    WHERE w.business_unit_id IN (
                        SELECT business_unit_id
                        FROM user_business_unit_access
                        WHERE user_id = auth.uid()
                    )
                )
                OR sr.fulfilling_warehouse_id IN (
                    SELECT w.id
                    FROM warehouses w
                    WHERE w.business_unit_id IN (
                        SELECT business_unit_id
                        FROM user_business_unit_access
                        WHERE user_id = auth.uid()
                    )
                )
            )
        )
    );

DROP POLICY IF EXISTS bu_update_policy ON stock_request_items;
CREATE POLICY bu_update_policy ON stock_request_items
    FOR UPDATE
    TO authenticated
    USING (
        EXISTS (
            SELECT 1 FROM stock_requests sr
            WHERE sr.id = stock_request_items.stock_request_id
            AND (
                sr.business_unit_id IN (
                    SELECT business_unit_id
                    FROM user_business_unit_access
                    WHERE user_id = auth.uid()
                )
                OR sr.requesting_warehouse_id IN (
                    SELECT w.id
                    FROM warehouses w
                    WHERE w.business_unit_id IN (
                        SELECT business_unit_id
                        FROM user_business_unit_access
                        WHERE user_id = auth.uid()
                    )
                )
                OR sr.fulfilling_warehouse_id IN (
                    SELECT w.id
                    FROM warehouses w
                    WHERE w.business_unit_id IN (
                        SELECT business_unit_id
                        FROM user_business_unit_access
                        WHERE user_id = auth.uid()
                    )
                )
            )
        )
    );

DROP POLICY IF EXISTS bu_delete_policy ON stock_request_items;
CREATE POLICY bu_delete_policy ON stock_request_items
    FOR DELETE
    TO authenticated
    USING (
        EXISTS (
            SELECT 1 FROM stock_requests sr
            WHERE sr.id = stock_request_items.stock_request_id
            AND (
                sr.business_unit_id IN (
                    SELECT business_unit_id
                    FROM user_business_unit_access
                    WHERE user_id = auth.uid()
                )
                OR sr.requesting_warehouse_id IN (
                    SELECT w.id
                    FROM warehouses w
                    WHERE w.business_unit_id IN (
                        SELECT business_unit_id
                        FROM user_business_unit_access
                        WHERE user_id = auth.uid()
                    )
                )
                OR sr.fulfilling_warehouse_id IN (
                    SELECT w.id
                    FROM warehouses w
                    WHERE w.business_unit_id IN (
                        SELECT business_unit_id
                        FROM user_business_unit_access
                        WHERE user_id = auth.uid()
                    )
                )
            )
        )
    );

-- Drop legacy constraints/indexes tied to old columns.
ALTER TABLE stock_requests DROP CONSTRAINT IF EXISTS stock_requests_source_warehouse_id_fkey;
ALTER TABLE stock_requests DROP CONSTRAINT IF EXISTS stock_requests_destination_warehouse_id_fkey;
DROP INDEX IF EXISTS idx_stock_requests_warehouse;

ALTER TABLE delivery_notes DROP CONSTRAINT IF EXISTS delivery_notes_source_entity_id_fkey;
ALTER TABLE delivery_notes DROP CONSTRAINT IF EXISTS delivery_notes_destination_entity_id_fkey;
ALTER TABLE delivery_notes DROP CONSTRAINT IF EXISTS delivery_notes_source_destination_check;
DROP INDEX IF EXISTS idx_dn_source_dest;

ALTER TABLE delivery_note_items DROP CONSTRAINT IF EXISTS delivery_note_items_source_entity_id_fkey;
ALTER TABLE delivery_note_items DROP CONSTRAINT IF EXISTS delivery_note_items_destination_entity_id_fkey;
ALTER TABLE delivery_note_items DROP CONSTRAINT IF EXISTS delivery_note_items_source_destination_check;
DROP INDEX IF EXISTS idx_dni_company_route;

-- Remove legacy columns.
ALTER TABLE stock_requests
  DROP COLUMN IF EXISTS source_warehouse_id,
  DROP COLUMN IF EXISTS destination_warehouse_id;

ALTER TABLE delivery_notes
  DROP COLUMN IF EXISTS source_entity_id,
  DROP COLUMN IF EXISTS destination_entity_id;

ALTER TABLE delivery_note_items
  DROP COLUMN IF EXISTS source_entity_id,
  DROP COLUMN IF EXISTS destination_entity_id;

COMMIT;


-- ============================================================================
-- Migration: 20260217130000_fix_dn_dispatch_receive_warehouse_direction.sql
-- ============================================================================

-- Fix DN stock movement direction after warehouse role rename.
-- Dispatch must consume stock from fulfilling warehouse.
-- Receive must add stock to requesting warehouse.

BEGIN;

DO $$
DECLARE
  v_sig regprocedure;
  v_def text;
  v_new_def text;
BEGIN
  FOR v_sig, v_def IN
    SELECT
      p.oid::regprocedure,
      pg_get_functiondef(p.oid)
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = 'public'
      AND p.proname = 'post_delivery_note_dispatch'
  LOOP
    v_new_def := replace(
      v_def,
      'COALESCE(v_dn_item.requesting_warehouse_id, v_dn.requesting_warehouse_id)',
      'COALESCE(v_dn_item.fulfilling_warehouse_id, v_dn.fulfilling_warehouse_id)'
    );

    IF v_new_def <> v_def THEN
      EXECUTE v_new_def;
    END IF;
  END LOOP;
END $$;

DO $$
DECLARE
  v_sig regprocedure;
  v_def text;
  v_new_def text;
BEGIN
  FOR v_sig, v_def IN
    SELECT
      p.oid::regprocedure,
      pg_get_functiondef(p.oid)
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = 'public'
      AND p.proname = 'post_delivery_note_receive'
  LOOP
    v_new_def := replace(
      v_def,
      'COALESCE(v_dn_item.fulfilling_warehouse_id, v_dn.fulfilling_warehouse_id)',
      'COALESCE(v_dn_item.requesting_warehouse_id, v_dn.requesting_warehouse_id)'
    );

    IF v_new_def <> v_def THEN
      EXECUTE v_new_def;
    END IF;
  END LOOP;
END $$;

COMMIT;


-- ============================================================================
-- Migration: 20260217133000_expand_stock_request_status_for_dn_derived.sql
-- ============================================================================

-- Allow DN-derived SR statuses in stock_requests.status cache.

BEGIN;

ALTER TABLE stock_requests
DROP CONSTRAINT IF EXISTS stock_requests_status_check;

ALTER TABLE stock_requests
ADD CONSTRAINT stock_requests_status_check
CHECK (
  status IN (
    'draft',
    'submitted',
    'approved',
    'ready_for_pick',
    'picking',
    'picked',
    'delivered',
    'received',
    'completed',
    'cancelled',
    'allocating',
    'partially_allocated',
    'allocated',
    'dispatched',
    'partially_fulfilled',
    'fulfilled'
  )
);

COMMENT ON COLUMN stock_requests.status IS
  'Workflow + derived cache status: draft/submitted/approved/ready_for_pick/picking/picked/delivered/received/completed/cancelled + allocating/partially_allocated/allocated/dispatched/partially_fulfilled/fulfilled';

COMMIT;


-- ============================================================================
-- Migration: 20260217180500_enable_realtime_for_delivery_and_pick_tables.sql
-- ============================================================================

-- Ensure core delivery/picking tables are published to Supabase realtime.
-- Extend the list below for additional modules that need realtime updates.
DO $$
DECLARE
  v_table TEXT;
BEGIN
  FOR v_table IN
    SELECT unnest(ARRAY[
      'delivery_notes',
      'delivery_note_items',
      'pick_lists',
      'pick_list_items'
    ])
  LOOP
    IF EXISTS (
      SELECT 1
      FROM pg_class c
      JOIN pg_namespace n ON n.oid = c.relnamespace
      WHERE n.nspname = 'public'
        AND c.relname = v_table
        AND c.relkind = 'r'
    )
    AND NOT EXISTS (
      SELECT 1
      FROM pg_publication p
      JOIN pg_publication_rel pr ON pr.prpubid = p.oid
      JOIN pg_class c ON c.oid = pr.prrelid
      JOIN pg_namespace n ON n.oid = c.relnamespace
      WHERE p.pubname = 'supabase_realtime'
        AND n.nspname = 'public'
        AND c.relname = v_table
    ) THEN
      EXECUTE format(
        'ALTER PUBLICATION supabase_realtime ADD TABLE %I.%I',
        'public',
        v_table
      );
    END IF;
  END LOOP;
END
$$;


-- ============================================================================
-- Migration: 20260217193000_make_dn_driver_signature_optional.sql
-- ============================================================================

-- Make driver signature optional when dispatching delivery notes.

BEGIN;

DO $$
DECLARE
  v_sig regprocedure;
  v_def text;
  v_new_def text;
BEGIN
  FOR v_sig, v_def IN
    SELECT
      p.oid::regprocedure,
      pg_get_functiondef(p.oid)
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = 'public'
      AND p.proname = 'post_delivery_note_dispatch'
  LOOP
    v_new_def := v_def;

    v_new_def := replace(
      v_new_def,
      $needle$
  IF COALESCE(BTRIM(p_driver_signature), '') = '' THEN
    RAISE EXCEPTION 'Driver signature is required for dispatch';
  END IF;

$needle$,
      E'\n'
    );

    v_new_def := replace(
      v_new_def,
      '    driver_signature = BTRIM(p_driver_signature),',
      '    driver_signature = COALESCE(NULLIF(BTRIM(p_driver_signature), ''''), driver_signature),'
    );

    IF v_new_def <> v_def THEN
      EXECUTE v_new_def;
    END IF;
  END LOOP;
END $$;

COMMIT;


