CREATE OR REPLACE FUNCTION public.get_items_enhanced_stats(
  p_company_id UUID,
  p_search TEXT DEFAULT NULL,
  p_category_id UUID DEFAULT NULL,
  p_warehouse_id UUID DEFAULT NULL,
  p_item_type TEXT DEFAULT NULL,
  p_status TEXT DEFAULT NULL,
  p_business_unit_id UUID DEFAULT NULL
)
RETURNS TABLE (
  total_available_value NUMERIC,
  low_stock_count BIGINT,
  out_of_stock_count BIGINT,
  total_count BIGINT
)
LANGUAGE sql
STABLE
AS $$
WITH filtered_items AS (
  SELECT
    i.id,
    COALESCE(i.is_active, true) AS is_active,
    COALESCE(i.sales_price, 0) AS sales_price
  FROM public.items i
  WHERE i.company_id = p_company_id
    AND i.deleted_at IS NULL
    AND (
      p_search IS NULL
      OR p_search = ''
      OR i.item_code ILIKE ('%' || p_search || '%')
      OR COALESCE(i.sku, '') ILIKE ('%' || p_search || '%')
      OR i.item_name ILIKE ('%' || p_search || '%')
      OR COALESCE(i.item_name_cn, '') ILIKE ('%' || p_search || '%')
    )
    AND (p_category_id IS NULL OR i.category_id = p_category_id)
    AND (p_item_type IS NULL OR i.item_type = p_item_type)
),
warehouse_scope AS (
  SELECT
    iw.item_id,
    iw.available_stock AS available,
    iw.reorder_level
  FROM public.item_warehouse iw
  INNER JOIN public.warehouses w ON w.id = iw.warehouse_id
  WHERE iw.company_id = p_company_id
    AND iw.deleted_at IS NULL
    AND w.deleted_at IS NULL
    AND (p_warehouse_id IS NULL OR iw.warehouse_id = p_warehouse_id)
    AND (
      p_warehouse_id IS NOT NULL
      OR p_business_unit_id IS NULL
      OR w.business_unit_id = p_business_unit_id
    )
),
stock_agg AS (
  SELECT
    ws.item_id,
    SUM(COALESCE(ws.available, 0)) AS available,
    MAX(COALESCE(ws.reorder_level, 0)) AS reorder_point
  FROM warehouse_scope ws
  GROUP BY ws.item_id
),
enriched AS (
  SELECT
    fi.id,
    fi.sales_price,
    COALESCE(sa.available, 0) AS available,
    COALESCE(sa.reorder_point, 0) AS reorder_point,
    CASE
      WHEN NOT fi.is_active THEN 'discontinued'
      WHEN COALESCE(sa.available, 0) <= 0 THEN 'out_of_stock'
      WHEN COALESCE(sa.reorder_point, 0) > 0
        AND COALESCE(sa.available, 0) <= COALESCE(sa.reorder_point, 0)
        THEN 'low_stock'
      WHEN COALESCE(sa.reorder_point, 0) > 0
        AND COALESCE(sa.available, 0) > (COALESCE(sa.reorder_point, 0) * 3)
        THEN 'overstock'
      ELSE 'normal'
    END AS status
  FROM filtered_items fi
  LEFT JOIN stock_agg sa ON sa.item_id = fi.id
),
status_filtered AS (
  SELECT *
  FROM enriched e
  WHERE p_status IS NULL
    OR p_status = ''
    OR p_status = 'all'
    OR e.status = p_status
)
SELECT
  COALESCE(SUM(COALESCE(status_filtered.available, 0) * COALESCE(status_filtered.sales_price, 0)), 0)
    AS total_available_value,
  COUNT(*) FILTER (WHERE status_filtered.status = 'low_stock')::BIGINT AS low_stock_count,
  COUNT(*) FILTER (WHERE status_filtered.status = 'out_of_stock')::BIGINT AS out_of_stock_count,
  COUNT(*)::BIGINT AS total_count
FROM status_filtered;
$$;


-- ============================================================================
-- Migration: 20260221183000_add_company_claim_to_auth_hook.sql
-- ============================================================================

-- Add company_id/default_business_unit_id claims to JWT for server request context
-- This reduces repeated users/company lookups in API routes while keeping BU switching behavior.

CREATE OR REPLACE FUNCTION public.custom_access_token_hook(event JSONB)
RETURNS JSONB
LANGUAGE plpgsql
VOLATILE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  claims JSONB;
  v_user_id UUID;
  current_bu_id UUID;
  selected_bu_id UUID;
  default_bu_id UUID;
  company_id_value UUID;
BEGIN
  claims := event->'claims';
  v_user_id := (event->>'user_id')::UUID;

  -- Resolve company claim
  SELECT company_id INTO company_id_value
  FROM users
  WHERE id = v_user_id
  LIMIT 1;

  IF company_id_value IS NOT NULL THEN
    claims := jsonb_set(claims, '{company_id}', to_jsonb(company_id_value::text));
  END IF;

  -- Resolve selected/default BU
  SELECT business_unit_id INTO selected_bu_id
  FROM user_business_unit_access
  WHERE user_id = v_user_id
    AND is_current = true
  LIMIT 1;

  SELECT business_unit_id INTO default_bu_id
  FROM user_business_unit_access
  WHERE user_id = v_user_id
    AND is_default = true
  LIMIT 1;

  current_bu_id := COALESCE(
    selected_bu_id,
    (claims->>'current_business_unit_id')::UUID,
    default_bu_id
  );

  IF current_bu_id IS NOT NULL THEN
    claims := jsonb_set(claims, '{current_business_unit_id}', to_jsonb(current_bu_id::text));
  END IF;

  IF default_bu_id IS NOT NULL THEN
    claims := jsonb_set(claims, '{default_business_unit_id}', to_jsonb(default_bu_id::text));
  END IF;

  -- Add accessible BU list
  claims := jsonb_set(
    claims,
    '{accessible_business_units}',
    (
      SELECT COALESCE(jsonb_agg(business_unit_id), '[]'::jsonb)
      FROM user_business_unit_access
      WHERE user_id = v_user_id
    )
  );

  event := jsonb_set(event, '{claims}', claims);
  RETURN event;
EXCEPTION
  WHEN OTHERS THEN
    -- Never block auth token issuance
    RETURN event;
END;
$$;


