CREATE OR REPLACE FUNCTION public.get_warehouses(
  p_company_id UUID,
  p_accessible_business_unit_ids UUID[] DEFAULT NULL,
  p_search TEXT DEFAULT NULL,
  p_country TEXT DEFAULT NULL,
  p_is_active BOOLEAN DEFAULT NULL,
  p_page INTEGER DEFAULT 1,
  p_limit INTEGER DEFAULT 10
)
RETURNS TABLE (
  id UUID,
  "companyId" UUID,
  "businessUnitId" UUID,
  code TEXT,
  name TEXT,
  description TEXT,
  address TEXT,
  city TEXT,
  state TEXT,
  "postalCode" TEXT,
  country TEXT,
  phone TEXT,
  email TEXT,
  "managerName" TEXT,
  "isActive" BOOLEAN,
  "isVan" BOOLEAN,
  "createdAt" TIMESTAMPTZ,
  "updatedAt" TIMESTAMPTZ,
  total_count BIGINT
)
LANGUAGE sql
STABLE
AS $$
WITH filtered AS (
  SELECT
    w.id,
    w.company_id AS "companyId",
    w.business_unit_id AS "businessUnitId",
    w.warehouse_code AS code,
    w.warehouse_name AS name,
    ''::TEXT AS description,
    TRIM(
      CONCAT(
        COALESCE(w.address_line1, ''),
        CASE
          WHEN w.address_line2 IS NOT NULL AND BTRIM(w.address_line2) <> '' THEN ' ' || w.address_line2
          ELSE ''
        END
      )
    ) AS address,
    COALESCE(w.city, '') AS city,
    COALESCE(w.state, '') AS state,
    COALESCE(w.postal_code, '') AS "postalCode",
    COALESCE(w.country, '') AS country,
    COALESCE(w.phone, '') AS phone,
    COALESCE(w.email, '') AS email,
    NULLIF(w.contact_person, '') AS "managerName",
    COALESCE(w.is_active, true) AS "isActive",
    COALESCE(w.is_van, false) AS "isVan",
    w.created_at AS "createdAt",
    COALESCE(w.updated_at, w.created_at) AS "updatedAt"
  FROM public.warehouses w
  WHERE w.company_id = p_company_id
    AND w.deleted_at IS NULL
    AND (
      p_accessible_business_unit_ids IS NULL
      OR cardinality(p_accessible_business_unit_ids) = 0
      OR w.business_unit_id IS NULL
      OR w.business_unit_id = ANY(p_accessible_business_unit_ids)
    )
    AND (
      p_search IS NULL
      OR p_search = ''
      OR w.warehouse_code ILIKE ('%' || p_search || '%')
      OR w.warehouse_name ILIKE ('%' || p_search || '%')
      OR COALESCE(w.city, '') ILIKE ('%' || p_search || '%')
    )
    AND (
      p_country IS NULL
      OR p_country = ''
      OR COALESCE(w.country, '') ILIKE ('%' || p_country || '%')
    )
    AND (p_is_active IS NULL OR COALESCE(w.is_active, true) = p_is_active)
)
SELECT
  f.id,
  f."companyId",
  f."businessUnitId",
  f.code,
  f.name,
  f.description,
  f.address,
  f.city,
  f.state,
  f."postalCode",
  f.country,
  f.phone,
  f.email,
  f."managerName",
  f."isActive",
  f."isVan",
  f."createdAt",
  f."updatedAt",
  COUNT(*) OVER() AS total_count
FROM filtered f
ORDER BY f.code ASC
OFFSET (GREATEST(p_page, 1) - 1) * GREATEST(p_limit, 1)
LIMIT GREATEST(p_limit, 1);
$$;


-- ============================================================================
-- Migration: 20260222123000_optimize_transformation_template.sql
-- ============================================================================

-- Add optional image URL for transformation templates

ALTER TABLE public.transformation_templates
ADD COLUMN IF NOT EXISTS image_url TEXT;

COMMENT ON COLUMN public.transformation_templates.image_url
IS 'Optional image/thumbnail URL for the transformation template';


-- Transactional RPC for updating transformation template header and replacing input/output rows.
-- Keeps delete+insert strategy for lines, but executes atomically in the database.

DROP FUNCTION IF EXISTS public.update_transformation_template(
  UUID,
  UUID,
  UUID,
  BOOLEAN,
  TEXT,
  BOOLEAN,
  TEXT,
  BOOLEAN,
  TEXT,
  BOOLEAN,
  BOOLEAN,
  JSONB,
  JSONB
);

CREATE OR REPLACE FUNCTION public.update_transformation_template(
  p_template_id UUID,
  p_company_id UUID,
  p_user_id UUID,
  p_template_name_provided BOOLEAN DEFAULT FALSE,
  p_template_name TEXT DEFAULT NULL,
  p_description_provided BOOLEAN DEFAULT FALSE,
  p_description TEXT DEFAULT NULL,
  p_image_url_provided BOOLEAN DEFAULT FALSE,
  p_image_url TEXT DEFAULT NULL,
  p_is_active_provided BOOLEAN DEFAULT FALSE,
  p_is_active BOOLEAN DEFAULT NULL,
  p_inputs JSONB DEFAULT NULL,
  p_outputs JSONB DEFAULT NULL
)
RETURNS public.transformation_templates
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_template public.transformation_templates%ROWTYPE;
  v_has_structural_changes BOOLEAN := (p_inputs IS NOT NULL OR p_outputs IS NOT NULL);
BEGIN
  SELECT *
  INTO v_template
  FROM public.transformation_templates
  WHERE id = p_template_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Template not found'
      USING ERRCODE = 'P0002';
  END IF;

  IF v_template.usage_count > 0 AND (
    v_has_structural_changes
    OR p_template_name_provided
    OR p_description_provided
    OR p_image_url_provided
  ) THEN
    RAISE EXCEPTION 'Template is locked because it is used by % order(s). Only status changes are allowed.',
      v_template.usage_count
      USING ERRCODE = 'P0001';
  END IF;

  UPDATE public.transformation_templates
  SET
    template_name = CASE WHEN p_template_name_provided THEN p_template_name ELSE template_name END,
    description = CASE WHEN p_description_provided THEN p_description ELSE description END,
    image_url = CASE WHEN p_image_url_provided THEN p_image_url ELSE image_url END,
    is_active = CASE WHEN p_is_active_provided THEN COALESCE(p_is_active, is_active) ELSE is_active END,
    updated_by = p_user_id,
    updated_at = CURRENT_TIMESTAMP
  WHERE id = p_template_id;

  IF v_template.usage_count = 0 THEN
    IF p_inputs IS NOT NULL THEN
      DELETE FROM public.transformation_template_inputs
      WHERE template_id = p_template_id;

      IF jsonb_typeof(p_inputs) = 'array' AND jsonb_array_length(p_inputs) > 0 THEN
        INSERT INTO public.transformation_template_inputs (
          template_id,
          item_id,
          quantity,
          uom_id,
          sequence,
          notes,
          created_by,
          updated_by
        )
        SELECT
          p_template_id,
          (i->>'itemId')::UUID,
          (i->>'quantity')::NUMERIC,
          (i->>'uomId')::UUID,
          COALESCE((i->>'sequence')::INTEGER, ordinality::INTEGER),
          NULLIF(i->>'notes', ''),
          p_user_id,
          p_user_id
        FROM jsonb_array_elements(p_inputs) WITH ORDINALITY AS t(i, ordinality);
      END IF;
    END IF;

    IF p_outputs IS NOT NULL THEN
      DELETE FROM public.transformation_template_outputs
      WHERE template_id = p_template_id;

      IF jsonb_typeof(p_outputs) = 'array' AND jsonb_array_length(p_outputs) > 0 THEN
        INSERT INTO public.transformation_template_outputs (
          template_id,
          item_id,
          quantity,
          uom_id,
          sequence,
          is_scrap,
          notes,
          created_by,
          updated_by
        )
        SELECT
          p_template_id,
          (o->>'itemId')::UUID,
          (o->>'quantity')::NUMERIC,
          (o->>'uomId')::UUID,
          COALESCE((o->>'sequence')::INTEGER, ordinality::INTEGER),
          COALESCE((o->>'isScrap')::BOOLEAN, FALSE),
          NULLIF(o->>'notes', ''),
          p_user_id,
          p_user_id
        FROM jsonb_array_elements(p_outputs) WITH ORDINALITY AS t(o, ordinality);
      END IF;
    END IF;
  END IF;

  SELECT *
  INTO v_template
  FROM public.transformation_templates
  WHERE id = p_template_id;

  RETURN v_template;
END;
$$;

REVOKE ALL ON FUNCTION public.update_transformation_template(
  UUID,
  UUID,
  UUID,
  BOOLEAN,
  TEXT,
  BOOLEAN,
  TEXT,
  BOOLEAN,
  TEXT,
  BOOLEAN,
  BOOLEAN,
  JSONB,
  JSONB
) FROM PUBLIC;

GRANT EXECUTE ON FUNCTION public.update_transformation_template(
  UUID,
  UUID,
  UUID,
  BOOLEAN,
  TEXT,
  BOOLEAN,
  TEXT,
  BOOLEAN,
  TEXT,
  BOOLEAN,
  BOOLEAN,
  JSONB,
  JSONB
) TO authenticated;

-- Fix DELETE behavior for template detail lock trigger.
-- In a BEFORE DELETE trigger, returning NEW (NULL) cancels the delete silently.
-- This caused delete-then-insert updates to leave old rows in place and then hit
-- uq_template_input_item / uq_template_output_item on re-insert.

CREATE OR REPLACE FUNCTION public.prevent_template_detail_modification()
RETURNS TRIGGER AS $$
DECLARE
    v_usage_count INTEGER;
BEGIN
    -- Get the template's usage count from the affected row's template_id
    SELECT usage_count INTO v_usage_count
    FROM public.transformation_templates
    WHERE id = OLD.template_id;

    IF v_usage_count > 0 THEN
        RAISE EXCEPTION 'Cannot modify template inputs/outputs because template is used by % order(s). Template is locked.',
            v_usage_count
            USING ERRCODE = 'integrity_constraint_violation';
    END IF;

    -- BEFORE DELETE must return OLD to allow the delete to proceed.
    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;



-- ============================================================================
-- Migration: 20260224100000_add_item_batch_tracking_tables.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add Item Batch Tracking Tables
-- Version: 20260224100000
-- Description: Adds item_batch and item_location_batch stock layers plus
--              reconciliation helpers for warehouse/location/batch totals.
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

-- ============================================================================
-- TABLE: item_batch
-- Aggregate stock per item + warehouse + batch_code
-- ============================================================================

CREATE TABLE IF NOT EXISTS item_batch (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id UUID NOT NULL REFERENCES companies(id),
  item_id UUID NOT NULL REFERENCES items(id),
  warehouse_id UUID NOT NULL REFERENCES warehouses(id),
  batch_code VARCHAR(150) NOT NULL,
  received_at TIMESTAMP NOT NULL,
  qty_on_hand DECIMAL(20, 4) NOT NULL DEFAULT 0,
  qty_reserved DECIMAL(20, 4) NOT NULL DEFAULT 0,
  qty_available DECIMAL(20, 4) GENERATED ALWAYS AS (qty_on_hand - qty_reserved) STORED,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  created_by UUID NULL REFERENCES users(id),
  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_by UUID NULL REFERENCES users(id),
  deleted_at TIMESTAMP NULL,
  version INTEGER NOT NULL DEFAULT 1,
  UNIQUE (company_id, item_id, warehouse_id, batch_code),
  CHECK (BTRIM(batch_code) <> ''),
  CHECK (qty_on_hand >= 0),
  CHECK (qty_reserved >= 0),
  CHECK (qty_reserved <= qty_on_hand)
);

CREATE INDEX IF NOT EXISTS idx_item_batch_company
  ON item_batch(company_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_item_batch_item_wh
  ON item_batch(company_id, item_id, warehouse_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_item_batch_fifo
  ON item_batch(company_id, item_id, warehouse_id, received_at, batch_code)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_item_batch_batch_code
  ON item_batch(company_id, batch_code)
  WHERE deleted_at IS NULL;

DROP TRIGGER IF EXISTS trigger_item_batch_updated_at ON item_batch;
CREATE TRIGGER trigger_item_batch_updated_at
  BEFORE UPDATE ON item_batch
  FOR EACH ROW
  EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE item_batch IS
  'Batch-level stock balances for an item within a warehouse.';
COMMENT ON COLUMN item_batch.received_at IS
  'Batch receipt timestamp preserved across warehouse transfers for FIFO.';

-- ============================================================================
-- TABLE: item_location_batch
-- Exact stock per item + warehouse + location + batch
-- ============================================================================

CREATE TABLE IF NOT EXISTS item_location_batch (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id UUID NOT NULL REFERENCES companies(id),
  item_id UUID NOT NULL REFERENCES items(id),
  warehouse_id UUID NOT NULL REFERENCES warehouses(id),
  location_id UUID NOT NULL REFERENCES warehouse_locations(id),
  item_batch_id UUID NOT NULL REFERENCES item_batch(id),
  qty_on_hand DECIMAL(20, 4) NOT NULL DEFAULT 0,
  qty_reserved DECIMAL(20, 4) NOT NULL DEFAULT 0,
  qty_available DECIMAL(20, 4) GENERATED ALWAYS AS (qty_on_hand - qty_reserved) STORED,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  created_by UUID NULL REFERENCES users(id),
  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_by UUID NULL REFERENCES users(id),
  deleted_at TIMESTAMP NULL,
  version INTEGER NOT NULL DEFAULT 1,
  UNIQUE (company_id, item_id, warehouse_id, location_id, item_batch_id),
  CHECK (qty_on_hand >= 0),
  CHECK (qty_reserved >= 0),
  CHECK (qty_reserved <= qty_on_hand)
);

CREATE INDEX IF NOT EXISTS idx_item_location_batch_company
  ON item_location_batch(company_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_item_location_batch_item_wh
  ON item_location_batch(company_id, item_id, warehouse_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_item_location_batch_loc
  ON item_location_batch(company_id, location_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_item_location_batch_batch
  ON item_location_batch(company_id, item_batch_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_item_location_batch_pick
  ON item_location_batch(company_id, item_id, warehouse_id, location_id, item_batch_id)
  WHERE deleted_at IS NULL;

DROP TRIGGER IF EXISTS trigger_item_location_batch_updated_at ON item_location_batch;
CREATE TRIGGER trigger_item_location_batch_updated_at
  BEFORE UPDATE ON item_location_batch
  FOR EACH ROW
  EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE item_location_batch IS
  'Exact stock balances per item, warehouse location, and batch.';

-- ============================================================================
-- RLS
-- ============================================================================

ALTER TABLE item_batch ENABLE ROW LEVEL SECURITY;
ALTER TABLE item_location_batch ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS item_batch_select ON item_batch;
CREATE POLICY item_batch_select
  ON item_batch FOR SELECT TO authenticated
  USING (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

DROP POLICY IF EXISTS item_batch_insert ON item_batch;
CREATE POLICY item_batch_insert
  ON item_batch FOR INSERT TO authenticated
  WITH CHECK (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

DROP POLICY IF EXISTS item_batch_update ON item_batch;
CREATE POLICY item_batch_update
  ON item_batch FOR UPDATE TO authenticated
  USING (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

DROP POLICY IF EXISTS item_location_batch_select ON item_location_batch;
CREATE POLICY item_location_batch_select
  ON item_location_batch FOR SELECT TO authenticated
  USING (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

DROP POLICY IF EXISTS item_location_batch_insert ON item_location_batch;
CREATE POLICY item_location_batch_insert
  ON item_location_batch FOR INSERT TO authenticated
  WITH CHECK (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

DROP POLICY IF EXISTS item_location_batch_update ON item_location_batch;
CREATE POLICY item_location_batch_update
  ON item_location_batch FOR UPDATE TO authenticated
  USING (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

-- ============================================================================
-- RECONCILIATION HELPERS
-- ============================================================================

CREATE OR REPLACE VIEW public.v_inventory_recon_item_warehouse_vs_location AS
SELECT
  iw.company_id,
  iw.item_id,
  iw.warehouse_id,
  COALESCE(iw.current_stock, 0)::DECIMAL(20, 4) AS warehouse_qty_on_hand,
  COALESCE(SUM(il.qty_on_hand), 0)::DECIMAL(20, 4) AS location_qty_on_hand_sum,
  (COALESCE(iw.current_stock, 0) - COALESCE(SUM(il.qty_on_hand), 0))::DECIMAL(20, 4) AS qty_diff
FROM item_warehouse iw
LEFT JOIN item_location il
  ON il.company_id = iw.company_id
 AND il.item_id = iw.item_id
 AND il.warehouse_id = iw.warehouse_id
 AND il.deleted_at IS NULL
WHERE iw.deleted_at IS NULL
GROUP BY iw.company_id, iw.item_id, iw.warehouse_id, iw.current_stock;

CREATE OR REPLACE VIEW public.v_inventory_recon_item_warehouse_vs_batch AS
SELECT
  iw.company_id,
  iw.item_id,
  iw.warehouse_id,
  COALESCE(iw.current_stock, 0)::DECIMAL(20, 4) AS warehouse_qty_on_hand,
  COALESCE(SUM(ib.qty_on_hand), 0)::DECIMAL(20, 4) AS batch_qty_on_hand_sum,
  (COALESCE(iw.current_stock, 0) - COALESCE(SUM(ib.qty_on_hand), 0))::DECIMAL(20, 4) AS qty_diff
FROM item_warehouse iw
LEFT JOIN item_batch ib
  ON ib.company_id = iw.company_id
 AND ib.item_id = iw.item_id
 AND ib.warehouse_id = iw.warehouse_id
 AND ib.deleted_at IS NULL
WHERE iw.deleted_at IS NULL
GROUP BY iw.company_id, iw.item_id, iw.warehouse_id, iw.current_stock;

CREATE OR REPLACE VIEW public.v_inventory_recon_item_location_vs_location_batch AS
SELECT
  il.company_id,
  il.item_id,
  il.warehouse_id,
  il.location_id,
  COALESCE(il.qty_on_hand, 0)::DECIMAL(20, 4) AS location_qty_on_hand,
  COALESCE(SUM(ilb.qty_on_hand), 0)::DECIMAL(20, 4) AS location_batch_qty_on_hand_sum,
  (COALESCE(il.qty_on_hand, 0) - COALESCE(SUM(ilb.qty_on_hand), 0))::DECIMAL(20, 4) AS qty_diff
FROM item_location il
LEFT JOIN item_location_batch ilb
  ON ilb.company_id = il.company_id
 AND ilb.item_id = il.item_id
 AND ilb.warehouse_id = il.warehouse_id
 AND ilb.location_id = il.location_id
 AND ilb.deleted_at IS NULL
WHERE il.deleted_at IS NULL
GROUP BY il.company_id, il.item_id, il.warehouse_id, il.location_id, il.qty_on_hand;

CREATE OR REPLACE VIEW public.v_inventory_recon_item_batch_vs_location_batch AS
SELECT
  ib.company_id,
  ib.id AS item_batch_id,
  ib.item_id,
  ib.warehouse_id,
  ib.batch_code,
  ib.received_at,
  COALESCE(ib.qty_on_hand, 0)::DECIMAL(20, 4) AS batch_qty_on_hand,
  COALESCE(SUM(ilb.qty_on_hand), 0)::DECIMAL(20, 4) AS location_batch_qty_on_hand_sum,
  (COALESCE(ib.qty_on_hand, 0) - COALESCE(SUM(ilb.qty_on_hand), 0))::DECIMAL(20, 4) AS qty_diff
FROM item_batch ib
LEFT JOIN item_location_batch ilb
  ON ilb.company_id = ib.company_id
 AND ilb.item_batch_id = ib.id
 AND ilb.deleted_at IS NULL
WHERE ib.deleted_at IS NULL
GROUP BY ib.company_id, ib.id, ib.item_id, ib.warehouse_id, ib.batch_code, ib.received_at, ib.qty_on_hand;

CREATE OR REPLACE FUNCTION public.get_inventory_batch_reconciliation_mismatches(
  p_company_id UUID DEFAULT NULL,
  p_tolerance NUMERIC DEFAULT 0
)
RETURNS TABLE (
  check_name TEXT,
  company_id UUID,
  item_id UUID,
  warehouse_id UUID,
  location_id UUID,
  item_batch_id UUID,
  batch_code TEXT,
  qty_diff NUMERIC
)
LANGUAGE sql
SECURITY INVOKER
AS $$
  SELECT
    'item_warehouse_vs_location'::TEXT AS check_name,
    r.company_id,
    r.item_id,
    r.warehouse_id,
    NULL::UUID AS location_id,
    NULL::UUID AS item_batch_id,
    NULL::TEXT AS batch_code,
    r.qty_diff::NUMERIC AS qty_diff
  FROM public.v_inventory_recon_item_warehouse_vs_location r
  WHERE (p_company_id IS NULL OR r.company_id = p_company_id)
    AND ABS(COALESCE(r.qty_diff, 0)) > COALESCE(p_tolerance, 0)

  UNION ALL

  SELECT
    'item_warehouse_vs_batch'::TEXT,
    r.company_id,
    r.item_id,
    r.warehouse_id,
    NULL::UUID,
    NULL::UUID,
    NULL::TEXT,
    r.qty_diff::NUMERIC
  FROM public.v_inventory_recon_item_warehouse_vs_batch r
  WHERE (p_company_id IS NULL OR r.company_id = p_company_id)
    AND ABS(COALESCE(r.qty_diff, 0)) > COALESCE(p_tolerance, 0)

  UNION ALL

  SELECT
    'item_location_vs_location_batch'::TEXT,
    r.company_id,
    r.item_id,
    r.warehouse_id,
    r.location_id,
    NULL::UUID,
    NULL::TEXT,
    r.qty_diff::NUMERIC
  FROM public.v_inventory_recon_item_location_vs_location_batch r
  WHERE (p_company_id IS NULL OR r.company_id = p_company_id)
    AND ABS(COALESCE(r.qty_diff, 0)) > COALESCE(p_tolerance, 0)

  UNION ALL

  SELECT
    'item_batch_vs_location_batch'::TEXT,
    r.company_id,
    r.item_id,
    r.warehouse_id,
    NULL::UUID,
    r.item_batch_id,
    r.batch_code::TEXT,
    r.qty_diff::NUMERIC
  FROM public.v_inventory_recon_item_batch_vs_location_batch r
  WHERE (p_company_id IS NULL OR r.company_id = p_company_id)
    AND ABS(COALESCE(r.qty_diff, 0)) > COALESCE(p_tolerance, 0);
$$;

COMMENT ON FUNCTION public.get_inventory_batch_reconciliation_mismatches(UUID, NUMERIC) IS
  'Returns inventory total mismatches across item_warehouse, item_location, item_batch, and item_location_batch.';

COMMIT;



-- ============================================================================
-- Migration: 20260224110000_add_grn_batch_approval_rpc.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add GRN Batch-Aware Approval RPC
-- Version: 20260224110000
-- Description: Replaces app-layer GRN approval inventory posting with a single
--              transactional RPC that updates item_warehouse, item_location,
--              item_batch, and item_location_batch.
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.approve_grn_with_batch_inventory(
  p_company_id UUID,
  p_user_id UUID,
  p_grn_id UUID,
  p_notes TEXT DEFAULT NULL
)
RETURNS TEXT
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_grn grns%ROWTYPE;
  v_grn_item grn_items%ROWTYPE;
  v_item_uom_id UUID;
  v_now TIMESTAMP := NOW();
  v_tx_id UUID;
  v_tx_code TEXT;
  v_posting_date DATE;
  v_posting_time TIME;
  v_default_location_id UUID;
  v_generated_batch_code TEXT;
  v_batch_code TEXT;
  v_item_wh item_warehouse%ROWTYPE;
  v_item_batch item_batch%ROWTYPE;
  v_item_loc item_location%ROWTYPE;
  v_item_loc_batch item_location_batch%ROWTYPE;
  v_received_qty NUMERIC;
  v_damaged_qty NUMERIC;
  v_batch_received_at TIMESTAMP;
  v_boxes_total_qty NUMERIC;
  v_remainder_qty NUMERIC;
  v_has_items BOOLEAN := FALSE;
  v_line_location RECORD;
  v_item_wh_current_stock NUMERIC;
  v_item_wh_reserved_stock NUMERIC;
  v_item_wh_next_stock NUMERIC;
BEGIN
  SELECT *
  INTO v_grn
  FROM grns
  WHERE id = p_grn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'GRN not found';
  END IF;

  IF v_grn.status <> 'pending_approval' THEN
    RAISE EXCEPTION 'Only GRNs in pending approval can be approved';
  END IF;

  v_posting_date := COALESCE(v_grn.receiving_date, CURRENT_DATE);
  v_posting_time := v_now::TIME;
  v_batch_received_at := v_posting_date::TIMESTAMP + v_posting_time;

  INSERT INTO warehouse_locations (
    company_id,
    warehouse_id,
    code,
    name,
    location_type,
    is_pickable,
    is_storable,
    is_active,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_grn.warehouse_id,
    'MAIN',
    'Main',
    'bin',
    TRUE,
    TRUE,
    TRUE,
    p_user_id,
    p_user_id
  )
  ON CONFLICT (company_id, warehouse_id, code) DO UPDATE
  SET updated_by = EXCLUDED.updated_by
  RETURNING id INTO v_default_location_id;

  v_tx_code := 'ST-' || TO_CHAR(v_now, 'YYYYMMDDHH24MISSMS') ||
               SUBSTRING(REPLACE(gen_random_uuid()::TEXT, '-', ''), 1, 4);

  INSERT INTO stock_transactions (
    company_id,
    business_unit_id,
    transaction_code,
    transaction_type,
    transaction_date,
    warehouse_id,
    to_location_id,
    reference_type,
    reference_id,
    status,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_grn.business_unit_id,
    v_tx_code,
    'in',
    v_posting_date,
    v_grn.warehouse_id,
    v_default_location_id,
    'grn',
    v_grn.id,
    'posted',
    COALESCE(NULLIF(BTRIM(p_notes), ''), 'Auto-created from GRN ' || v_grn.grn_number),
    p_user_id,
    p_user_id
  )
  RETURNING id INTO v_tx_id;

  FOR v_grn_item IN
    SELECT gi.*
    FROM grn_items gi
    WHERE gi.grn_id = v_grn.id
    ORDER BY gi.created_at ASC, gi.id ASC
    FOR UPDATE
  LOOP
    v_has_items := TRUE;
    v_received_qty := COALESCE(v_grn_item.received_qty, 0);
    v_damaged_qty := COALESCE(v_grn_item.damaged_qty, 0);

    IF v_received_qty <= 0 THEN
      CONTINUE;
    END IF;

    SELECT i.uom_id
    INTO v_item_uom_id
    FROM items i
    WHERE i.id = v_grn_item.item_id;

    IF v_item_uom_id IS NULL THEN
      RAISE EXCEPTION 'Item UOM not found for item %', v_grn_item.item_id;
    END IF;

    v_generated_batch_code := COALESCE(
      NULLIF(BTRIM(v_grn.batch_number), ''),
      'GRN-' || v_grn.grn_number || '-' || SUBSTRING(REPLACE(v_grn_item.id::TEXT, '-', ''), 1, 8)
    );
    v_batch_code := v_generated_batch_code;

    -- GRN rule: duplicate item+warehouse+batch_code is not allowed.
    PERFORM 1
    FROM item_batch ib_dup
    WHERE ib_dup.company_id = p_company_id
      AND ib_dup.item_id = v_grn_item.item_id
      AND ib_dup.warehouse_id = v_grn.warehouse_id
      AND ib_dup.batch_code = v_batch_code
      AND ib_dup.deleted_at IS NULL;

    IF FOUND THEN
      RAISE EXCEPTION 'Duplicate batch code % for item % in warehouse %',
        v_batch_code, v_grn_item.item_id, v_grn.warehouse_id;
    END IF;

    SELECT *
    INTO v_item_wh
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_grn_item.item_id
      AND warehouse_id = v_grn.warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF FOUND THEN
      v_item_wh_current_stock := COALESCE(v_item_wh.current_stock, 0);
      v_item_wh_reserved_stock := COALESCE(v_item_wh.reserved_stock, 0);
      v_item_wh_next_stock := v_item_wh_current_stock + v_received_qty;

      UPDATE item_warehouse
      SET
        current_stock = v_item_wh_next_stock,
        in_transit = GREATEST(0, COALESCE(in_transit, 0) - v_received_qty),
        estimated_arrival_date = CASE
          WHEN GREATEST(0, COALESCE(in_transit, 0) - v_received_qty) > 0 THEN estimated_arrival_date
          ELSE NULL
        END,
        default_location_id = COALESCE(default_location_id, v_default_location_id),
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_wh.id;
    ELSE
      v_item_wh_current_stock := 0;
      v_item_wh_reserved_stock := 0;
      v_item_wh_next_stock := v_received_qty;

      INSERT INTO item_warehouse (
        company_id,
        item_id,
        warehouse_id,
        current_stock,
        reserved_stock,
        in_transit,
        estimated_arrival_date,
        default_location_id,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        v_item_wh_next_stock,
        0,
        0,
        NULL,
        v_default_location_id,
        p_user_id,
        p_user_id
      );
    END IF;

    INSERT INTO item_batch (
      company_id,
      item_id,
      warehouse_id,
      batch_code,
      received_at,
      qty_on_hand,
      qty_reserved,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_grn_item.item_id,
      v_grn.warehouse_id,
      v_batch_code,
      v_batch_received_at,
      v_received_qty,
      0,
      p_user_id,
      p_user_id
    )
    RETURNING * INTO v_item_batch;

    -- Post into item_location / item_location_batch using assigned box locations where available.
    v_boxes_total_qty := 0;

    FOR v_line_location IN
      SELECT
        gb.warehouse_location_id AS location_id,
        SUM(COALESCE(gb.qty_per_box, 0))::NUMERIC AS qty
      FROM grn_boxes gb
      WHERE gb.grn_item_id = v_grn_item.id
        AND gb.warehouse_location_id IS NOT NULL
      GROUP BY gb.warehouse_location_id
      ORDER BY gb.warehouse_location_id
    LOOP
      EXIT WHEN v_line_location.qty IS NULL OR v_line_location.qty <= 0;
      v_boxes_total_qty := v_boxes_total_qty + COALESCE(v_line_location.qty, 0);

      INSERT INTO item_location (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        v_line_location.location_id,
        v_line_location.qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
      SET
        qty_on_hand = item_location.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now
      RETURNING * INTO v_item_loc;

      INSERT INTO item_location_batch (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        item_batch_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        v_line_location.location_id,
        v_item_batch.id,
        v_line_location.qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id, item_batch_id) DO UPDATE
      SET
        qty_on_hand = item_location_batch.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now;
    END LOOP;

    v_remainder_qty := GREATEST(0, v_received_qty - COALESCE(v_boxes_total_qty, 0));
    IF v_remainder_qty > 0 THEN
      INSERT INTO item_location (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        COALESCE(v_item_wh.default_location_id, v_default_location_id),
        v_remainder_qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
      SET
        qty_on_hand = item_location.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now;

      INSERT INTO item_location_batch (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        item_batch_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        COALESCE(v_item_wh.default_location_id, v_default_location_id),
        v_item_batch.id,
        v_remainder_qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id, item_batch_id) DO UPDATE
      SET
        qty_on_hand = item_location_batch.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now;
    END IF;

    INSERT INTO stock_transaction_items (
      company_id,
      transaction_id,
      item_id,
      quantity,
      uom_id,
      batch_no,
      qty_before,
      qty_after,
      posting_date,
      posting_time,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_tx_id,
      v_grn_item.item_id,
      v_received_qty,
      v_item_uom_id,
      v_batch_code,
      v_item_wh_current_stock,
      v_item_wh_next_stock,
      v_posting_date,
      v_posting_time,
      CASE
        WHEN v_damaged_qty > 0 THEN 'GRN ' || v_grn.grn_number || ' (Damaged: ' || v_damaged_qty || ')'
        ELSE 'GRN ' || v_grn.grn_number
      END,
      p_user_id,
      p_user_id
    );
  END LOOP;

  IF NOT v_has_items THEN
    RAISE EXCEPTION 'GRN has no items';
  END IF;

  UPDATE grns
  SET
    status = 'approved',
    checked_by = p_user_id,
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = v_grn.id;

  UPDATE load_lists
  SET
    status = 'received',
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = v_grn.load_list_id;

  RETURN v_tx_code;
END;
$$;

COMMENT ON FUNCTION public.approve_grn_with_batch_inventory(UUID, UUID, UUID, TEXT) IS
  'Approves a GRN and posts inventory into warehouse/location/batch tables in one transaction.';

COMMIT;



-- ============================================================================
-- Migration: 20260224120000_add_delivery_note_item_picks.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add Delivery Note Item Pick Execution Rows
-- Version: 20260224120000
-- Description: Adds actual pick execution rows (delivery_note_item_picks) and
--              DN line suggested/override pick source fields.
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

-- Advisory pick source fields on DN line (non-binding suggestion + retained override).
ALTER TABLE delivery_note_items
  ADD COLUMN IF NOT EXISTS suggested_pick_location_id UUID REFERENCES warehouse_locations(id),
  ADD COLUMN IF NOT EXISTS suggested_pick_batch_code VARCHAR(150),
  ADD COLUMN IF NOT EXISTS suggested_pick_batch_received_at TIMESTAMP,
  ADD COLUMN IF NOT EXISTS has_pick_source_override BOOLEAN NOT NULL DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS last_pick_source_override_at TIMESTAMP,
  ADD COLUMN IF NOT EXISTS last_pick_source_override_by UUID REFERENCES users(id);

COMMENT ON COLUMN delivery_note_items.suggested_pick_location_id IS
  'Advisory suggested pick location (shelf/rack/bin) for the DN line. Non-binding.';
COMMENT ON COLUMN delivery_note_items.suggested_pick_batch_code IS
  'Advisory suggested batch code for the DN line. Non-binding.';
COMMENT ON COLUMN delivery_note_items.suggested_pick_batch_received_at IS
  'Advisory suggested batch receipt timestamp for FIFO guidance. Non-binding.';
COMMENT ON COLUMN delivery_note_items.has_pick_source_override IS
  'True when picker confirms actual pick source different from suggested source.';

-- Actual pick execution rows (source of truth for dispatch depletion by location+batch).
CREATE TABLE IF NOT EXISTS delivery_note_item_picks (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id UUID NOT NULL REFERENCES companies(id),
  dn_id UUID NOT NULL REFERENCES delivery_notes(id) ON DELETE CASCADE,
  delivery_note_item_id UUID NOT NULL REFERENCES delivery_note_items(id) ON DELETE CASCADE,
  pick_list_id UUID NOT NULL REFERENCES pick_lists(id) ON DELETE RESTRICT,
  item_id UUID NOT NULL REFERENCES items(id),
  source_warehouse_id UUID NOT NULL REFERENCES warehouses(id),
  picked_location_id UUID NOT NULL REFERENCES warehouse_locations(id),
  picked_batch_code VARCHAR(150) NOT NULL,
  picked_batch_received_at TIMESTAMP NOT NULL,
  picked_qty DECIMAL(20, 4) NOT NULL DEFAULT 0,
  dispatched_qty DECIMAL(20, 4) NOT NULL DEFAULT 0,
  picker_user_id UUID REFERENCES users(id),
  picked_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  is_mismatch_warning_acknowledged BOOLEAN NOT NULL DEFAULT FALSE,
  mismatch_reason TEXT,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  created_by UUID REFERENCES users(id),
  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_by UUID REFERENCES users(id),
  deleted_at TIMESTAMP NULL,
  version INTEGER NOT NULL DEFAULT 1,
  CHECK (BTRIM(picked_batch_code) <> ''),
  CHECK (picked_qty >= 0),
  CHECK (dispatched_qty >= 0),
  CHECK (dispatched_qty <= picked_qty)
);

-- Merge key rule:
-- merge when same DN line + same location + same batch identity + same preserved receipt date;
-- otherwise append a new row.
CREATE UNIQUE INDEX IF NOT EXISTS ux_dn_item_picks_merge_key
  ON delivery_note_item_picks(
    delivery_note_item_id,
    pick_list_id,
    picked_location_id,
    picked_batch_code,
    picked_batch_received_at
  )
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_dn_item_picks_company_dn
  ON delivery_note_item_picks(company_id, dn_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_dn_item_picks_dn_item
  ON delivery_note_item_picks(company_id, delivery_note_item_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_dn_item_picks_pick_list
  ON delivery_note_item_picks(company_id, pick_list_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_dn_item_picks_item_source_wh
  ON delivery_note_item_picks(company_id, item_id, source_warehouse_id)
  WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_dn_item_picks_batch_lookup
  ON delivery_note_item_picks(company_id, picked_batch_code, picked_batch_received_at)
  WHERE deleted_at IS NULL;

DROP TRIGGER IF EXISTS trigger_delivery_note_item_picks_updated_at ON delivery_note_item_picks;
CREATE TRIGGER trigger_delivery_note_item_picks_updated_at
  BEFORE UPDATE ON delivery_note_item_picks
  FOR EACH ROW
  EXECUTE FUNCTION update_updated_at_column();

COMMENT ON TABLE delivery_note_item_picks IS
  'Actual picked source rows per delivery note line (location + batch), used for dispatch depletion and transfer receipt batch preservation.';
COMMENT ON COLUMN delivery_note_item_picks.is_mismatch_warning_acknowledged IS
  'True when picker continues after mismatch warning against suggested pick source.';

ALTER TABLE delivery_note_item_picks ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS company_select ON delivery_note_item_picks;
CREATE POLICY company_select ON delivery_note_item_picks
  FOR SELECT TO authenticated
  USING (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

DROP POLICY IF EXISTS company_insert ON delivery_note_item_picks;
CREATE POLICY company_insert ON delivery_note_item_picks
  FOR INSERT TO authenticated
  WITH CHECK (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

DROP POLICY IF EXISTS company_update ON delivery_note_item_picks;
CREATE POLICY company_update ON delivery_note_item_picks
  FOR UPDATE TO authenticated
  USING (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

DROP POLICY IF EXISTS company_delete ON delivery_note_item_picks;
CREATE POLICY company_delete ON delivery_note_item_picks
  FOR DELETE TO authenticated
  USING (company_id = (SELECT company_id FROM users WHERE id = auth.uid()));

COMMIT;



-- ============================================================================
-- Migration: 20260224130000_add_dn_reservation_suggestion_rpc.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add DN Reservation + Suggestion RPC
-- Version: 20260224130000
-- Description: Reserves aggregate stock at DN creation and computes advisory
--              suggested pick source (location + batch) per DN line.
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.reserve_delivery_note_inventory(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dni delivery_note_items%ROWTYPE;
  v_wh item_warehouse%ROWTYPE;
  v_available NUMERIC;
  v_suggested_pick_location_id UUID;
  v_suggested_pick_batch_code TEXT;
  v_suggested_pick_batch_received_at TIMESTAMP;
  v_total_allocated NUMERIC := 0;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'draft' THEN
    RAISE EXCEPTION 'Inventory reservation only allowed while delivery note is in draft status';
  END IF;

  FOR v_dni IN
    SELECT *
    FROM delivery_note_items
    WHERE company_id = p_company_id
      AND dn_id = p_dn_id
    ORDER BY created_at ASC, id ASC
    FOR UPDATE
  LOOP
    v_total_allocated := v_total_allocated + COALESCE(v_dni.allocated_qty, 0);

    SELECT *
    INTO v_wh
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_dni.item_id
      AND warehouse_id = v_dni.fulfilling_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Insufficient stock for item % in warehouse %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id;
    END IF;

    v_available := GREATEST(0, COALESCE(v_wh.current_stock, 0) - COALESCE(v_wh.reserved_stock, 0));
    IF v_available < COALESCE(v_dni.allocated_qty, 0) THEN
      RAISE EXCEPTION 'Insufficient available stock for item % in warehouse %. Available %, requested %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id, v_available, COALESCE(v_dni.allocated_qty, 0);
    END IF;

    UPDATE item_warehouse
    SET
      reserved_stock = COALESCE(reserved_stock, 0) + COALESCE(v_dni.allocated_qty, 0),
      updated_by = p_user_id,
      updated_at = NOW()
    WHERE id = v_wh.id;

    -- Advisory suggestion only (non-binding): oldest batch, then deterministic location row.
    v_suggested_pick_location_id := NULL;
    v_suggested_pick_batch_code := NULL;
    v_suggested_pick_batch_received_at := NULL;

    SELECT
      ilb.location_id,
      ib.batch_code,
      ib.received_at
    INTO
      v_suggested_pick_location_id,
      v_suggested_pick_batch_code,
      v_suggested_pick_batch_received_at
    FROM item_location_batch ilb
    JOIN item_batch ib
      ON ib.id = ilb.item_batch_id
     AND ib.company_id = ilb.company_id
     AND ib.deleted_at IS NULL
    WHERE ilb.company_id = p_company_id
      AND ilb.item_id = v_dni.item_id
      AND ilb.warehouse_id = v_dni.fulfilling_warehouse_id
      AND ilb.deleted_at IS NULL
      AND GREATEST(0, COALESCE(ilb.qty_on_hand, 0) - COALESCE(ilb.qty_reserved, 0)) > 0
    ORDER BY ib.received_at ASC, ilb.created_at ASC, ilb.id ASC
    LIMIT 1;

    UPDATE delivery_note_items
    SET
      suggested_pick_location_id = COALESCE(v_suggested_pick_location_id, suggested_pick_location_id),
      suggested_pick_batch_code = COALESCE(v_suggested_pick_batch_code, suggested_pick_batch_code),
      suggested_pick_batch_received_at = COALESCE(v_suggested_pick_batch_received_at, suggested_pick_batch_received_at),
      updated_at = NOW()
    WHERE id = v_dni.id
      AND company_id = p_company_id;
  END LOOP;

  IF v_total_allocated <= 0 THEN
    RAISE EXCEPTION 'Delivery note has no allocatable line quantities';
  END IF;
END;
$$;

COMMENT ON FUNCTION public.reserve_delivery_note_inventory(UUID, UUID, UUID) IS
  'Reserves aggregate stock on item_warehouse for a draft delivery note and stores advisory FIFO pick source suggestions on delivery_note_items.';

COMMIT;


-- ============================================================================
-- Migration: 20260224140000_refactor_dn_dispatch_to_pick_rows.sql
-- ============================================================================

-- ============================================================================
-- Migration: Refactor DN Dispatch To Use Pick Rows
-- Version: 20260224140000
-- Description: Updates post_delivery_note_dispatch to consume
--              delivery_note_item_picks (actual picked location+batch rows)
--              and batch-aware inventory layers.
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.post_delivery_note_dispatch(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_business_unit_id UUID,
  p_dispatch_date DATE,
  p_notes TEXT,
  p_driver_name TEXT,
  p_driver_signature TEXT,
  p_items JSONB
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dn_item delivery_note_items%ROWTYPE;
  v_warehouse_stock item_warehouse%ROWTYPE;
  v_tx_id UUID;
  v_now TIMESTAMP;
  v_posting_date DATE;
  v_posting_time TIME;
  v_line JSONB;
  v_item_id UUID;
  v_dispatch_qty NUMERIC;
  v_remaining_pick_qty NUMERIC;
  v_remaining_dispatch_qty NUMERIC;
  v_take_qty NUMERIC;
  v_current_stock NUMERIC;
  v_next_stock NUMERIC;
  v_has_dispatch_line BOOLEAN := FALSE;
  v_line_fulfilling_warehouse_id UUID;
  v_line_default_location_id UUID;
  v_reserved_stock NUMERIC;
  v_pick_row RECORD;
  v_item_batch_row item_batch%ROWTYPE;
  v_item_location_batch_row item_location_batch%ROWTYPE;
  v_item_location_row item_location%ROWTYPE;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatch_ready' THEN
    RAISE EXCEPTION 'Only dispatch_ready delivery notes can be dispatched';
  END IF;

  IF p_business_unit_id IS NULL THEN
    RAISE EXCEPTION 'Business unit context required';
  END IF;

  v_now := NOW();
  v_posting_date := COALESCE(p_dispatch_date, v_now::DATE);
  v_posting_time := v_now::TIME;

  FOR v_line IN
    SELECT value
    FROM jsonb_array_elements(COALESCE(p_items, '[]'::jsonb))
  LOOP
    v_item_id := NULLIF(v_line->>'deliveryNoteItemId', '')::UUID;
    IF v_item_id IS NULL THEN
      CONTINUE;
    END IF;

    v_dispatch_qty := COALESCE((v_line->>'dispatchQty')::NUMERIC, 0);

    SELECT *
    INTO v_dn_item
    FROM delivery_note_items
    WHERE id = v_item_id
      AND company_id = p_company_id
      AND dn_id = p_dn_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Invalid delivery note item %', v_item_id;
    END IF;

    v_remaining_pick_qty := GREATEST(
      0,
      COALESCE(v_dn_item.picked_qty, 0) - COALESCE(v_dn_item.dispatched_qty, 0)
    );
    IF v_dispatch_qty < 0 OR v_dispatch_qty > v_remaining_pick_qty THEN
      RAISE EXCEPTION 'Invalid dispatch quantity for delivery note item %', v_item_id;
    END IF;

    IF v_dispatch_qty = 0 THEN
      CONTINUE;
    END IF;

    v_line_fulfilling_warehouse_id := COALESCE(v_dn_item.fulfilling_warehouse_id, v_dn.fulfilling_warehouse_id);
    IF v_line_fulfilling_warehouse_id IS NULL THEN
      RAISE EXCEPTION 'Missing fulfilling warehouse for delivery note item %', v_item_id;
    END IF;

    INSERT INTO warehouse_locations (
      company_id,
      warehouse_id,
      code,
      name,
      location_type,
      is_pickable,
      is_storable,
      is_active,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_line_fulfilling_warehouse_id,
      'MAIN',
      'Main',
      'bin',
      TRUE,
      TRUE,
      TRUE,
      p_user_id,
      p_user_id
    )
    ON CONFLICT (company_id, warehouse_id, code) DO UPDATE
    SET updated_by = EXCLUDED.updated_by
    RETURNING id INTO v_line_default_location_id;

    INSERT INTO stock_transactions (
      company_id,
      business_unit_id,
      transaction_type,
      transaction_date,
      warehouse_id,
      from_location_id,
      reference_type,
      reference_id,
      reference_code,
      status,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      p_business_unit_id,
      'out',
      v_posting_date,
      v_line_fulfilling_warehouse_id,
      v_line_default_location_id,
      'delivery_note',
      v_dn.id,
      v_dn.dn_no,
      'posted',
      COALESCE(NULLIF(BTRIM(p_notes), ''), 'Delivery note ' || v_dn.dn_no || ' dispatched'),
      p_user_id,
      p_user_id
    )
    RETURNING id INTO v_tx_id;

    v_has_dispatch_line := TRUE;

    SELECT *
    INTO v_warehouse_stock
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_dn_item.item_id
      AND warehouse_id = v_line_fulfilling_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Insufficient stock for item %', v_dn_item.item_id;
    END IF;

    v_current_stock := COALESCE(v_warehouse_stock.current_stock, 0);
    IF v_current_stock < v_dispatch_qty THEN
      RAISE EXCEPTION 'Insufficient stock for item %', v_dn_item.item_id;
    END IF;

    v_reserved_stock := COALESCE(v_warehouse_stock.reserved_stock, 0);
    IF v_reserved_stock < v_dispatch_qty THEN
      RAISE EXCEPTION 'Insufficient reserved stock for item % on delivery note dispatch', v_dn_item.item_id;
    END IF;

    v_remaining_dispatch_qty := v_dispatch_qty;

    FOR v_pick_row IN
      SELECT *
      FROM delivery_note_item_picks
      WHERE company_id = p_company_id
        AND dn_id = p_dn_id
        AND delivery_note_item_id = v_dn_item.id
        AND deleted_at IS NULL
        AND COALESCE(picked_qty, 0) > COALESCE(dispatched_qty, 0)
      ORDER BY created_at ASC, id ASC
      FOR UPDATE
    LOOP
      EXIT WHEN v_remaining_dispatch_qty <= 0;

      v_take_qty := LEAST(
        v_remaining_dispatch_qty,
        GREATEST(0, COALESCE(v_pick_row.picked_qty, 0) - COALESCE(v_pick_row.dispatched_qty, 0))
      );
      IF v_take_qty <= 0 THEN
        CONTINUE;
      END IF;

      SELECT *
      INTO v_item_batch_row
      FROM item_batch
      WHERE company_id = p_company_id
        AND item_id = v_dn_item.item_id
        AND warehouse_id = COALESCE(v_pick_row.source_warehouse_id, v_line_fulfilling_warehouse_id)
        AND batch_code = v_pick_row.picked_batch_code
        AND received_at = v_pick_row.picked_batch_received_at
        AND deleted_at IS NULL
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Picked batch not found for delivery note item % (batch %, receipt %)',
          v_dn_item.id, v_pick_row.picked_batch_code, v_pick_row.picked_batch_received_at;
      END IF;

      IF COALESCE(v_item_batch_row.qty_on_hand, 0) < v_take_qty THEN
        RAISE EXCEPTION 'Insufficient item_batch stock for delivery note item %', v_dn_item.id;
      END IF;

      SELECT *
      INTO v_item_location_batch_row
      FROM item_location_batch
      WHERE company_id = p_company_id
        AND item_id = v_dn_item.item_id
        AND warehouse_id = COALESCE(v_pick_row.source_warehouse_id, v_line_fulfilling_warehouse_id)
        AND location_id = v_pick_row.picked_location_id
        AND item_batch_id = v_item_batch_row.id
        AND deleted_at IS NULL
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Picked item_location_batch row not found for delivery note item %', v_dn_item.id;
      END IF;

      IF COALESCE(v_item_location_batch_row.qty_on_hand, 0) < v_take_qty THEN
        RAISE EXCEPTION 'Insufficient item_location_batch stock for delivery note item %', v_dn_item.id;
      END IF;

      SELECT *
      INTO v_item_location_row
      FROM item_location
      WHERE company_id = p_company_id
        AND item_id = v_dn_item.item_id
        AND warehouse_id = COALESCE(v_pick_row.source_warehouse_id, v_line_fulfilling_warehouse_id)
        AND location_id = v_pick_row.picked_location_id
        AND deleted_at IS NULL
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Picked item_location row not found for delivery note item %', v_dn_item.id;
      END IF;

      IF COALESCE(v_item_location_row.qty_on_hand, 0) < v_take_qty THEN
        RAISE EXCEPTION 'Insufficient item_location stock for delivery note item %', v_dn_item.id;
      END IF;

      UPDATE item_location_batch
      SET
        qty_on_hand = qty_on_hand - v_take_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_location_batch_row.id;

      UPDATE item_batch
      SET
        qty_on_hand = qty_on_hand - v_take_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_batch_row.id;

      UPDATE item_location
      SET
        qty_on_hand = qty_on_hand - v_take_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_location_row.id;

      UPDATE delivery_note_item_picks
      SET
        dispatched_qty = COALESCE(dispatched_qty, 0) + v_take_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_pick_row.id;

      v_remaining_dispatch_qty := v_remaining_dispatch_qty - v_take_qty;
    END LOOP;

    IF v_remaining_dispatch_qty > 0 THEN
      RAISE EXCEPTION 'Insufficient picked rows to dispatch delivery note item %', v_dn_item.id;
    END IF;

    v_next_stock := v_current_stock - v_dispatch_qty;

    UPDATE item_warehouse
    SET
      current_stock = v_next_stock,
      reserved_stock = GREATEST(0, COALESCE(reserved_stock, 0) - v_dispatch_qty),
      updated_by = p_user_id,
      updated_at = v_now
    WHERE id = v_warehouse_stock.id;

    INSERT INTO stock_transaction_items (
      company_id,
      transaction_id,
      item_id,
      quantity,
      uom_id,
      qty_before,
      qty_after,
      posting_date,
      posting_time,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_tx_id,
      v_dn_item.item_id,
      v_dispatch_qty,
      v_dn_item.uom_id,
      v_current_stock,
      v_next_stock,
      v_posting_date,
      v_posting_time,
      COALESCE(NULLIF(BTRIM(p_notes), ''), 'Delivery note ' || v_dn.dn_no || ' dispatched'),
      p_user_id,
      p_user_id
    );

    UPDATE delivery_note_items
    SET
      dispatched_qty = COALESCE(dispatched_qty, 0) + v_dispatch_qty,
      updated_at = v_now
    WHERE id = v_dn_item.id;

    UPDATE stock_request_items
    SET
      dispatch_qty = COALESCE(dispatch_qty, 0) + v_dispatch_qty,
      updated_at = v_now
    WHERE id = v_dn_item.sr_item_id;
  END LOOP;

  IF NOT v_has_dispatch_line THEN
    RAISE EXCEPTION 'No picked quantities available for dispatch';
  END IF;

  UPDATE delivery_notes
  SET
    status = 'dispatched',
    dispatched_at = v_now,
    driver_name = COALESCE(NULLIF(BTRIM(p_driver_name), ''), driver_name),
    driver_signature = COALESCE(NULLIF(BTRIM(p_driver_signature), ''), driver_signature),
    notes = COALESCE(NULLIF(BTRIM(p_notes), ''), notes),
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260224150000_refactor_dn_receive_to_pick_rows.sql
-- ============================================================================

-- ============================================================================
-- Migration: Refactor DN Receive To Use Pick Rows
-- Version: 20260224150000
-- Description: Updates post_delivery_note_receive to rebuild destination stock
--              from delivery_note_item_picks while preserving batch_code and
--              original batch received_at across warehouses.
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

ALTER TABLE delivery_note_item_picks
  ADD COLUMN IF NOT EXISTS received_qty DECIMAL(20, 4) NOT NULL DEFAULT 0;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'delivery_note_item_picks_received_qty_check'
  ) THEN
    ALTER TABLE delivery_note_item_picks
      ADD CONSTRAINT delivery_note_item_picks_received_qty_check
      CHECK (received_qty >= 0 AND received_qty <= dispatched_qty);
  END IF;
END $$;

COMMENT ON COLUMN delivery_note_item_picks.received_qty IS
  'Quantity from this picked row that has been posted on destination receive.';

CREATE OR REPLACE FUNCTION public.post_delivery_note_receive(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_business_unit_id UUID,
  p_received_date DATE,
  p_notes TEXT,
  p_items JSONB
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dn_item delivery_note_items%ROWTYPE;
  v_warehouse_stock item_warehouse%ROWTYPE;
  v_tx_id UUID;
  v_now TIMESTAMP;
  v_posting_date DATE;
  v_posting_time TIME;
  v_line JSONB;
  v_item_id UUID;
  v_received_qty NUMERIC;
  v_max_receivable_qty NUMERIC;
  v_current_stock NUMERIC;
  v_next_stock NUMERIC;
  v_has_receive_line BOOLEAN := FALSE;
  v_target_location_id UUID;
  v_line_requesting_warehouse_id UUID;
  v_line_default_location_id UUID;
  v_remaining_receive_qty NUMERIC;
  v_take_qty NUMERIC;
  v_pick_row RECORD;
  v_dest_item_batch item_batch%ROWTYPE;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be received';
  END IF;

  IF p_business_unit_id IS NULL THEN
    RAISE EXCEPTION 'Business unit context required';
  END IF;

  v_now := NOW();
  v_posting_date := COALESCE(p_received_date, v_now::DATE);
  v_posting_time := v_now::TIME;

  FOR v_line IN
    SELECT value
    FROM jsonb_array_elements(COALESCE(p_items, '[]'::jsonb))
  LOOP
    v_item_id := NULLIF(v_line->>'deliveryNoteItemId', '')::UUID;
    IF v_item_id IS NULL THEN
      CONTINUE;
    END IF;

    v_received_qty := COALESCE((v_line->>'receivedQty')::NUMERIC, 0);

    SELECT *
    INTO v_dn_item
    FROM delivery_note_items
    WHERE id = v_item_id
      AND company_id = p_company_id
      AND dn_id = p_dn_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Invalid delivery note item %', v_item_id;
    END IF;

    SELECT COALESCE(SUM(GREATEST(0, COALESCE(dispatched_qty, 0) - COALESCE(received_qty, 0))), 0)
    INTO v_max_receivable_qty
    FROM delivery_note_item_picks
    WHERE company_id = p_company_id
      AND dn_id = p_dn_id
      AND delivery_note_item_id = v_dn_item.id
      AND deleted_at IS NULL;

    -- Fallback for legacy rows / older data where pick rows might not be present.
    IF v_max_receivable_qty = 0 THEN
      v_max_receivable_qty := COALESCE(v_dn_item.dispatched_qty, 0);
    END IF;

    IF v_received_qty < 0 OR v_received_qty > v_max_receivable_qty THEN
      RAISE EXCEPTION 'Received quantity must be between 0 and %', v_max_receivable_qty;
    END IF;

    IF v_received_qty = 0 THEN
      CONTINUE;
    END IF;

    v_line_requesting_warehouse_id := COALESCE(
      v_dn_item.requesting_warehouse_id,
      v_dn.requesting_warehouse_id
    );
    IF v_line_requesting_warehouse_id IS NULL THEN
      RAISE EXCEPTION 'Missing requesting warehouse for delivery note item %', v_item_id;
    END IF;

    INSERT INTO warehouse_locations (
      company_id,
      warehouse_id,
      code,
      name,
      location_type,
      is_pickable,
      is_storable,
      is_active,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_line_requesting_warehouse_id,
      'MAIN',
      'Main',
      'bin',
      TRUE,
      TRUE,
      TRUE,
      p_user_id,
      p_user_id
    )
    ON CONFLICT (company_id, warehouse_id, code) DO UPDATE
    SET updated_by = EXCLUDED.updated_by
    RETURNING id INTO v_line_default_location_id;

    v_target_location_id := COALESCE(NULLIF(v_line->>'locationId', '')::UUID, v_line_default_location_id);

    INSERT INTO stock_transactions (
      company_id,
      business_unit_id,
      transaction_type,
      transaction_date,
      warehouse_id,
      to_location_id,
      reference_type,
      reference_id,
      reference_code,
      status,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      p_business_unit_id,
      'in',
      v_posting_date,
      v_line_requesting_warehouse_id,
      v_target_location_id,
      'delivery_note',
      v_dn.id,
      v_dn.dn_no,
      'posted',
      COALESCE(NULLIF(BTRIM(p_notes), ''), 'Delivery note ' || v_dn.dn_no || ' received'),
      p_user_id,
      p_user_id
    )
    RETURNING id INTO v_tx_id;

    v_has_receive_line := TRUE;

    SELECT *
    INTO v_warehouse_stock
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_dn_item.item_id
      AND warehouse_id = v_line_requesting_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF FOUND THEN
      v_current_stock := COALESCE(v_warehouse_stock.current_stock, 0);
      v_next_stock := v_current_stock + v_received_qty;

      IF v_warehouse_stock.default_location_id IS NULL THEN
        UPDATE item_warehouse
        SET
          default_location_id = v_line_default_location_id,
          current_stock = v_next_stock,
          updated_by = p_user_id,
          updated_at = v_now
        WHERE id = v_warehouse_stock.id;
      ELSE
        UPDATE item_warehouse
        SET
          current_stock = v_next_stock,
          updated_by = p_user_id,
          updated_at = v_now
        WHERE id = v_warehouse_stock.id;
      END IF;
    ELSE
      v_current_stock := 0;
      v_next_stock := v_received_qty;

      INSERT INTO item_warehouse (
        company_id,
        item_id,
        warehouse_id,
        current_stock,
        default_location_id,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_dn_item.item_id,
        v_line_requesting_warehouse_id,
        v_next_stock,
        v_line_default_location_id,
        p_user_id,
        p_user_id
      );
    END IF;

    INSERT INTO item_location (
      company_id,
      item_id,
      warehouse_id,
      location_id,
      qty_on_hand,
      qty_reserved,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_dn_item.item_id,
      v_line_requesting_warehouse_id,
      v_target_location_id,
      v_received_qty,
      0,
      p_user_id,
      p_user_id
    )
    ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
    SET
      qty_on_hand = item_location.qty_on_hand + EXCLUDED.qty_on_hand,
      updated_by = EXCLUDED.updated_by,
      updated_at = v_now;

    v_remaining_receive_qty := v_received_qty;

    FOR v_pick_row IN
      SELECT *
      FROM delivery_note_item_picks
      WHERE company_id = p_company_id
        AND dn_id = p_dn_id
        AND delivery_note_item_id = v_dn_item.id
        AND deleted_at IS NULL
        AND COALESCE(dispatched_qty, 0) > COALESCE(received_qty, 0)
      ORDER BY created_at ASC, id ASC
      FOR UPDATE
    LOOP
      EXIT WHEN v_remaining_receive_qty <= 0;

      v_take_qty := LEAST(
        v_remaining_receive_qty,
        GREATEST(0, COALESCE(v_pick_row.dispatched_qty, 0) - COALESCE(v_pick_row.received_qty, 0))
      );
      IF v_take_qty <= 0 THEN
        CONTINUE;
      END IF;

      SELECT *
      INTO v_dest_item_batch
      FROM item_batch
      WHERE company_id = p_company_id
        AND item_id = v_dn_item.item_id
        AND warehouse_id = v_line_requesting_warehouse_id
        AND batch_code = v_pick_row.picked_batch_code
        AND deleted_at IS NULL
      FOR UPDATE;

      IF FOUND THEN
        IF v_dest_item_batch.received_at <> v_pick_row.picked_batch_received_at THEN
          RAISE EXCEPTION 'Batch % receipt date mismatch on destination warehouse for item % (existing %, incoming %)',
            v_pick_row.picked_batch_code,
            v_dn_item.item_id,
            v_dest_item_batch.received_at,
            v_pick_row.picked_batch_received_at;
        END IF;

        UPDATE item_batch
        SET
          qty_on_hand = qty_on_hand + v_take_qty,
          updated_by = p_user_id,
          updated_at = v_now
        WHERE id = v_dest_item_batch.id;
      ELSE
        INSERT INTO item_batch (
          company_id,
          item_id,
          warehouse_id,
          batch_code,
          received_at,
          qty_on_hand,
          qty_reserved,
          created_by,
          updated_by
        )
        VALUES (
          p_company_id,
          v_dn_item.item_id,
          v_line_requesting_warehouse_id,
          v_pick_row.picked_batch_code,
          v_pick_row.picked_batch_received_at,
          v_take_qty,
          0,
          p_user_id,
          p_user_id
        )
        RETURNING * INTO v_dest_item_batch;
      END IF;

      INSERT INTO item_location_batch (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        item_batch_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_dn_item.item_id,
        v_line_requesting_warehouse_id,
        v_target_location_id,
        v_dest_item_batch.id,
        v_take_qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id, item_batch_id) DO UPDATE
      SET
        qty_on_hand = item_location_batch.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now;

      UPDATE delivery_note_item_picks
      SET
        received_qty = COALESCE(received_qty, 0) + v_take_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_pick_row.id;

      v_remaining_receive_qty := v_remaining_receive_qty - v_take_qty;
    END LOOP;

    IF v_remaining_receive_qty > 0 THEN
      RAISE EXCEPTION 'Insufficient dispatched pick rows to receive delivery note item %', v_dn_item.id;
    END IF;

    INSERT INTO stock_transaction_items (
      company_id,
      transaction_id,
      item_id,
      quantity,
      uom_id,
      unit_cost,
      total_cost,
      qty_before,
      qty_after,
      valuation_rate,
      stock_value_before,
      stock_value_after,
      posting_date,
      posting_time,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_tx_id,
      v_dn_item.item_id,
      v_received_qty,
      v_dn_item.uom_id,
      0,
      0,
      v_current_stock,
      v_next_stock,
      0,
      0,
      0,
      v_posting_date,
      v_posting_time,
      COALESCE(NULLIF(BTRIM(p_notes), ''), 'Delivery note ' || v_dn.dn_no || ' received'),
      p_user_id,
      p_user_id
    );

    UPDATE stock_request_items
    SET
      received_qty = COALESCE(received_qty, 0) + v_received_qty,
      updated_at = v_now
    WHERE id = v_dn_item.sr_item_id;
  END LOOP;

  IF NOT v_has_receive_line THEN
    RAISE EXCEPTION 'No dispatched quantities available to receive';
  END IF;

  UPDATE delivery_notes
  SET
    status = 'received',
    received_at = v_now,
    notes = COALESCE(NULLIF(BTRIM(p_notes), ''), notes),
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260224160000_add_dn_direct_customer_pickup_completion_rpc.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add DN Direct Customer Pickup Completion RPC
-- Version: 20260224160000
-- Description: Adds a separate transition path to complete delivery notes as
--              customer pickup from warehouse without destination inventory
--              receive posting, while still marking workflow as received.
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.complete_delivery_note_direct_customer_pickup(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_received_date DATE,
  p_notes TEXT,
  p_items JSONB
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dn_item delivery_note_items%ROWTYPE;
  v_line JSONB;
  v_item_id UUID;
  v_received_qty NUMERIC;
  v_max_receivable_qty NUMERIC;
  v_remaining_receive_qty NUMERIC;
  v_take_qty NUMERIC;
  v_pick_row RECORD;
  v_now TIMESTAMP;
  v_has_receive_line BOOLEAN := FALSE;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be completed as direct customer pickup';
  END IF;

  v_now := NOW();

  FOR v_line IN
    SELECT value
    FROM jsonb_array_elements(COALESCE(p_items, '[]'::jsonb))
  LOOP
    v_item_id := NULLIF(v_line->>'deliveryNoteItemId', '')::UUID;
    IF v_item_id IS NULL THEN
      CONTINUE;
    END IF;

    v_received_qty := COALESCE((v_line->>'receivedQty')::NUMERIC, 0);

    SELECT *
    INTO v_dn_item
    FROM delivery_note_items
    WHERE id = v_item_id
      AND company_id = p_company_id
      AND dn_id = p_dn_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Invalid delivery note item %', v_item_id;
    END IF;

    SELECT COALESCE(SUM(GREATEST(0, COALESCE(dispatched_qty, 0) - COALESCE(received_qty, 0))), 0)
    INTO v_max_receivable_qty
    FROM delivery_note_item_picks
    WHERE company_id = p_company_id
      AND dn_id = p_dn_id
      AND delivery_note_item_id = v_dn_item.id
      AND deleted_at IS NULL;

    IF v_max_receivable_qty = 0 THEN
      v_max_receivable_qty := COALESCE(v_dn_item.dispatched_qty, 0);
    END IF;

    IF v_received_qty < 0 OR v_received_qty > v_max_receivable_qty THEN
      RAISE EXCEPTION 'Received quantity must be between 0 and %', v_max_receivable_qty;
    END IF;

    IF v_received_qty = 0 THEN
      CONTINUE;
    END IF;

    v_has_receive_line := TRUE;
    v_remaining_receive_qty := v_received_qty;

    FOR v_pick_row IN
      SELECT *
      FROM delivery_note_item_picks
      WHERE company_id = p_company_id
        AND dn_id = p_dn_id
        AND delivery_note_item_id = v_dn_item.id
        AND deleted_at IS NULL
        AND COALESCE(dispatched_qty, 0) > COALESCE(received_qty, 0)
      ORDER BY created_at ASC, id ASC
      FOR UPDATE
    LOOP
      EXIT WHEN v_remaining_receive_qty <= 0;

      v_take_qty := LEAST(
        v_remaining_receive_qty,
        GREATEST(0, COALESCE(v_pick_row.dispatched_qty, 0) - COALESCE(v_pick_row.received_qty, 0))
      );
      IF v_take_qty <= 0 THEN
        CONTINUE;
      END IF;

      UPDATE delivery_note_item_picks
      SET
        received_qty = COALESCE(received_qty, 0) + v_take_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_pick_row.id;

      v_remaining_receive_qty := v_remaining_receive_qty - v_take_qty;
    END LOOP;

    IF v_remaining_receive_qty > 0 THEN
      RAISE EXCEPTION 'Insufficient dispatched pick rows to complete customer pickup for delivery note item %',
        v_dn_item.id;
    END IF;

    UPDATE stock_request_items
    SET
      received_qty = COALESCE(received_qty, 0) + v_received_qty,
      updated_at = v_now
    WHERE id = v_dn_item.sr_item_id;
  END LOOP;

  IF NOT v_has_receive_line THEN
    RAISE EXCEPTION 'No dispatched quantities available to complete';
  END IF;

  UPDATE delivery_notes
  SET
    status = 'received',
    received_at = COALESCE(p_received_date::timestamp, v_now),
    notes = COALESCE(NULLIF(BTRIM(p_notes), ''), notes),
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260224170000_add_delivery_note_fulfillment_mode.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add Delivery Note Fulfillment Mode
-- Version: 20260224170000
-- Description: Persists fulfillment mode on delivery notes so direct customer
--              pickup can be guarded from normal DN receive posting.
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

ALTER TABLE delivery_notes
  ADD COLUMN IF NOT EXISTS fulfillment_mode VARCHAR(50) NOT NULL DEFAULT 'transfer_to_store';

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'delivery_notes_fulfillment_mode_check'
  ) THEN
    ALTER TABLE delivery_notes
      ADD CONSTRAINT delivery_notes_fulfillment_mode_check
      CHECK (
        fulfillment_mode IN ('transfer_to_store', 'customer_pickup_from_warehouse')
      );
  END IF;
END $$;

COMMENT ON COLUMN delivery_notes.fulfillment_mode IS
  'Fulfillment path: transfer_to_store (normal dispatch+receive inventory) or customer_pickup_from_warehouse (dispatch only inventory, workflow receive completion only).';

CREATE INDEX IF NOT EXISTS idx_delivery_notes_company_fulfillment_mode
  ON delivery_notes(company_id, fulfillment_mode)
  WHERE deleted_at IS NULL;

COMMIT;


-- ============================================================================
-- Migration: 20260224180000_add_item_location_batch_sku.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add Item Location Batch SKU
-- Version: 20260224180000
-- Description: Adds a database-generated 10-digit scan code on item_location_batch
--              to identify a specific item + batch + location(shelf/rack/bin).
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

-- Sequence-backed generator avoids race conditions from app-side generation.
CREATE SEQUENCE IF NOT EXISTS public.item_location_batch_sku_seq
  AS bigint
  START WITH 1
  INCREMENT BY 1
  NO MINVALUE
  NO MAXVALUE
  CACHE 20;

CREATE OR REPLACE FUNCTION public.generate_item_location_batch_sku()
RETURNS VARCHAR(10)
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_seq NUMERIC;
  v_mod_base CONSTANT NUMERIC := 10000000000; -- 10^10
  v_val NUMERIC;
BEGIN
  -- Pseudo-randomized permutation from a monotonically increasing sequence.
  -- Multiplier is coprime with 10^10 (not divisible by 2 or 5), preserving uniqueness
  -- within the modulus cycle.
  v_seq := nextval('public.item_location_batch_sku_seq');
  v_val := mod((v_seq * 2454267029) + 518734127, v_mod_base);

  RETURN LPAD(TRUNC(v_val)::BIGINT::TEXT, 10, '0');
END;
$$;

ALTER TABLE item_location_batch
  ADD COLUMN IF NOT EXISTS batch_location_sku VARCHAR(10);

COMMENT ON COLUMN item_location_batch.batch_location_sku IS
  'Database-generated 10-digit scan code for a specific item+batch+location row.';


CREATE UNIQUE INDEX IF NOT EXISTS ux_item_location_batch_company_batch_location_sku
  ON item_location_batch(company_id, batch_location_sku)
  WHERE deleted_at IS NULL;

ALTER TABLE item_location_batch
  ALTER COLUMN batch_location_sku SET NOT NULL;

CREATE OR REPLACE FUNCTION public.set_item_location_batch_sku()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
BEGIN
  IF NEW.batch_location_sku IS NULL OR BTRIM(NEW.batch_location_sku) = '' THEN
    NEW.batch_location_sku := public.generate_item_location_batch_sku();
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trigger_item_location_batch_set_sku ON item_location_batch;
CREATE TRIGGER trigger_item_location_batch_set_sku
  BEFORE INSERT ON item_location_batch
  FOR EACH ROW
  EXECUTE FUNCTION public.set_item_location_batch_sku();

COMMIT;


-- ============================================================================
-- Migration: 20260224190000_persist_grn_box_batch_location_sku.sql
-- ============================================================================

-- ============================================================================
-- Migration: Persist batch_location_sku on GRN boxes after approval posting
-- Version: 20260224190000
-- Description: Stores the resolved item_location_batch.batch_location_sku on
--              grn_boxes so QR labels can print the same scan code reliably.
-- Date: 2026-02-24
-- ============================================================================

BEGIN;

ALTER TABLE grn_boxes
  ADD COLUMN IF NOT EXISTS batch_location_sku VARCHAR(10);

COMMENT ON COLUMN grn_boxes.batch_location_sku IS
  'Persisted batch_location_sku for the box''s posted item+location+batch row; populated during GRN approval when resolvable.';

CREATE INDEX IF NOT EXISTS idx_grn_boxes_batch_location_sku
  ON grn_boxes(batch_location_sku);

-- Backfill persisted box scan SKU for existing approved GRNs when the
-- corresponding item_location_batch row already exists.
UPDATE grn_boxes gb
SET batch_location_sku = ilb.batch_location_sku
FROM grn_items gi
JOIN grns g
  ON g.id = gi.grn_id
JOIN item_batch ib
  ON ib.company_id = g.company_id
 AND ib.item_id = gi.item_id
 AND ib.warehouse_id = g.warehouse_id
 AND ib.batch_code = g.batch_number
 AND ib.deleted_at IS NULL
JOIN item_location_batch ilb
  ON ilb.company_id = g.company_id
 AND ilb.item_id = gi.item_id
 AND ilb.warehouse_id = g.warehouse_id
 AND ilb.item_batch_id = ib.id
 AND ilb.deleted_at IS NULL
WHERE gb.grn_item_id = gi.id
  AND gb.warehouse_location_id IS NOT NULL
  AND ilb.location_id = gb.warehouse_location_id
  AND COALESCE(gb.batch_location_sku, '') = '';

CREATE OR REPLACE FUNCTION public.approve_grn_with_batch_inventory(
  p_company_id UUID,
  p_user_id UUID,
  p_grn_id UUID,
  p_notes TEXT DEFAULT NULL
)
RETURNS TEXT
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_grn grns%ROWTYPE;
  v_grn_item grn_items%ROWTYPE;
  v_item_uom_id UUID;
  v_now TIMESTAMP := NOW();
  v_tx_id UUID;
  v_tx_code TEXT;
  v_posting_date DATE;
  v_posting_time TIME;
  v_default_location_id UUID;
  v_generated_batch_code TEXT;
  v_batch_code TEXT;
  v_item_wh item_warehouse%ROWTYPE;
  v_item_batch item_batch%ROWTYPE;
  v_item_loc item_location%ROWTYPE;
  v_item_loc_batch item_location_batch%ROWTYPE;
  v_received_qty NUMERIC;
  v_damaged_qty NUMERIC;
  v_batch_received_at TIMESTAMP;
  v_boxes_total_qty NUMERIC;
  v_remainder_qty NUMERIC;
  v_has_items BOOLEAN := FALSE;
  v_line_location RECORD;
  v_item_wh_current_stock NUMERIC;
  v_item_wh_reserved_stock NUMERIC;
  v_item_wh_next_stock NUMERIC;
BEGIN
  SELECT *
  INTO v_grn
  FROM grns
  WHERE id = p_grn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'GRN not found';
  END IF;

  IF v_grn.status <> 'pending_approval' THEN
    RAISE EXCEPTION 'Only GRNs in pending approval can be approved';
  END IF;

  v_posting_date := COALESCE(v_grn.receiving_date, CURRENT_DATE);
  v_posting_time := v_now::TIME;
  v_batch_received_at := v_posting_date::TIMESTAMP + v_posting_time;

  INSERT INTO warehouse_locations (
    company_id,
    warehouse_id,
    code,
    name,
    location_type,
    is_pickable,
    is_storable,
    is_active,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_grn.warehouse_id,
    'MAIN',
    'Main',
    'bin',
    TRUE,
    TRUE,
    TRUE,
    p_user_id,
    p_user_id
  )
  ON CONFLICT (company_id, warehouse_id, code) DO UPDATE
  SET updated_by = EXCLUDED.updated_by
  RETURNING id INTO v_default_location_id;

  INSERT INTO stock_transactions (
    company_id,
    business_unit_id,
    transaction_type,
    transaction_date,
    warehouse_id,
    to_location_id,
    reference_type,
    reference_id,
    status,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_grn.business_unit_id,
    'in',
    v_posting_date,
    v_grn.warehouse_id,
    v_default_location_id,
    'grn',
    v_grn.id,
    'posted',
    COALESCE(NULLIF(BTRIM(p_notes), ''), 'Auto-created from GRN ' || v_grn.grn_number),
    p_user_id,
    p_user_id
  )
  RETURNING id, transaction_code INTO v_tx_id, v_tx_code;

  FOR v_grn_item IN
    SELECT gi.*
    FROM grn_items gi
    WHERE gi.grn_id = v_grn.id
    ORDER BY gi.created_at ASC, gi.id ASC
    FOR UPDATE
  LOOP
    v_has_items := TRUE;
    v_received_qty := COALESCE(v_grn_item.received_qty, 0);
    v_damaged_qty := COALESCE(v_grn_item.damaged_qty, 0);

    IF v_received_qty <= 0 THEN
      CONTINUE;
    END IF;

    SELECT i.uom_id
    INTO v_item_uom_id
    FROM items i
    WHERE i.id = v_grn_item.item_id;

    IF v_item_uom_id IS NULL THEN
      RAISE EXCEPTION 'Item UOM not found for item %', v_grn_item.item_id;
    END IF;

    v_generated_batch_code := COALESCE(
      NULLIF(BTRIM(v_grn.batch_number), ''),
      'GRN-' || v_grn.grn_number || '-' || SUBSTRING(REPLACE(v_grn_item.id::TEXT, '-', ''), 1, 8)
    );
    v_batch_code := v_generated_batch_code;

    PERFORM 1
    FROM item_batch ib_dup
    WHERE ib_dup.company_id = p_company_id
      AND ib_dup.item_id = v_grn_item.item_id
      AND ib_dup.warehouse_id = v_grn.warehouse_id
      AND ib_dup.batch_code = v_batch_code
      AND ib_dup.deleted_at IS NULL;

    IF FOUND THEN
      RAISE EXCEPTION 'Duplicate batch code % for item % in warehouse %',
        v_batch_code, v_grn_item.item_id, v_grn.warehouse_id;
    END IF;

    SELECT *
    INTO v_item_wh
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_grn_item.item_id
      AND warehouse_id = v_grn.warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF FOUND THEN
      v_item_wh_current_stock := COALESCE(v_item_wh.current_stock, 0);
      v_item_wh_reserved_stock := COALESCE(v_item_wh.reserved_stock, 0);
      v_item_wh_next_stock := v_item_wh_current_stock + v_received_qty;

      UPDATE item_warehouse
      SET
        current_stock = v_item_wh_next_stock,
        in_transit = GREATEST(0, COALESCE(in_transit, 0) - v_received_qty),
        estimated_arrival_date = CASE
          WHEN GREATEST(0, COALESCE(in_transit, 0) - v_received_qty) > 0 THEN estimated_arrival_date
          ELSE NULL
        END,
        default_location_id = COALESCE(default_location_id, v_default_location_id),
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_wh.id;
    ELSE
      v_item_wh_current_stock := 0;
      v_item_wh_reserved_stock := 0;
      v_item_wh_next_stock := v_received_qty;

      INSERT INTO item_warehouse (
        company_id,
        item_id,
        warehouse_id,
        current_stock,
        reserved_stock,
        in_transit,
        estimated_arrival_date,
        default_location_id,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        v_item_wh_next_stock,
        0,
        0,
        NULL,
        v_default_location_id,
        p_user_id,
        p_user_id
      );
    END IF;

    INSERT INTO item_batch (
      company_id,
      item_id,
      warehouse_id,
      batch_code,
      received_at,
      qty_on_hand,
      qty_reserved,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_grn_item.item_id,
      v_grn.warehouse_id,
      v_batch_code,
      v_batch_received_at,
      v_received_qty,
      0,
      p_user_id,
      p_user_id
    )
    RETURNING * INTO v_item_batch;

    v_boxes_total_qty := 0;

    FOR v_line_location IN
      SELECT
        gb.warehouse_location_id AS location_id,
        MIN(NULLIF(BTRIM(gb.batch_location_sku), '')) AS batch_location_sku,
        SUM(COALESCE(gb.qty_per_box, 0))::NUMERIC AS qty
      FROM grn_boxes gb
      WHERE gb.grn_item_id = v_grn_item.id
        AND gb.warehouse_location_id IS NOT NULL
      GROUP BY gb.warehouse_location_id
      ORDER BY gb.warehouse_location_id
    LOOP
      EXIT WHEN v_line_location.qty IS NULL OR v_line_location.qty <= 0;
      v_boxes_total_qty := v_boxes_total_qty + COALESCE(v_line_location.qty, 0);

      INSERT INTO item_location (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        v_line_location.location_id,
        v_line_location.qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
      SET
        qty_on_hand = item_location.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now
      RETURNING * INTO v_item_loc;

      INSERT INTO item_location_batch (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        item_batch_id,
        batch_location_sku,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        v_line_location.location_id,
        v_item_batch.id,
        NULLIF(BTRIM(v_line_location.batch_location_sku::TEXT), ''),
        v_line_location.qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id, item_batch_id) DO UPDATE
      SET
        qty_on_hand = item_location_batch.qty_on_hand + EXCLUDED.qty_on_hand,
        batch_location_sku = COALESCE(item_location_batch.batch_location_sku, EXCLUDED.batch_location_sku),
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now
      RETURNING * INTO v_item_loc_batch;

      UPDATE grn_boxes
      SET
        batch_location_sku = v_item_loc_batch.batch_location_sku
      WHERE grn_item_id = v_grn_item.id
        AND warehouse_location_id = v_line_location.location_id;
    END LOOP;

    v_remainder_qty := GREATEST(0, v_received_qty - COALESCE(v_boxes_total_qty, 0));
    IF v_remainder_qty > 0 THEN
      INSERT INTO item_location (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        COALESCE(v_item_wh.default_location_id, v_default_location_id),
        v_remainder_qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
      SET
        qty_on_hand = item_location.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now;

      INSERT INTO item_location_batch (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        item_batch_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        COALESCE(v_item_wh.default_location_id, v_default_location_id),
        v_item_batch.id,
        v_remainder_qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id, item_batch_id) DO UPDATE
      SET
        qty_on_hand = item_location_batch.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now;
    END IF;

    INSERT INTO stock_transaction_items (
      company_id,
      transaction_id,
      item_id,
      quantity,
      uom_id,
      batch_no,
      qty_before,
      qty_after,
      posting_date,
      posting_time,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_tx_id,
      v_grn_item.item_id,
      v_received_qty,
      v_item_uom_id,
      v_batch_code,
      v_item_wh_current_stock,
      v_item_wh_next_stock,
      v_posting_date,
      v_posting_time,
      CASE
        WHEN v_damaged_qty > 0 THEN 'GRN ' || v_grn.grn_number || ' (Damaged: ' || v_damaged_qty || ')'
        ELSE 'GRN ' || v_grn.grn_number
      END,
      p_user_id,
      p_user_id
    );
  END LOOP;

  IF NOT v_has_items THEN
    RAISE EXCEPTION 'GRN has no items';
  END IF;

  UPDATE grns
  SET
    status = 'approved',
    checked_by = p_user_id,
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = v_grn.id;

  UPDATE load_lists
  SET
    status = 'received',
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = v_grn.load_list_id;

  RETURN v_tx_code;
END;
$$;

COMMENT ON FUNCTION public.approve_grn_with_batch_inventory(UUID, UUID, UUID, TEXT) IS
  'Approves a GRN and posts inventory into warehouse/location/batch tables in one transaction, persisting box batch_location_sku when resolvable.';

COMMIT;


