-- ============================================================================
-- Migration: 20260227124500_fix_void_cancel_short_qty_reset.sql
-- ============================================================================

-- ============================================================================
-- Migration: Fix short_qty reset in DN void / pick-list cancel RPCs
-- Version: 20260227124500
-- Description: Ensures short_qty remains consistent with CHECK constraints
--              (short_qty = allocated_qty - picked_qty) when resetting picks.
-- Date: 2026-02-27
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.cancel_pick_list_reset_progress(
  p_company_id UUID,
  p_user_id UUID,
  p_pick_list_id UUID
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_pick_list pick_lists%ROWTYPE;
  v_now TIMESTAMPTZ := NOW();
  v_has_dispatched BOOLEAN := FALSE;
BEGIN
  SELECT *
  INTO v_pick_list
  FROM pick_lists
  WHERE id = p_pick_list_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Pick list not found';
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM delivery_note_items dni
    WHERE dni.company_id = p_company_id
      AND dni.dn_id = v_pick_list.dn_id
      AND COALESCE(dni.dispatched_qty, 0) > 0
  )
  INTO v_has_dispatched;

  IF v_has_dispatched THEN
    RAISE EXCEPTION 'Cannot cancel pick list after dispatch has started';
  END IF;

  UPDATE pick_list_items
  SET
    picked_qty = 0,
    short_qty = allocated_qty,
    updated_at = v_now
  WHERE company_id = p_company_id
    AND pick_list_id = p_pick_list_id;

  UPDATE delivery_note_item_picks
  SET
    deleted_at = v_now,
    updated_at = v_now,
    updated_by = p_user_id
  WHERE company_id = p_company_id
    AND pick_list_id = p_pick_list_id
    AND deleted_at IS NULL;
END;
$$;

CREATE OR REPLACE FUNCTION public.void_delivery_note_pre_dispatch(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_reason TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_now TIMESTAMPTZ := NOW();
  v_reason TEXT := NULLIF(BTRIM(p_reason), '');
  v_pick_cancel_reason TEXT;
  v_has_dispatched BOOLEAN := FALSE;
  v_rel RECORD;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status NOT IN ('draft', 'confirmed', 'queued_for_picking', 'picking_in_progress', 'dispatch_ready') THEN
    RAISE EXCEPTION 'Delivery note can only be voided before dispatch';
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM delivery_note_items dni
    WHERE dni.company_id = p_company_id
      AND dni.dn_id = p_dn_id
      AND COALESCE(dni.dispatched_qty, 0) > 0
  )
  INTO v_has_dispatched;

  IF v_has_dispatched THEN
    RAISE EXCEPTION 'Delivery note can only be voided before dispatch';
  END IF;

  FOR v_rel IN
    SELECT
      dni.item_id,
      dni.fulfilling_warehouse_id AS warehouse_id,
      SUM(GREATEST(0, COALESCE(dni.allocated_qty, 0) - COALESCE(dni.dispatched_qty, 0)))::NUMERIC AS qty_to_release
    FROM delivery_note_items dni
    WHERE dni.company_id = p_company_id
      AND dni.dn_id = p_dn_id
      AND dni.fulfilling_warehouse_id IS NOT NULL
    GROUP BY dni.item_id, dni.fulfilling_warehouse_id
  LOOP
    IF COALESCE(v_rel.qty_to_release, 0) <= 0 THEN
      CONTINUE;
    END IF;

    UPDATE item_warehouse iw
    SET
      reserved_stock = GREATEST(0, COALESCE(iw.reserved_stock, 0) - v_rel.qty_to_release),
      updated_at = v_now,
      updated_by = p_user_id
    WHERE iw.company_id = p_company_id
      AND iw.item_id = v_rel.item_id
      AND iw.warehouse_id = v_rel.warehouse_id
      AND iw.deleted_at IS NULL;
  END LOOP;

  v_pick_cancel_reason := 'Delivery note voided' || COALESCE(': ' || v_reason, '');

  UPDATE pick_list_items pli
  SET
    picked_qty = 0,
    short_qty = pli.allocated_qty,
    updated_at = v_now
  FROM pick_lists pl
  WHERE pl.id = pli.pick_list_id
    AND pl.company_id = p_company_id
    AND pl.dn_id = p_dn_id
    AND pl.deleted_at IS NULL
    AND pli.company_id = p_company_id;

  UPDATE pick_lists
  SET
    status = 'cancelled',
    cancel_reason = v_pick_cancel_reason,
    updated_at = v_now,
    updated_by = p_user_id
  WHERE company_id = p_company_id
    AND dn_id = p_dn_id
    AND deleted_at IS NULL
    AND status <> 'cancelled';

  UPDATE delivery_note_item_picks
  SET
    deleted_at = v_now,
    updated_at = v_now,
    updated_by = p_user_id
  WHERE company_id = p_company_id
    AND dn_id = p_dn_id
    AND deleted_at IS NULL;

  UPDATE delivery_note_items
  SET
    picked_qty = 0,
    short_qty = allocated_qty,
    updated_at = v_now
  WHERE company_id = p_company_id
    AND dn_id = p_dn_id;

  UPDATE delivery_notes
  SET
    status = 'voided',
    voided_at = v_now,
    void_reason = v_reason,
    updated_at = v_now,
    updated_by = p_user_id
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260228110000_add_generic_notification_rpcs.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add Generic Notification RPCs
-- Version: 20260228110000
-- Description: Adds reusable SECURITY DEFINER RPCs for notification fanout
--              and warehouse -> business unit lookup.
-- Date: 2026-02-28
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.get_warehouse_business_units(
  p_company_id UUID,
  p_warehouse_ids UUID[]
)
RETURNS TABLE (
  warehouse_id UUID,
  business_unit_id UUID
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM users u
    WHERE u.id = auth.uid()
      AND u.company_id = p_company_id
      AND u.deleted_at IS NULL
  ) THEN
    RAISE EXCEPTION 'User is not authorized for the specified company';
  END IF;

  RETURN QUERY
  SELECT
    w.id AS warehouse_id,
    w.business_unit_id
  FROM warehouses w
  WHERE w.company_id = p_company_id
    AND w.id = ANY(COALESCE(p_warehouse_ids, ARRAY[]::UUID[]))
    AND w.deleted_at IS NULL;
END;
$$;

CREATE OR REPLACE FUNCTION public.notify_users(
  p_company_id UUID,
  p_actor_user_id UUID,
  p_target_user_ids UUID[],
  p_title TEXT,
  p_message TEXT,
  p_type TEXT,
  p_metadata JSONB DEFAULT NULL
)
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_inserted_count INTEGER := 0;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;

  IF p_actor_user_id IS DISTINCT FROM auth.uid() THEN
    RAISE EXCEPTION 'Actor mismatch';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM users u
    WHERE u.id = p_actor_user_id
      AND u.company_id = p_company_id
      AND u.deleted_at IS NULL
  ) THEN
    RAISE EXCEPTION 'Actor is not authorized for the specified company';
  END IF;

  WITH target_users AS (
    SELECT DISTINCT u.id AS user_id
    FROM users u
    WHERE u.company_id = p_company_id
      AND u.id = ANY(COALESCE(p_target_user_ids, ARRAY[]::UUID[]))
      AND u.is_active = TRUE
      AND u.deleted_at IS NULL
  ), inserted AS (
    INSERT INTO notifications (
      company_id,
      user_id,
      title,
      message,
      type,
      metadata
    )
    SELECT
      p_company_id,
      tu.user_id,
      p_title,
      p_message,
      p_type,
      p_metadata
    FROM target_users tu
    RETURNING 1
  )
  SELECT COUNT(*) INTO v_inserted_count FROM inserted;

  RETURN v_inserted_count;
END;
$$;

CREATE OR REPLACE FUNCTION public.notify_business_units(
  p_company_id UUID,
  p_actor_user_id UUID,
  p_target_business_unit_ids UUID[],
  p_title TEXT,
  p_message TEXT,
  p_type TEXT,
  p_metadata JSONB DEFAULT NULL,
  p_exclude_user_ids UUID[] DEFAULT NULL
)
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_inserted_count INTEGER := 0;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;

  IF p_actor_user_id IS DISTINCT FROM auth.uid() THEN
    RAISE EXCEPTION 'Actor mismatch';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM users u
    WHERE u.id = p_actor_user_id
      AND u.company_id = p_company_id
      AND u.deleted_at IS NULL
  ) THEN
    RAISE EXCEPTION 'Actor is not authorized for the specified company';
  END IF;

  WITH target_users AS (
    SELECT DISTINCT uba.user_id
    FROM user_business_unit_access uba
    JOIN users u
      ON u.id = uba.user_id
    WHERE uba.business_unit_id = ANY(COALESCE(p_target_business_unit_ids, ARRAY[]::UUID[]))
      AND u.company_id = p_company_id
      AND u.is_active = TRUE
      AND u.deleted_at IS NULL
      AND (
        p_exclude_user_ids IS NULL
        OR NOT (uba.user_id = ANY(p_exclude_user_ids))
      )
  ), inserted AS (
    INSERT INTO notifications (
      company_id,
      user_id,
      title,
      message,
      type,
      metadata
    )
    SELECT
      p_company_id,
      tu.user_id,
      p_title,
      p_message,
      p_type,
      p_metadata
    FROM target_users tu
    RETURNING 1
  )
  SELECT COUNT(*) INTO v_inserted_count FROM inserted;

  RETURN v_inserted_count;
END;
$$;

REVOKE ALL ON FUNCTION public.get_warehouse_business_units(UUID, UUID[]) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.get_warehouse_business_units(UUID, UUID[]) TO authenticated;

REVOKE ALL ON FUNCTION public.notify_users(UUID, UUID, UUID[], TEXT, TEXT, TEXT, JSONB) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.notify_users(UUID, UUID, UUID[], TEXT, TEXT, TEXT, JSONB) TO authenticated;

REVOKE ALL ON FUNCTION public.notify_business_units(UUID, UUID, UUID[], TEXT, TEXT, TEXT, JSONB, UUID[]) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.notify_business_units(UUID, UUID, UUID[], TEXT, TEXT, TEXT, JSONB, UUID[]) TO authenticated;

COMMENT ON FUNCTION public.get_warehouse_business_units(UUID, UUID[]) IS
  'Resolves warehouse IDs to business units within a company context.';

COMMENT ON FUNCTION public.notify_users(UUID, UUID, UUID[], TEXT, TEXT, TEXT, JSONB) IS
  'Generic user-targeted notification insert for a company, with actor validation.';

COMMENT ON FUNCTION public.notify_business_units(UUID, UUID, UUID[], TEXT, TEXT, TEXT, JSONB, UUID[]) IS
  'Generic BU-targeted notification fanout with actor validation and optional excluded users.';

COMMIT;


-- ============================================================================
-- Migration: 20260228120000_enable_realtime_for_purchasing_and_notifications.sql
-- ============================================================================

-- Publish purchasing and notifications tables to Supabase realtime.
DO $$
DECLARE
  v_table TEXT;
BEGIN
  FOR v_table IN
    SELECT unnest(ARRAY[
      'notifications',
      'stock_requisitions',
      'stock_requisition_items',
      'load_lists',
      'load_list_items',
      'load_list_sr_items',
      'grns',
      'grn_items',
      'grn_boxes'
    ])
  LOOP
    IF EXISTS (
      SELECT 1
      FROM pg_class c
      JOIN pg_namespace n ON n.oid = c.relnamespace
      WHERE n.nspname = 'public'
        AND c.relname = v_table
        AND c.relkind = 'r'
    )
    AND NOT EXISTS (
      SELECT 1
      FROM pg_publication p
      JOIN pg_publication_rel pr ON pr.prpubid = p.oid
      JOIN pg_class c ON c.oid = pr.prrelid
      JOIN pg_namespace n ON n.oid = c.relnamespace
      WHERE p.pubname = 'supabase_realtime'
        AND n.nspname = 'public'
        AND c.relname = v_table
    ) THEN
      EXECUTE format(
        'ALTER PUBLICATION supabase_realtime ADD TABLE %I.%I',
        'public',
        v_table
      );
    END IF;
  END LOOP;
END
$$;


-- ============================================================================
-- Migration: 20260228130000_scope_notifications_by_business_unit.sql
-- ============================================================================

-- ============================================================================
-- Migration: Scope Notifications by Business Unit
-- Version: 20260228130000
-- Description:
--   1) Adds notifications.business_unit_id (nullable for global notifications).
--   2) Enforces BU-aware read visibility (current BU + global NULL).
--   3) Updates generic notification RPCs to stamp owner BU per notification row.
-- Date: 2026-02-28
-- ============================================================================

BEGIN;

ALTER TABLE public.notifications
  ADD COLUMN IF NOT EXISTS business_unit_id UUID REFERENCES public.business_units(id);

CREATE INDEX IF NOT EXISTS idx_notifications_user_bu_created
  ON public.notifications(user_id, business_unit_id, created_at DESC);

DROP POLICY IF EXISTS notifications_company_select ON public.notifications;
CREATE POLICY notifications_company_select ON public.notifications
  FOR SELECT
  USING (
    user_id = auth.uid()
    AND (
      business_unit_id IS NULL
      OR business_unit_id = get_current_business_unit_id()
    )
  );

DROP POLICY IF EXISTS notifications_company_insert ON public.notifications;
CREATE POLICY notifications_company_insert ON public.notifications
  FOR INSERT
  WITH CHECK (
    company_id IN (SELECT company_id FROM public.users WHERE id = auth.uid())
    AND user_id IN (
      SELECT id
      FROM public.users
      WHERE company_id IN (SELECT company_id FROM public.users WHERE id = auth.uid())
        AND deleted_at IS NULL
    )
    AND (
      business_unit_id IS NULL
      OR business_unit_id IN (
        SELECT bu.id
        FROM public.business_units bu
        WHERE bu.company_id IN (SELECT company_id FROM public.users WHERE id = auth.uid())
      )
    )
  );

CREATE OR REPLACE FUNCTION public.notify_users(
  p_company_id UUID,
  p_actor_user_id UUID,
  p_target_user_ids UUID[],
  p_title TEXT,
  p_message TEXT,
  p_type TEXT,
  p_metadata JSONB DEFAULT NULL,
  p_business_unit_id UUID DEFAULT NULL
)
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_inserted_count INTEGER := 0;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;

  IF p_actor_user_id IS DISTINCT FROM auth.uid() THEN
    RAISE EXCEPTION 'Actor mismatch';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM users u
    WHERE u.id = p_actor_user_id
      AND u.company_id = p_company_id
      AND u.deleted_at IS NULL
  ) THEN
    RAISE EXCEPTION 'Actor is not authorized for the specified company';
  END IF;

  IF p_business_unit_id IS NOT NULL
     AND NOT EXISTS (
       SELECT 1
       FROM business_units bu
       WHERE bu.id = p_business_unit_id
         AND bu.company_id = p_company_id
     ) THEN
    RAISE EXCEPTION 'Notification business unit is not authorized for the specified company';
  END IF;

  WITH target_users AS (
    SELECT DISTINCT u.id AS user_id
    FROM users u
    WHERE u.company_id = p_company_id
      AND u.id = ANY(COALESCE(p_target_user_ids, ARRAY[]::UUID[]))
      AND u.is_active = TRUE
      AND u.deleted_at IS NULL
  ), inserted AS (
    INSERT INTO notifications (
      company_id,
      business_unit_id,
      user_id,
      title,
      message,
      type,
      metadata
    )
    SELECT
      p_company_id,
      p_business_unit_id,
      tu.user_id,
      p_title,
      p_message,
      p_type,
      p_metadata
    FROM target_users tu
    RETURNING 1
  )
  SELECT COUNT(*) INTO v_inserted_count FROM inserted;

  RETURN v_inserted_count;
END;
$$;

CREATE OR REPLACE FUNCTION public.notify_business_units(
  p_company_id UUID,
  p_actor_user_id UUID,
  p_target_business_unit_ids UUID[],
  p_title TEXT,
  p_message TEXT,
  p_type TEXT,
  p_metadata JSONB DEFAULT NULL,
  p_exclude_user_ids UUID[] DEFAULT NULL
)
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_inserted_count INTEGER := 0;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;

  IF p_actor_user_id IS DISTINCT FROM auth.uid() THEN
    RAISE EXCEPTION 'Actor mismatch';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM users u
    WHERE u.id = p_actor_user_id
      AND u.company_id = p_company_id
      AND u.deleted_at IS NULL
  ) THEN
    RAISE EXCEPTION 'Actor is not authorized for the specified company';
  END IF;

  WITH target_users AS (
    SELECT DISTINCT
      uba.user_id,
      uba.business_unit_id
    FROM user_business_unit_access uba
    JOIN users u
      ON u.id = uba.user_id
    JOIN business_units bu
      ON bu.id = uba.business_unit_id
    WHERE uba.business_unit_id = ANY(COALESCE(p_target_business_unit_ids, ARRAY[]::UUID[]))
      AND bu.company_id = p_company_id
      AND u.company_id = p_company_id
      AND u.is_active = TRUE
      AND u.deleted_at IS NULL
      AND (
        p_exclude_user_ids IS NULL
        OR NOT (uba.user_id = ANY(p_exclude_user_ids))
      )
  ), inserted AS (
    INSERT INTO notifications (
      company_id,
      business_unit_id,
      user_id,
      title,
      message,
      type,
      metadata
    )
    SELECT
      p_company_id,
      tu.business_unit_id,
      tu.user_id,
      p_title,
      p_message,
      p_type,
      p_metadata
    FROM target_users tu
    RETURNING 1
  )
  SELECT COUNT(*) INTO v_inserted_count FROM inserted;

  RETURN v_inserted_count;
END;
$$;

REVOKE ALL ON FUNCTION public.notify_users(UUID, UUID, UUID[], TEXT, TEXT, TEXT, JSONB, UUID) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.notify_users(UUID, UUID, UUID[], TEXT, TEXT, TEXT, JSONB, UUID) TO authenticated;

REVOKE ALL ON FUNCTION public.notify_business_units(UUID, UUID, UUID[], TEXT, TEXT, TEXT, JSONB, UUID[]) FROM PUBLIC;
