DROP INDEX IF EXISTS public.idx_items_company_sku;
ALTER TABLE public.items DROP CONSTRAINT IF EXISTS items_sku_check;
ALTER TABLE public.items DROP COLUMN IF EXISTS sku;

COMMIT;


-- ============================================================================
-- Migration: 20260405172000_fix_dn_reservation_qty_per_unit.sql
-- ============================================================================

-- ============================================================================
-- Migration: Fix DN reservation qty_per_unit handling
-- Version: 20260405172000
-- Description: Converts delivery note allocated quantities from selected
--              item-unit-option quantity into base quantity when reserving
--              inventory.
-- Date: 2026-04-05
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.reserve_delivery_note_inventory(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dni delivery_note_items%ROWTYPE;
  v_wh item_warehouse%ROWTYPE;
  v_available NUMERIC;
  v_suggested_pick_location_id UUID;
  v_suggested_pick_batch_code TEXT;
  v_suggested_pick_batch_received_at TIMESTAMP;
  v_total_allocated NUMERIC := 0;
  v_qty_per_unit NUMERIC := 1;
  v_allocated_base_qty NUMERIC := 0;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'draft' THEN
    RAISE EXCEPTION 'Inventory reservation only allowed while delivery note is in draft status';
  END IF;

  FOR v_dni IN
    SELECT *
    FROM delivery_note_items
    WHERE company_id = p_company_id
      AND dn_id = p_dn_id
    ORDER BY created_at ASC, id ASC
    FOR UPDATE
  LOOP
    IF v_dni.item_unit_option_id IS NOT NULL THEN
      SELECT COALESCE(qty_per_unit, 1)
      INTO v_qty_per_unit
      FROM public.item_unit_options
      WHERE id = v_dni.item_unit_option_id
        AND deleted_at IS NULL;
    ELSE
      v_qty_per_unit := 1;
    END IF;

    v_allocated_base_qty := COALESCE(v_dni.allocated_qty, 0) * COALESCE(v_qty_per_unit, 1);
    v_total_allocated := v_total_allocated + v_allocated_base_qty;

    SELECT *
    INTO v_wh
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_dni.item_id
      AND warehouse_id = v_dni.fulfilling_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Insufficient stock for item % in warehouse %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id;
    END IF;

    v_available := GREATEST(0, COALESCE(v_wh.current_stock, 0) - COALESCE(v_wh.reserved_stock, 0));
    IF v_available < v_allocated_base_qty THEN
      RAISE EXCEPTION 'Insufficient available stock for item % in warehouse %. Available %, requested %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id, v_available, v_allocated_base_qty;
    END IF;

    UPDATE item_warehouse
    SET
      reserved_stock = COALESCE(reserved_stock, 0) + v_allocated_base_qty,
      updated_by = p_user_id,
      updated_at = NOW()
    WHERE id = v_wh.id;

    v_suggested_pick_location_id := NULL;
    v_suggested_pick_batch_code := NULL;
    v_suggested_pick_batch_received_at := NULL;

    SELECT
      ilb.location_id,
      ib.batch_code,
      ib.received_at
    INTO
      v_suggested_pick_location_id,
      v_suggested_pick_batch_code,
      v_suggested_pick_batch_received_at
    FROM item_location_batch ilb
    JOIN item_batch ib
      ON ib.id = ilb.item_batch_id
     AND ib.company_id = ilb.company_id
     AND ib.deleted_at IS NULL
    WHERE ilb.company_id = p_company_id
      AND ilb.item_id = v_dni.item_id
      AND ilb.warehouse_id = v_dni.fulfilling_warehouse_id
      AND ilb.deleted_at IS NULL
      AND GREATEST(0, COALESCE(ilb.qty_on_hand, 0) - COALESCE(ilb.qty_reserved, 0)) > 0
    ORDER BY ib.received_at ASC, ilb.created_at ASC, ilb.id ASC
    LIMIT 1;

    UPDATE delivery_note_items
    SET
      suggested_pick_location_id = COALESCE(v_suggested_pick_location_id, suggested_pick_location_id),
      suggested_pick_batch_code = COALESCE(v_suggested_pick_batch_code, suggested_pick_batch_code),
      suggested_pick_batch_received_at = COALESCE(v_suggested_pick_batch_received_at, suggested_pick_batch_received_at),
      updated_at = NOW()
    WHERE id = v_dni.id
      AND company_id = p_company_id;
  END LOOP;

  IF v_total_allocated <= 0 THEN
    RAISE EXCEPTION 'Delivery note has no allocatable line quantities';
  END IF;
END;
$$;

CREATE OR REPLACE FUNCTION public.reserve_delivery_note_inventory_lines(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_line_ids UUID[]
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dni delivery_note_items%ROWTYPE;
  v_wh item_warehouse%ROWTYPE;
  v_available NUMERIC;
  v_suggested_pick_location_id UUID;
  v_suggested_pick_batch_code TEXT;
  v_suggested_pick_batch_received_at TIMESTAMP;
  v_qty_per_unit NUMERIC := 1;
  v_allocated_base_qty NUMERIC := 0;
BEGIN
  IF COALESCE(array_length(p_line_ids, 1), 0) = 0 THEN
    RAISE EXCEPTION 'At least one delivery note line id is required';
  END IF;

  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status IN ('received', 'voided') THEN
    RAISE EXCEPTION 'Cannot reserve delivery note lines for received or voided delivery notes';
  END IF;

  FOR v_dni IN
    SELECT *
    FROM delivery_note_items
    WHERE company_id = p_company_id
      AND dn_id = p_dn_id
      AND id = ANY(p_line_ids)
    ORDER BY created_at ASC, id ASC
    FOR UPDATE
  LOOP
    IF COALESCE(v_dni.is_voided, FALSE) THEN
      RAISE EXCEPTION 'Cannot reserve inventory for voided delivery note line %', v_dni.id;
    END IF;

    IF v_dni.item_unit_option_id IS NOT NULL THEN
      SELECT COALESCE(qty_per_unit, 1)
      INTO v_qty_per_unit
      FROM public.item_unit_options
      WHERE id = v_dni.item_unit_option_id
        AND deleted_at IS NULL;
    ELSE
      v_qty_per_unit := 1;
    END IF;

    v_allocated_base_qty := COALESCE(v_dni.allocated_qty, 0) * COALESCE(v_qty_per_unit, 1);

    SELECT *
    INTO v_wh
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_dni.item_id
      AND warehouse_id = v_dni.fulfilling_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Insufficient stock for item % in warehouse %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id;
    END IF;

    v_available := GREATEST(0, COALESCE(v_wh.current_stock, 0) - COALESCE(v_wh.reserved_stock, 0));
    IF v_available < v_allocated_base_qty THEN
      RAISE EXCEPTION 'Insufficient available stock for item % in warehouse %. Available %, requested %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id, v_available, v_allocated_base_qty;
    END IF;

    UPDATE item_warehouse
    SET
      reserved_stock = COALESCE(reserved_stock, 0) + v_allocated_base_qty,
      updated_by = p_user_id,
      updated_at = NOW()
    WHERE id = v_wh.id;

    v_suggested_pick_location_id := NULL;
    v_suggested_pick_batch_code := NULL;
    v_suggested_pick_batch_received_at := NULL;

    SELECT
      ilb.location_id,
      ib.batch_code,
      ib.received_at
    INTO
      v_suggested_pick_location_id,
      v_suggested_pick_batch_code,
      v_suggested_pick_batch_received_at
    FROM item_location_batch ilb
    JOIN item_batch ib
      ON ib.id = ilb.item_batch_id
     AND ib.company_id = ilb.company_id
     AND ib.deleted_at IS NULL
    WHERE ilb.company_id = p_company_id
      AND ilb.item_id = v_dni.item_id
      AND ilb.warehouse_id = v_dni.fulfilling_warehouse_id
      AND ilb.deleted_at IS NULL
      AND GREATEST(0, COALESCE(ilb.qty_on_hand, 0) - COALESCE(ilb.qty_reserved, 0)) > 0
    ORDER BY ib.received_at ASC, ilb.created_at ASC, ilb.id ASC
    LIMIT 1;

    UPDATE delivery_note_items
    SET
      suggested_pick_location_id = COALESCE(v_suggested_pick_location_id, suggested_pick_location_id),
      suggested_pick_batch_code = COALESCE(v_suggested_pick_batch_code, suggested_pick_batch_code),
      suggested_pick_batch_received_at = COALESCE(v_suggested_pick_batch_received_at, suggested_pick_batch_received_at),
      updated_at = NOW()
    WHERE id = v_dni.id
      AND company_id = p_company_id;
  END LOOP;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260405174000_fix_dn_dispatch_receive_qty_per_unit.sql
-- ============================================================================

-- ============================================================================
-- Migration: Fix DN dispatch/receive qty_per_unit handling
-- Version: 20260405174000
-- Description: Converts delivery note selected-unit quantities into base
--              inventory quantity for dispatch, receive, and post-dispatch
--              adjustment flows.
-- Date: 2026-04-05
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.post_delivery_note_dispatch(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_business_unit_id UUID,
  p_dispatch_date DATE,
  p_notes TEXT,
  p_driver_name TEXT,
  p_driver_signature TEXT,
  p_items JSONB
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dn_item delivery_note_items%ROWTYPE;
  v_warehouse_stock item_warehouse%ROWTYPE;
  v_tx_id UUID;
  v_now TIMESTAMP;
  v_posting_date DATE;
  v_posting_time TIME;
  v_line JSONB;
  v_item_id UUID;
  v_dispatch_qty NUMERIC;
  v_dispatch_base_qty NUMERIC;
  v_remaining_pick_qty NUMERIC;
  v_remaining_dispatch_qty NUMERIC;
  v_take_qty NUMERIC;
  v_take_base_qty NUMERIC;
  v_current_stock NUMERIC;
  v_next_stock NUMERIC;
  v_has_dispatch_line BOOLEAN := FALSE;
  v_line_fulfilling_warehouse_id UUID;
  v_line_default_location_id UUID;
  v_reserved_stock NUMERIC;
  v_pick_row RECORD;
  v_item_batch_row item_batch%ROWTYPE;
  v_item_location_batch_row item_location_batch%ROWTYPE;
  v_item_location_row item_location%ROWTYPE;
  v_qty_per_unit NUMERIC := 1;
  v_item_base_uom_id UUID;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatch_ready' THEN
    RAISE EXCEPTION 'Only dispatch_ready delivery notes can be dispatched';
  END IF;

  IF p_business_unit_id IS NULL THEN
    RAISE EXCEPTION 'Business unit context required';
  END IF;

  v_now := NOW();
  v_posting_date := COALESCE(p_dispatch_date, v_now::DATE);
  v_posting_time := v_now::TIME;

  FOR v_line IN
    SELECT value
    FROM jsonb_array_elements(COALESCE(p_items, '[]'::jsonb))
  LOOP
    v_item_id := NULLIF(v_line->>'deliveryNoteItemId', '')::UUID;
    IF v_item_id IS NULL THEN
      CONTINUE;
    END IF;

    v_dispatch_qty := COALESCE((v_line->>'dispatchQty')::NUMERIC, 0);

    SELECT *
    INTO v_dn_item
    FROM delivery_note_items
    WHERE id = v_item_id
      AND company_id = p_company_id
      AND dn_id = p_dn_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Invalid delivery note item %', v_item_id;
    END IF;

    SELECT
      COALESCE(iuo.qty_per_unit, 1),
      i.uom_id
    INTO
      v_qty_per_unit,
      v_item_base_uom_id
    FROM public.items i
    LEFT JOIN public.item_unit_options iuo
      ON iuo.id = v_dn_item.item_unit_option_id
     AND iuo.deleted_at IS NULL
    WHERE i.id = v_dn_item.item_id;

    v_remaining_pick_qty := GREATEST(
      0,
      COALESCE(v_dn_item.picked_qty, 0) - COALESCE(v_dn_item.dispatched_qty, 0)
    );
    IF v_dispatch_qty < 0 OR v_dispatch_qty > v_remaining_pick_qty THEN
      RAISE EXCEPTION 'Invalid dispatch quantity for delivery note item %', v_item_id;
    END IF;

    IF v_dispatch_qty = 0 THEN
      CONTINUE;
    END IF;

    v_dispatch_base_qty := v_dispatch_qty * COALESCE(v_qty_per_unit, 1);

    v_line_fulfilling_warehouse_id := COALESCE(v_dn_item.fulfilling_warehouse_id, v_dn.fulfilling_warehouse_id);
    IF v_line_fulfilling_warehouse_id IS NULL THEN
      RAISE EXCEPTION 'Missing fulfilling warehouse for delivery note item %', v_item_id;
    END IF;

    INSERT INTO warehouse_locations (
      company_id,
      warehouse_id,
      code,
      name,
      location_type,
      is_pickable,
      is_storable,
      is_active,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_line_fulfilling_warehouse_id,
      'MAIN',
      'Main',
      'bin',
      TRUE,
      TRUE,
      TRUE,
      p_user_id,
      p_user_id
    )
    ON CONFLICT (company_id, warehouse_id, code) DO UPDATE
    SET updated_by = EXCLUDED.updated_by
    RETURNING id INTO v_line_default_location_id;

    INSERT INTO stock_transactions (
      company_id,
      business_unit_id,
      transaction_type,
      transaction_date,
      warehouse_id,
      from_location_id,
      reference_type,
      reference_id,
      reference_code,
      status,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      p_business_unit_id,
      'out',
      v_posting_date,
      v_line_fulfilling_warehouse_id,
      v_line_default_location_id,
      'delivery_note',
      v_dn.id,
      v_dn.dn_no,
      'posted',
      COALESCE(NULLIF(BTRIM(p_notes), ''), 'Delivery note ' || v_dn.dn_no || ' dispatched'),
      p_user_id,
      p_user_id
    )
    RETURNING id INTO v_tx_id;

    v_has_dispatch_line := TRUE;

    SELECT *
    INTO v_warehouse_stock
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_dn_item.item_id
      AND warehouse_id = v_line_fulfilling_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Insufficient stock for item %', v_dn_item.item_id;
    END IF;

    v_current_stock := COALESCE(v_warehouse_stock.current_stock, 0);
    IF v_current_stock < v_dispatch_base_qty THEN
      RAISE EXCEPTION 'Insufficient stock for item %', v_dn_item.item_id;
    END IF;

    v_reserved_stock := COALESCE(v_warehouse_stock.reserved_stock, 0);
    IF v_reserved_stock < v_dispatch_base_qty THEN
      RAISE EXCEPTION 'Insufficient reserved stock for item % on delivery note dispatch', v_dn_item.item_id;
    END IF;

    v_remaining_dispatch_qty := v_dispatch_qty;

    FOR v_pick_row IN
      SELECT *
      FROM delivery_note_item_picks
      WHERE company_id = p_company_id
        AND dn_id = p_dn_id
        AND delivery_note_item_id = v_dn_item.id
        AND deleted_at IS NULL
        AND COALESCE(picked_qty, 0) > COALESCE(dispatched_qty, 0)
      ORDER BY created_at ASC, id ASC
      FOR UPDATE
    LOOP
      EXIT WHEN v_remaining_dispatch_qty <= 0;

      v_take_qty := LEAST(
        v_remaining_dispatch_qty,
        GREATEST(0, COALESCE(v_pick_row.picked_qty, 0) - COALESCE(v_pick_row.dispatched_qty, 0))
      );
      IF v_take_qty <= 0 THEN
        CONTINUE;
      END IF;

      v_take_base_qty := v_take_qty * COALESCE(v_qty_per_unit, 1);

      SELECT *
      INTO v_item_batch_row
      FROM item_batch
      WHERE company_id = p_company_id
        AND item_id = v_dn_item.item_id
        AND warehouse_id = COALESCE(v_pick_row.source_warehouse_id, v_line_fulfilling_warehouse_id)
        AND batch_code = v_pick_row.picked_batch_code
        AND received_at = v_pick_row.picked_batch_received_at
        AND deleted_at IS NULL
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Picked batch not found for delivery note item % (batch %, receipt %)',
          v_dn_item.id, v_pick_row.picked_batch_code, v_pick_row.picked_batch_received_at;
      END IF;

      IF COALESCE(v_item_batch_row.qty_on_hand, 0) < v_take_base_qty THEN
        RAISE EXCEPTION 'Insufficient item_batch stock for delivery note item %', v_dn_item.id;
      END IF;

      SELECT *
      INTO v_item_location_batch_row
      FROM item_location_batch
      WHERE company_id = p_company_id
        AND item_id = v_dn_item.item_id
        AND warehouse_id = COALESCE(v_pick_row.source_warehouse_id, v_line_fulfilling_warehouse_id)
        AND location_id = v_pick_row.picked_location_id
        AND item_batch_id = v_item_batch_row.id
        AND deleted_at IS NULL
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Picked item_location_batch row not found for delivery note item %', v_dn_item.id;
      END IF;

      IF COALESCE(v_item_location_batch_row.qty_on_hand, 0) < v_take_base_qty THEN
        RAISE EXCEPTION 'Insufficient item_location_batch stock for delivery note item %', v_dn_item.id;
      END IF;

      SELECT *
      INTO v_item_location_row
      FROM item_location
      WHERE company_id = p_company_id
        AND item_id = v_dn_item.item_id
        AND warehouse_id = COALESCE(v_pick_row.source_warehouse_id, v_line_fulfilling_warehouse_id)
        AND location_id = v_pick_row.picked_location_id
        AND deleted_at IS NULL
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Picked item_location row not found for delivery note item %', v_dn_item.id;
      END IF;

      IF COALESCE(v_item_location_row.qty_on_hand, 0) < v_take_base_qty THEN
        RAISE EXCEPTION 'Insufficient item_location stock for delivery note item %', v_dn_item.id;
      END IF;

      UPDATE item_location_batch
      SET
        qty_on_hand = qty_on_hand - v_take_base_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_location_batch_row.id;

      UPDATE item_batch
      SET
        qty_on_hand = qty_on_hand - v_take_base_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_batch_row.id;

      UPDATE item_location
      SET
        qty_on_hand = qty_on_hand - v_take_base_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_location_row.id;

      UPDATE delivery_note_item_picks
      SET
        dispatched_qty = COALESCE(dispatched_qty, 0) + v_take_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_pick_row.id;

      v_remaining_dispatch_qty := v_remaining_dispatch_qty - v_take_qty;
    END LOOP;

    IF v_remaining_dispatch_qty > 0 THEN
      RAISE EXCEPTION 'Insufficient picked rows to dispatch delivery note item %', v_dn_item.id;
    END IF;

    v_next_stock := v_current_stock - v_dispatch_base_qty;

    UPDATE item_warehouse
    SET
      current_stock = v_next_stock,
      reserved_stock = GREATEST(0, COALESCE(reserved_stock, 0) - v_dispatch_base_qty),
      updated_by = p_user_id,
      updated_at = v_now
    WHERE id = v_warehouse_stock.id;

    INSERT INTO stock_transaction_items (
      company_id,
      transaction_id,
      item_id,
      quantity,
      uom_id,
      qty_before,
      qty_after,
      posting_date,
      posting_time,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_tx_id,
      v_dn_item.item_id,
      v_dispatch_base_qty,
      v_item_base_uom_id,
      v_current_stock,
      v_next_stock,
      v_posting_date,
      v_posting_time,
      COALESCE(NULLIF(BTRIM(p_notes), ''), 'Delivery note ' || v_dn.dn_no || ' dispatched'),
      p_user_id,
      p_user_id
    );

    UPDATE delivery_note_items
    SET
      dispatched_qty = COALESCE(dispatched_qty, 0) + v_dispatch_qty,
      updated_at = v_now
    WHERE id = v_dn_item.id;

    UPDATE stock_request_items
    SET
      dispatch_qty = COALESCE(dispatch_qty, 0) + v_dispatch_qty,
      updated_at = v_now
    WHERE id = v_dn_item.sr_item_id;
  END LOOP;

  IF NOT v_has_dispatch_line THEN
    RAISE EXCEPTION 'No picked quantities available for dispatch';
  END IF;

  UPDATE delivery_notes
  SET
    status = 'dispatched',
    dispatched_at = v_now,
    driver_name = COALESCE(NULLIF(BTRIM(p_driver_name), ''), driver_name),
    driver_signature = COALESCE(NULLIF(BTRIM(p_driver_signature), ''), driver_signature),
    notes = COALESCE(NULLIF(BTRIM(p_notes), ''), notes),
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.post_delivery_note_receive(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_business_unit_id UUID,
  p_received_date DATE,
  p_notes TEXT,
  p_items JSONB
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dn_item delivery_note_items%ROWTYPE;
  v_warehouse_stock item_warehouse%ROWTYPE;
  v_tx_id UUID;
  v_now TIMESTAMP;
  v_posting_date DATE;
  v_posting_time TIME;
  v_line JSONB;
  v_item_id UUID;
  v_received_qty NUMERIC;
  v_received_base_qty NUMERIC;
  v_max_receivable_qty NUMERIC;
  v_current_stock NUMERIC;
  v_next_stock NUMERIC;
  v_has_receive_line BOOLEAN := FALSE;
  v_target_location_id UUID;
  v_line_requesting_warehouse_id UUID;
  v_line_default_location_id UUID;
  v_remaining_receive_qty NUMERIC;
  v_take_qty NUMERIC;
  v_take_base_qty NUMERIC;
  v_pick_row RECORD;
  v_dest_item_batch item_batch%ROWTYPE;
  v_qty_per_unit NUMERIC := 1;
  v_item_base_uom_id UUID;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be received';
  END IF;

  IF p_business_unit_id IS NULL THEN
    RAISE EXCEPTION 'Business unit context required';
  END IF;

  v_now := NOW();
  v_posting_date := COALESCE(p_received_date, v_now::DATE);
  v_posting_time := v_now::TIME;

  FOR v_line IN
    SELECT value
    FROM jsonb_array_elements(COALESCE(p_items, '[]'::jsonb))
  LOOP
    v_item_id := NULLIF(v_line->>'deliveryNoteItemId', '')::UUID;
    IF v_item_id IS NULL THEN
      CONTINUE;
    END IF;

    v_received_qty := COALESCE((v_line->>'receivedQty')::NUMERIC, 0);

    SELECT *
    INTO v_dn_item
    FROM delivery_note_items
    WHERE id = v_item_id
      AND company_id = p_company_id
      AND dn_id = p_dn_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Invalid delivery note item %', v_item_id;
    END IF;

    SELECT
      COALESCE(iuo.qty_per_unit, 1),
      i.uom_id
    INTO
      v_qty_per_unit,
      v_item_base_uom_id
    FROM public.items i
    LEFT JOIN public.item_unit_options iuo
      ON iuo.id = v_dn_item.item_unit_option_id
     AND iuo.deleted_at IS NULL
    WHERE i.id = v_dn_item.item_id;

    SELECT COALESCE(SUM(GREATEST(0, COALESCE(dispatched_qty, 0) - COALESCE(received_qty, 0))), 0)
    INTO v_max_receivable_qty
    FROM delivery_note_item_picks
    WHERE company_id = p_company_id
      AND dn_id = p_dn_id
      AND delivery_note_item_id = v_dn_item.id
      AND deleted_at IS NULL;

    IF v_max_receivable_qty = 0 THEN
      v_max_receivable_qty := COALESCE(v_dn_item.dispatched_qty, 0);
    END IF;

    IF v_received_qty < 0 OR v_received_qty > v_max_receivable_qty THEN
      RAISE EXCEPTION 'Received quantity must be between 0 and %', v_max_receivable_qty;
    END IF;

    IF v_received_qty = 0 THEN
      CONTINUE;
    END IF;

    v_received_base_qty := v_received_qty * COALESCE(v_qty_per_unit, 1);

    v_line_requesting_warehouse_id := COALESCE(
      v_dn_item.requesting_warehouse_id,
      v_dn.requesting_warehouse_id
    );
    IF v_line_requesting_warehouse_id IS NULL THEN
      RAISE EXCEPTION 'Missing requesting warehouse for delivery note item %', v_item_id;
    END IF;

    INSERT INTO warehouse_locations (
      company_id,
      warehouse_id,
      code,
      name,
      location_type,
      is_pickable,
      is_storable,
      is_active,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_line_requesting_warehouse_id,
      'MAIN',
      'Main',
      'bin',
      TRUE,
      TRUE,
      TRUE,
      p_user_id,
      p_user_id
    )
    ON CONFLICT (company_id, warehouse_id, code) DO UPDATE
    SET updated_by = EXCLUDED.updated_by
    RETURNING id INTO v_line_default_location_id;

    v_target_location_id := COALESCE(NULLIF(v_line->>'locationId', '')::UUID, v_line_default_location_id);

    INSERT INTO stock_transactions (
      company_id,
      business_unit_id,
      transaction_type,
      transaction_date,
      warehouse_id,
      to_location_id,
      reference_type,
      reference_id,
      reference_code,
      status,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      p_business_unit_id,
      'in',
      v_posting_date,
      v_line_requesting_warehouse_id,
      v_target_location_id,
      'delivery_note',
      v_dn.id,
      v_dn.dn_no,
      'posted',
      COALESCE(NULLIF(BTRIM(p_notes), ''), 'Delivery note ' || v_dn.dn_no || ' received'),
      p_user_id,
      p_user_id
    )
    RETURNING id INTO v_tx_id;

    v_has_receive_line := TRUE;

    SELECT *
    INTO v_warehouse_stock
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_dn_item.item_id
      AND warehouse_id = v_line_requesting_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF FOUND THEN
      v_current_stock := COALESCE(v_warehouse_stock.current_stock, 0);
      v_next_stock := v_current_stock + v_received_base_qty;

      IF v_warehouse_stock.default_location_id IS NULL THEN
        UPDATE item_warehouse
        SET
          default_location_id = v_line_default_location_id,
          current_stock = v_next_stock,
          updated_by = p_user_id,
          updated_at = v_now
        WHERE id = v_warehouse_stock.id;
      ELSE
        UPDATE item_warehouse
        SET
          current_stock = v_next_stock,
          updated_by = p_user_id,
          updated_at = v_now
        WHERE id = v_warehouse_stock.id;
      END IF;
    ELSE
      v_current_stock := 0;
      v_next_stock := v_received_base_qty;

      INSERT INTO item_warehouse (
        company_id,
        item_id,
        warehouse_id,
        current_stock,
        default_location_id,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_dn_item.item_id,
        v_line_requesting_warehouse_id,
        v_next_stock,
        v_line_default_location_id,
        p_user_id,
        p_user_id
      );
    END IF;

    INSERT INTO item_location (
      company_id,
      item_id,
      warehouse_id,
      location_id,
      qty_on_hand,
      qty_reserved,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_dn_item.item_id,
      v_line_requesting_warehouse_id,
      v_target_location_id,
      v_received_base_qty,
      0,
      p_user_id,
      p_user_id
    )
    ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
    SET
      qty_on_hand = item_location.qty_on_hand + EXCLUDED.qty_on_hand,
      updated_by = EXCLUDED.updated_by,
      updated_at = v_now;

    v_remaining_receive_qty := v_received_qty;

    FOR v_pick_row IN
      SELECT *
      FROM delivery_note_item_picks
      WHERE company_id = p_company_id
        AND dn_id = p_dn_id
        AND delivery_note_item_id = v_dn_item.id
        AND deleted_at IS NULL
        AND COALESCE(dispatched_qty, 0) > COALESCE(received_qty, 0)
      ORDER BY created_at ASC, id ASC
      FOR UPDATE
    LOOP
      EXIT WHEN v_remaining_receive_qty <= 0;

      v_take_qty := LEAST(
        v_remaining_receive_qty,
        GREATEST(0, COALESCE(v_pick_row.dispatched_qty, 0) - COALESCE(v_pick_row.received_qty, 0))
      );
      IF v_take_qty <= 0 THEN
        CONTINUE;
      END IF;

      v_take_base_qty := v_take_qty * COALESCE(v_qty_per_unit, 1);

      SELECT *
      INTO v_dest_item_batch
      FROM item_batch
      WHERE company_id = p_company_id
        AND item_id = v_dn_item.item_id
        AND warehouse_id = v_line_requesting_warehouse_id
        AND batch_code = v_pick_row.picked_batch_code
        AND deleted_at IS NULL
      FOR UPDATE;

      IF FOUND THEN
        IF v_dest_item_batch.received_at <> v_pick_row.picked_batch_received_at THEN
          RAISE EXCEPTION 'Batch % receipt date mismatch on destination warehouse for item % (existing %, incoming %)',
            v_pick_row.picked_batch_code,
            v_dn_item.item_id,
            v_dest_item_batch.received_at,
            v_pick_row.picked_batch_received_at;
        END IF;

        UPDATE item_batch
        SET
          qty_on_hand = qty_on_hand + v_take_base_qty,
          updated_by = p_user_id,
          updated_at = v_now
        WHERE id = v_dest_item_batch.id;
      ELSE
        INSERT INTO item_batch (
          company_id,
          item_id,
          warehouse_id,
          batch_code,
          received_at,
          qty_on_hand,
          qty_reserved,
          created_by,
          updated_by
        )
        VALUES (
          p_company_id,
          v_dn_item.item_id,
          v_line_requesting_warehouse_id,
          v_pick_row.picked_batch_code,
          v_pick_row.picked_batch_received_at,
          v_take_base_qty,
          0,
          p_user_id,
          p_user_id
        )
        RETURNING * INTO v_dest_item_batch;
      END IF;

      INSERT INTO item_location_batch (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        item_batch_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_dn_item.item_id,
        v_line_requesting_warehouse_id,
        v_target_location_id,
        v_dest_item_batch.id,
        v_take_base_qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id, item_batch_id) DO UPDATE
      SET
        qty_on_hand = item_location_batch.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now;

      UPDATE delivery_note_item_picks
      SET
        received_qty = COALESCE(received_qty, 0) + v_take_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_pick_row.id;

      v_remaining_receive_qty := v_remaining_receive_qty - v_take_qty;
    END LOOP;

    IF v_remaining_receive_qty > 0 THEN
      RAISE EXCEPTION 'Insufficient dispatched pick rows to receive delivery note item %', v_dn_item.id;
    END IF;

    INSERT INTO stock_transaction_items (
      company_id,
      transaction_id,
      item_id,
      quantity,
      uom_id,
      unit_cost,
      total_cost,
      qty_before,
      qty_after,
      valuation_rate,
      stock_value_before,
      stock_value_after,
      posting_date,
      posting_time,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_tx_id,
      v_dn_item.item_id,
      v_received_base_qty,
      v_item_base_uom_id,
      0,
      0,
      v_current_stock,
      v_next_stock,
      0,
      0,
      0,
      v_posting_date,
      v_posting_time,
      COALESCE(NULLIF(BTRIM(p_notes), ''), 'Delivery note ' || v_dn.dn_no || ' received'),
      p_user_id,
      p_user_id
    );

    UPDATE stock_request_items
    SET
      received_qty = COALESCE(received_qty, 0) + v_received_qty,
      updated_at = v_now
    WHERE id = v_dn_item.sr_item_id;
  END LOOP;

  IF NOT v_has_receive_line THEN
    RAISE EXCEPTION 'No dispatched quantities available to receive';
  END IF;

  UPDATE delivery_notes
  SET
    status = 'received',
    received_at = v_now,
    notes = COALESCE(NULLIF(BTRIM(p_notes), ''), notes),
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.adjust_dispatched_delivery_note_item(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_delivery_note_item_id UUID,
  p_new_dispatched_qty NUMERIC,
  p_reason TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dni delivery_note_items%ROWTYPE;
  v_now TIMESTAMPTZ := NOW();
  v_reason TEXT := NULLIF(BTRIM(p_reason), '');
  v_current_dispatched NUMERIC;
  v_delta NUMERIC;
  v_delta_base_qty NUMERIC;
  v_pick_row RECORD;
  v_take_qty NUMERIC;
  v_take_base_qty NUMERIC;
  v_remaining_reversal NUMERIC;
  v_item_batch_row item_batch%ROWTYPE;
  v_item_location_batch_row item_location_batch%ROWTYPE;
  v_item_location_row item_location%ROWTYPE;
  v_warehouse_stock item_warehouse%ROWTYPE;
  v_tx_id UUID;
  v_current_stock NUMERIC;
  v_next_stock NUMERIC;
  v_new_allocated NUMERIC;
  v_new_picked NUMERIC;
  v_new_short NUMERIC;
  v_qty_per_unit NUMERIC := 1;
  v_item_base_uom_id UUID;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be adjusted';
  END IF;

  SELECT *
  INTO v_dni
  FROM delivery_note_items
  WHERE id = p_delivery_note_item_id
    AND company_id = p_company_id
    AND dn_id = p_dn_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note item not found';
  END IF;

  IF COALESCE(v_dni.is_voided, FALSE) THEN
    RAISE EXCEPTION 'Voided delivery note lines cannot be adjusted';
  END IF;

  SELECT
    COALESCE(iuo.qty_per_unit, 1),
    i.uom_id
  INTO
    v_qty_per_unit,
    v_item_base_uom_id
  FROM public.items i
  LEFT JOIN public.item_unit_options iuo
    ON iuo.id = v_dni.item_unit_option_id
   AND iuo.deleted_at IS NULL
  WHERE i.id = v_dni.item_id;

  IF p_new_dispatched_qty IS NULL THEN
    RAISE EXCEPTION 'New dispatched quantity is required';
  END IF;

  v_current_dispatched := COALESCE(v_dni.dispatched_qty, 0);
  IF p_new_dispatched_qty < 0 OR p_new_dispatched_qty > v_current_dispatched THEN
    RAISE EXCEPTION 'New dispatched quantity must be between 0 and %', v_current_dispatched;
  END IF;

  v_delta := v_current_dispatched - p_new_dispatched_qty;
  IF v_delta <= 0 THEN
    RAISE EXCEPTION 'Adjustment delta must be greater than zero';
  END IF;

  v_delta_base_qty := v_delta * COALESCE(v_qty_per_unit, 1);

  SELECT *
  INTO v_warehouse_stock
  FROM item_warehouse
  WHERE company_id = p_company_id
    AND item_id = v_dni.item_id
    AND warehouse_id = v_dni.fulfilling_warehouse_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Warehouse stock not found for item %', v_dni.item_id;
  END IF;

  v_current_stock := COALESCE(v_warehouse_stock.current_stock, 0);
  v_next_stock := v_current_stock + v_delta_base_qty;

  v_remaining_reversal := v_delta;

  FOR v_pick_row IN
    SELECT *
    FROM delivery_note_item_picks
    WHERE company_id = p_company_id
      AND dn_id = p_dn_id
      AND delivery_note_item_id = p_delivery_note_item_id
      AND deleted_at IS NULL
      AND COALESCE(dispatched_qty, 0) > COALESCE(reversed_qty, 0)
    ORDER BY created_at DESC, id DESC
    FOR UPDATE
  LOOP
    EXIT WHEN v_remaining_reversal <= 0;

    v_take_qty := LEAST(
      v_remaining_reversal,
      GREATEST(0, COALESCE(v_pick_row.dispatched_qty, 0) - COALESCE(v_pick_row.reversed_qty, 0))
    );

    IF v_take_qty <= 0 THEN
      CONTINUE;
    END IF;

    v_take_base_qty := v_take_qty * COALESCE(v_qty_per_unit, 1);

    SELECT *
    INTO v_item_batch_row
    FROM item_batch
    WHERE company_id = p_company_id
      AND item_id = v_dni.item_id
      AND warehouse_id = COALESCE(v_pick_row.source_warehouse_id, v_dni.fulfilling_warehouse_id)
      AND batch_code = v_pick_row.picked_batch_code
      AND received_at = v_pick_row.picked_batch_received_at
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Item batch not found for reversal';
    END IF;

    SELECT *
    INTO v_item_location_batch_row
    FROM item_location_batch
    WHERE company_id = p_company_id
      AND item_id = v_dni.item_id
      AND warehouse_id = COALESCE(v_pick_row.source_warehouse_id, v_dni.fulfilling_warehouse_id)
      AND location_id = v_pick_row.picked_location_id
      AND item_batch_id = v_item_batch_row.id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Item location batch not found for reversal';
    END IF;

    SELECT *
    INTO v_item_location_row
    FROM item_location
    WHERE company_id = p_company_id
      AND item_id = v_dni.item_id
      AND warehouse_id = COALESCE(v_pick_row.source_warehouse_id, v_dni.fulfilling_warehouse_id)
      AND location_id = v_pick_row.picked_location_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Item location not found for reversal';
    END IF;

    UPDATE item_location_batch
    SET
      qty_on_hand = COALESCE(qty_on_hand, 0) + v_take_base_qty,
      updated_by = p_user_id,
      updated_at = v_now
    WHERE id = v_item_location_batch_row.id;

    UPDATE item_batch
    SET
      qty_on_hand = COALESCE(qty_on_hand, 0) + v_take_base_qty,
      updated_by = p_user_id,
      updated_at = v_now
    WHERE id = v_item_batch_row.id;

    UPDATE item_location
    SET
      qty_on_hand = COALESCE(qty_on_hand, 0) + v_take_base_qty,
      updated_by = p_user_id,
      updated_at = v_now
    WHERE id = v_item_location_row.id;

    UPDATE delivery_note_item_picks
    SET
      reversed_qty = COALESCE(reversed_qty, 0) + v_take_qty,
      updated_by = p_user_id,
      updated_at = v_now
    WHERE id = v_pick_row.id;

    v_remaining_reversal := v_remaining_reversal - v_take_qty;
  END LOOP;

  IF v_remaining_reversal > 0 THEN
    RAISE EXCEPTION 'Insufficient dispatched pick rows to reverse delivery note item %', p_delivery_note_item_id;
  END IF;

  INSERT INTO stock_transactions (
    company_id,
    business_unit_id,
    transaction_type,
    transaction_date,
    warehouse_id,
    reference_type,
    reference_id,
    reference_code,
    status,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_dn.business_unit_id,
    'adjustment',
    v_now::DATE,
    v_dni.fulfilling_warehouse_id,
    'delivery_note_adjustment',
    v_dn.id,
    v_dn.dn_no,
    'posted',
    COALESCE(v_reason, 'Delivery note line quantity reduced after dispatch'),
    p_user_id,
    p_user_id
  )
  RETURNING id INTO v_tx_id;

  UPDATE item_warehouse
  SET
    current_stock = v_next_stock,
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = v_warehouse_stock.id;

  INSERT INTO stock_transaction_items (
    company_id,
    transaction_id,
    item_id,
    quantity,
    uom_id,
    qty_before,
    qty_after,
    posting_date,
    posting_time,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_tx_id,
    v_dni.item_id,
    v_delta_base_qty,
    v_item_base_uom_id,
    v_current_stock,
    v_next_stock,
    v_now::DATE,
    v_now::TIME,
    COALESCE(v_reason, 'Delivery note line quantity reduced after dispatch'),
    p_user_id,
    p_user_id
  );

  v_new_allocated := GREATEST(0, COALESCE(v_dni.allocated_qty, 0) - v_delta);
  v_new_picked := GREATEST(0, COALESCE(v_dni.picked_qty, 0) - v_delta);
  v_new_short := GREATEST(0, v_new_allocated - v_new_picked);

  UPDATE delivery_note_items
  SET
    allocated_qty = v_new_allocated,
    picked_qty = v_new_picked,
    short_qty = v_new_short,
    dispatched_qty = p_new_dispatched_qty,
    is_voided = (p_new_dispatched_qty = 0),
    voided_at = CASE WHEN p_new_dispatched_qty = 0 THEN v_now ELSE NULL END,
    voided_by = CASE WHEN p_new_dispatched_qty = 0 THEN p_user_id ELSE NULL END,
    void_reason = CASE WHEN p_new_dispatched_qty = 0 THEN v_reason ELSE NULL END,
    updated_at = v_now
  WHERE id = p_delivery_note_item_id
    AND company_id = p_company_id;

  UPDATE stock_request_items
  SET
    dispatch_qty = GREATEST(0, COALESCE(dispatch_qty, 0) - v_delta),
    updated_at = v_now
  WHERE id = v_dni.sr_item_id;

  INSERT INTO delivery_note_item_adjustments (
    company_id,
    dn_id,
    delivery_note_item_id,
    adjustment_type,
    qty_delta,
    prior_dispatched_qty,
    new_dispatched_qty,
    reason,
    created_at,
    created_by
  )
  VALUES (
    p_company_id,
    p_dn_id,
    p_delivery_note_item_id,
    CASE WHEN p_new_dispatched_qty = 0 THEN 'void_qty' ELSE 'reduce_qty' END,
    v_delta,
    v_current_dispatched,
    p_new_dispatched_qty,
    v_reason,
    v_now,
    p_user_id
  );
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260405193000_add_stock_requisition_item_unit_option_id.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add unit option support to stock requisition items
-- Version: 20260405193000
-- Description: Persists the exact selected item unit option on purchasing
--              stock requisition lines while keeping uom_id for compatibility.
-- Date: 2026-04-05
-- ============================================================================

BEGIN;

ALTER TABLE public.stock_requisition_items
  ADD COLUMN IF NOT EXISTS uom_id UUID REFERENCES public.units_of_measure(id) ON DELETE RESTRICT,
  ADD COLUMN IF NOT EXISTS item_unit_option_id UUID
    REFERENCES public.item_unit_options(id) ON DELETE RESTRICT;

COMMENT ON COLUMN public.stock_requisition_items.uom_id IS
  'Selected unit of measure for the requisition line.';

COMMENT ON COLUMN public.stock_requisition_items.item_unit_option_id IS
  'Selected item-specific unit option for the requisition line.';

CREATE INDEX IF NOT EXISTS idx_stock_requisition_items_uom_id
  ON public.stock_requisition_items(uom_id)
  WHERE uom_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_stock_requisition_items_item_unit_option_id
  ON public.stock_requisition_items(item_unit_option_id)
  WHERE item_unit_option_id IS NOT NULL;

UPDATE public.stock_requisition_items sri
SET uom_id = i.uom_id
FROM public.items i
WHERE sri.item_id = i.id
  AND sri.uom_id IS NULL;

WITH matched_options AS (
  SELECT DISTINCT ON (sri.id)
    sri.id AS requisition_item_id,
    iuo.id AS item_unit_option_id
  FROM public.stock_requisition_items sri
  JOIN public.item_unit_options iuo
    ON iuo.item_id = sri.item_id
   AND iuo.uom_id = sri.uom_id
   AND iuo.is_active = TRUE
   AND iuo.deleted_at IS NULL
  WHERE sri.item_unit_option_id IS NULL
  ORDER BY sri.id, iuo.is_base DESC, iuo.is_default DESC, iuo.sort_order ASC, iuo.created_at ASC
)
UPDATE public.stock_requisition_items sri
SET item_unit_option_id = matched_options.item_unit_option_id
FROM matched_options
WHERE matched_options.requisition_item_id = sri.id;

ALTER TABLE public.stock_requisition_items
  ALTER COLUMN uom_id SET NOT NULL;

CREATE OR REPLACE FUNCTION public.validate_stock_requisition_item_unit_option()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
DECLARE
  v_option_item_id UUID;
  v_option_uom_id UUID;
  v_option_is_active BOOLEAN;
  v_option_deleted_at TIMESTAMPTZ;
BEGIN
  IF NEW.item_unit_option_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT item_id, uom_id, is_active, deleted_at
    INTO v_option_item_id, v_option_uom_id, v_option_is_active, v_option_deleted_at
  FROM public.item_unit_options
  WHERE id = NEW.item_unit_option_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Item unit option % does not exist', NEW.item_unit_option_id;
  END IF;

  IF v_option_deleted_at IS NOT NULL THEN
    RAISE EXCEPTION 'Item unit option % has been deleted', NEW.item_unit_option_id;
  END IF;

  IF NOT v_option_is_active THEN
    RAISE EXCEPTION 'Item unit option % is inactive', NEW.item_unit_option_id;
  END IF;

  IF NEW.item_id IS DISTINCT FROM v_option_item_id THEN
    RAISE EXCEPTION 'Item unit option % does not belong to item %', NEW.item_unit_option_id, NEW.item_id;
  END IF;

  IF NEW.uom_id IS DISTINCT FROM v_option_uom_id THEN
    RAISE EXCEPTION 'Item unit option % does not match unit of measure %', NEW.item_unit_option_id, NEW.uom_id;
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_stock_requisition_items_validate_unit_option ON public.stock_requisition_items;
CREATE TRIGGER trg_stock_requisition_items_validate_unit_option
  BEFORE INSERT OR UPDATE ON public.stock_requisition_items
  FOR EACH ROW
  EXECUTE FUNCTION public.validate_stock_requisition_item_unit_option();

COMMIT;


-- ============================================================================
-- Migration: 20260406093000_add_load_list_item_unit_option_id.sql
-- ============================================================================

ALTER TABLE public.load_list_items
ADD COLUMN uom_id uuid REFERENCES public.units_of_measure(id) ON DELETE RESTRICT,
ADD COLUMN item_unit_option_id uuid REFERENCES public.item_unit_options(id) ON DELETE RESTRICT;

UPDATE public.load_list_items lli
SET uom_id = i.uom_id
FROM public.items i
WHERE i.id = lli.item_id
  AND lli.uom_id IS NULL;

UPDATE public.load_list_items lli
SET item_unit_option_id = matched.id
FROM (
  SELECT DISTINCT ON (lli_inner.id)
    lli_inner.id AS load_list_item_id,
    iuo.id
  FROM public.load_list_items lli_inner
  JOIN public.item_unit_options iuo
    ON iuo.item_id = lli_inner.item_id
   AND iuo.uom_id = lli_inner.uom_id
   AND iuo.is_active = true
   AND iuo.deleted_at IS NULL
  ORDER BY
    lli_inner.id,
    iuo.is_base DESC,
    iuo.is_default DESC,
    iuo.sort_order ASC,
    iuo.created_at ASC
) AS matched
WHERE matched.load_list_item_id = lli.id
  AND lli.item_unit_option_id IS NULL;

ALTER TABLE public.load_list_items
ALTER COLUMN uom_id SET NOT NULL;

CREATE INDEX idx_load_list_items_uom_id ON public.load_list_items(uom_id);
CREATE INDEX idx_load_list_items_item_unit_option_id ON public.load_list_items(item_unit_option_id);

CREATE OR REPLACE FUNCTION public.validate_load_list_item_unit_option()
RETURNS trigger
LANGUAGE plpgsql
AS $$
DECLARE
  option_item_id uuid;
  option_uom_id uuid;
BEGIN
  IF NEW.item_unit_option_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT item_id, uom_id
  INTO option_item_id, option_uom_id
  FROM public.item_unit_options
  WHERE id = NEW.item_unit_option_id
    AND deleted_at IS NULL
    AND is_active = true;

  IF option_item_id IS NULL THEN
    RAISE EXCEPTION 'Selected item unit option is invalid or inactive';
  END IF;

  IF option_item_id <> NEW.item_id THEN
    RAISE EXCEPTION 'Selected item unit option does not belong to the item';
  END IF;

  IF option_uom_id <> NEW.uom_id THEN
    RAISE EXCEPTION 'Selected item unit option does not match the unit';
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_validate_load_list_item_unit_option ON public.load_list_items;

CREATE TRIGGER trg_validate_load_list_item_unit_option
BEFORE INSERT OR UPDATE ON public.load_list_items
FOR EACH ROW
EXECUTE FUNCTION public.validate_load_list_item_unit_option();


-- ============================================================================
-- Migration: 20260406113000_add_grn_item_load_list_item_and_unit_option.sql
-- ============================================================================

ALTER TABLE public.grn_items
ADD COLUMN load_list_item_id UUID REFERENCES public.load_list_items(id) ON DELETE SET NULL,
ADD COLUMN item_unit_option_id UUID REFERENCES public.item_unit_options(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_grn_items_load_list_item_id
  ON public.grn_items(load_list_item_id);

CREATE INDEX IF NOT EXISTS idx_grn_items_item_unit_option_id
  ON public.grn_items(item_unit_option_id);

WITH matched AS (
  SELECT DISTINCT ON (gi.id)
    gi.id AS grn_item_id,
    lli.id AS load_list_item_id,
    lli.item_unit_option_id
  FROM public.grn_items gi
  JOIN public.grns g
    ON g.id = gi.grn_id
  JOIN public.load_list_items lli
    ON lli.load_list_id = g.load_list_id
   AND lli.item_id = gi.item_id
   AND lli.load_list_qty = gi.load_list_qty
  WHERE gi.load_list_item_id IS NULL
  ORDER BY gi.id, lli.id
)
UPDATE public.grn_items gi
SET
  load_list_item_id = matched.load_list_item_id,
  item_unit_option_id = matched.item_unit_option_id
FROM matched
WHERE matched.grn_item_id = gi.id;

CREATE OR REPLACE FUNCTION public.validate_grn_item_source_link()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
DECLARE
  v_grn_load_list_id UUID;
  v_load_list_item RECORD;
BEGIN
  IF NEW.load_list_item_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT load_list_id
  INTO v_grn_load_list_id
  FROM public.grns
  WHERE id = NEW.grn_id;

  IF v_grn_load_list_id IS NULL THEN
    RAISE EXCEPTION 'GRN % not found for GRN item validation', NEW.grn_id;
  END IF;

  SELECT id, item_id, item_unit_option_id, load_list_qty
  INTO v_load_list_item
  FROM public.load_list_items
  WHERE id = NEW.load_list_item_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Load list item % not found', NEW.load_list_item_id;
  END IF;

  IF v_load_list_item.item_id IS DISTINCT FROM NEW.item_id THEN
    RAISE EXCEPTION 'GRN item % item_id does not match load list item %', NEW.id, NEW.load_list_item_id;
  END IF;

  IF v_grn_load_list_id IS DISTINCT FROM (
    SELECT load_list_id FROM public.load_list_items WHERE id = NEW.load_list_item_id
  ) THEN
    RAISE EXCEPTION 'Load list item % does not belong to GRN load list %', NEW.load_list_item_id, v_grn_load_list_id;
  END IF;

  IF NEW.item_unit_option_id IS NOT NULL
     AND v_load_list_item.item_unit_option_id IS DISTINCT FROM NEW.item_unit_option_id THEN
    RAISE EXCEPTION 'GRN item % unit option does not match load list item %', NEW.id, NEW.load_list_item_id;
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS validate_grn_item_source_link_trigger ON public.grn_items;

CREATE TRIGGER validate_grn_item_source_link_trigger
BEFORE INSERT OR UPDATE ON public.grn_items
FOR EACH ROW
EXECUTE FUNCTION public.validate_grn_item_source_link();


-- ============================================================================
-- Migration: 20260406130000_fix_grn_approve_in_transit_full_load_qty.sql
-- ============================================================================

CREATE OR REPLACE FUNCTION public.approve_grn_with_batch_inventory(
  p_company_id UUID,
  p_user_id UUID,
  p_grn_id UUID,
  p_notes TEXT DEFAULT NULL
)
RETURNS TEXT
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_grn grns%ROWTYPE;
  v_grn_item grn_items%ROWTYPE;
  v_item_uom_id UUID;
  v_now TIMESTAMP := NOW();
  v_tx_id UUID;
  v_tx_code TEXT;
  v_posting_date DATE;
  v_posting_time TIME;
  v_default_location_id UUID;
  v_generated_batch_code TEXT;
  v_batch_code TEXT;
  v_item_wh item_warehouse%ROWTYPE;
  v_item_batch item_batch%ROWTYPE;
  v_item_loc item_location%ROWTYPE;
  v_item_loc_batch item_location_batch%ROWTYPE;
  v_received_qty NUMERIC;
  v_received_base_qty NUMERIC;
  v_expected_base_qty NUMERIC;
  v_damaged_qty NUMERIC;
  v_qty_per_unit NUMERIC;
  v_batch_received_at TIMESTAMP;
  v_boxes_total_qty NUMERIC;
  v_remainder_qty NUMERIC;
  v_has_items BOOLEAN := FALSE;
  v_line_location RECORD;
  v_item_wh_current_stock NUMERIC;
  v_item_wh_reserved_stock NUMERIC;
  v_item_wh_next_stock NUMERIC;
BEGIN
  SELECT *
  INTO v_grn
  FROM grns
  WHERE id = p_grn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'GRN not found';
  END IF;

  IF v_grn.status <> 'pending_approval' THEN
    RAISE EXCEPTION 'Only GRNs in pending approval can be approved';
  END IF;

  v_posting_date := COALESCE(v_grn.receiving_date, CURRENT_DATE);
  v_posting_time := v_now::TIME;
  v_batch_received_at := v_posting_date::TIMESTAMP + v_posting_time;

  INSERT INTO warehouse_locations (
    company_id,
    warehouse_id,
    code,
    name,
    location_type,
    is_pickable,
    is_storable,
    is_active,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_grn.warehouse_id,
    'MAIN',
    'Main',
    'bin',
    TRUE,
    TRUE,
    TRUE,
    p_user_id,
    p_user_id
  )
  ON CONFLICT (company_id, warehouse_id, code) DO UPDATE
  SET updated_by = EXCLUDED.updated_by
  RETURNING id INTO v_default_location_id;

  INSERT INTO stock_transactions (
    company_id,
    business_unit_id,
    transaction_type,
    transaction_date,
    warehouse_id,
    to_location_id,
    reference_type,
    reference_id,
    status,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_grn.business_unit_id,
    'in',
    v_posting_date,
    v_grn.warehouse_id,
    v_default_location_id,
    'grn',
    v_grn.id,
    'posted',
    COALESCE(NULLIF(BTRIM(p_notes), ''), 'Auto-created from GRN ' || v_grn.grn_number),
    p_user_id,
    p_user_id
  )
  RETURNING id, transaction_code INTO v_tx_id, v_tx_code;

  FOR v_grn_item IN
    SELECT gi.*
    FROM grn_items gi
    WHERE gi.grn_id = v_grn.id
    ORDER BY gi.created_at ASC, gi.id ASC
    FOR UPDATE
  LOOP
    v_has_items := TRUE;
    v_received_qty := COALESCE(v_grn_item.received_qty, 0);
    v_damaged_qty := COALESCE(v_grn_item.damaged_qty, 0);

    SELECT COALESCE(iuo.qty_per_unit, 1)
    INTO v_qty_per_unit
    FROM item_unit_options iuo
    WHERE iuo.id = v_grn_item.item_unit_option_id;

    v_qty_per_unit := COALESCE(v_qty_per_unit, 1);
    v_expected_base_qty := COALESCE(v_grn_item.load_list_qty, 0) * v_qty_per_unit;
    v_received_base_qty := v_received_qty * v_qty_per_unit;

    IF v_received_qty <= 0 THEN
      UPDATE item_warehouse
      SET
        in_transit = GREATEST(0, COALESCE(in_transit, 0) - v_expected_base_qty),
        estimated_arrival_date = CASE
          WHEN GREATEST(0, COALESCE(in_transit, 0) - v_expected_base_qty) > 0 THEN estimated_arrival_date
          ELSE NULL
        END,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE company_id = p_company_id
        AND item_id = v_grn_item.item_id
        AND warehouse_id = v_grn.warehouse_id
        AND deleted_at IS NULL;

      CONTINUE;
    END IF;

    SELECT i.uom_id
    INTO v_item_uom_id
    FROM items i
    WHERE i.id = v_grn_item.item_id;

    IF v_item_uom_id IS NULL THEN
      RAISE EXCEPTION 'Item UOM not found for item %', v_grn_item.item_id;
    END IF;

    v_generated_batch_code := COALESCE(
      NULLIF(BTRIM(v_grn.batch_number), ''),
      'GRN-' || v_grn.grn_number || '-' || SUBSTRING(REPLACE(v_grn_item.id::TEXT, '-', ''), 1, 8)
    );
    v_batch_code := v_generated_batch_code;

    PERFORM 1
    FROM item_batch ib_dup
    WHERE ib_dup.company_id = p_company_id
      AND ib_dup.item_id = v_grn_item.item_id
      AND ib_dup.warehouse_id = v_grn.warehouse_id
      AND ib_dup.batch_code = v_batch_code
      AND ib_dup.deleted_at IS NULL;

    IF FOUND THEN
      RAISE EXCEPTION 'Duplicate batch code % for item % in warehouse %',
        v_batch_code, v_grn_item.item_id, v_grn.warehouse_id;
    END IF;

    SELECT *
    INTO v_item_wh
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_grn_item.item_id
      AND warehouse_id = v_grn.warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF FOUND THEN
      v_item_wh_current_stock := COALESCE(v_item_wh.current_stock, 0);
      v_item_wh_reserved_stock := COALESCE(v_item_wh.reserved_stock, 0);
      v_item_wh_next_stock := v_item_wh_current_stock + v_received_base_qty;

      UPDATE item_warehouse
      SET
        current_stock = v_item_wh_next_stock,
        in_transit = GREATEST(0, COALESCE(in_transit, 0) - v_expected_base_qty),
        estimated_arrival_date = CASE
          WHEN GREATEST(0, COALESCE(in_transit, 0) - v_expected_base_qty) > 0 THEN estimated_arrival_date
          ELSE NULL
        END,
        default_location_id = COALESCE(default_location_id, v_default_location_id),
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_wh.id;
    ELSE
      v_item_wh_current_stock := 0;
      v_item_wh_reserved_stock := 0;
      v_item_wh_next_stock := v_received_base_qty;

      INSERT INTO item_warehouse (
        company_id,
        item_id,
        warehouse_id,
        current_stock,
        reserved_stock,
        in_transit,
        estimated_arrival_date,
        default_location_id,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        v_item_wh_next_stock,
        0,
        0,
        NULL,
        v_default_location_id,
        p_user_id,
        p_user_id
      );
    END IF;

    INSERT INTO item_batch (
      company_id,
      item_id,
      warehouse_id,
      batch_code,
      received_at,
      qty_on_hand,
      qty_reserved,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_grn_item.item_id,
      v_grn.warehouse_id,
      v_batch_code,
      v_batch_received_at,
      v_received_base_qty,
      0,
      p_user_id,
      p_user_id
    )
    RETURNING * INTO v_item_batch;

    v_boxes_total_qty := 0;

    FOR v_line_location IN
      SELECT
        gb.warehouse_location_id AS location_id,
        MIN(NULLIF(BTRIM(gb.batch_location_sku), '')) AS batch_location_sku,
        SUM(COALESCE(gb.qty_per_box, 0))::NUMERIC AS qty
      FROM grn_boxes gb
      WHERE gb.grn_item_id = v_grn_item.id
        AND gb.warehouse_location_id IS NOT NULL
      GROUP BY gb.warehouse_location_id
      ORDER BY gb.warehouse_location_id
    LOOP
      EXIT WHEN v_line_location.qty IS NULL OR v_line_location.qty <= 0;
      v_boxes_total_qty := v_boxes_total_qty + COALESCE(v_line_location.qty, 0);

      INSERT INTO item_location (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        v_line_location.location_id,
        v_line_location.qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
      SET
        qty_on_hand = item_location.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now
      RETURNING * INTO v_item_loc;

      INSERT INTO item_location_batch (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        item_batch_id,
        batch_location_sku,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        v_line_location.location_id,
        v_item_batch.id,
        NULLIF(BTRIM(v_line_location.batch_location_sku::TEXT), ''),
        v_line_location.qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id, item_batch_id) DO UPDATE
      SET
        qty_on_hand = item_location_batch.qty_on_hand + EXCLUDED.qty_on_hand,
        batch_location_sku = COALESCE(item_location_batch.batch_location_sku, EXCLUDED.batch_location_sku),
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now
      RETURNING * INTO v_item_loc_batch;

      UPDATE grn_boxes
      SET
        batch_location_sku = v_item_loc_batch.batch_location_sku
      WHERE grn_item_id = v_grn_item.id
        AND warehouse_location_id = v_line_location.location_id;
    END LOOP;

    v_remainder_qty := GREATEST(0, v_received_base_qty - COALESCE(v_boxes_total_qty, 0));
    IF v_remainder_qty > 0 THEN
      INSERT INTO item_location (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        COALESCE(v_item_wh.default_location_id, v_default_location_id),
        v_remainder_qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
      SET
        qty_on_hand = item_location.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now;

      INSERT INTO item_location_batch (
        company_id,
        item_id,
        warehouse_id,
        location_id,
        item_batch_id,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_grn_item.item_id,
        v_grn.warehouse_id,
        COALESCE(v_item_wh.default_location_id, v_default_location_id),
        v_item_batch.id,
        v_remainder_qty,
        0,
        p_user_id,
        p_user_id
      )
      ON CONFLICT (company_id, item_id, warehouse_id, location_id, item_batch_id) DO UPDATE
      SET
        qty_on_hand = item_location_batch.qty_on_hand + EXCLUDED.qty_on_hand,
        updated_by = EXCLUDED.updated_by,
        updated_at = v_now;
    END IF;

    INSERT INTO stock_transaction_items (
      company_id,
      transaction_id,
      item_id,
      quantity,
      uom_id,
      batch_no,
      qty_before,
      qty_after,
      posting_date,
      posting_time,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_tx_id,
      v_grn_item.item_id,
      v_received_base_qty,
      v_item_uom_id,
      v_batch_code,
      v_item_wh_current_stock,
      v_item_wh_next_stock,
      v_posting_date,
      v_posting_time,
      CASE
        WHEN v_damaged_qty > 0 THEN 'GRN ' || v_grn.grn_number || ' (Damaged: ' || v_damaged_qty || ')'
        ELSE 'GRN ' || v_grn.grn_number
      END,
      p_user_id,
      p_user_id
    );
  END LOOP;

  IF NOT v_has_items THEN
    RAISE EXCEPTION 'GRN has no items';
  END IF;

  UPDATE grns
  SET
    status = 'approved',
    checked_by = p_user_id,
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = v_grn.id;

  UPDATE load_lists
  SET
    status = 'received',
    updated_by = p_user_id,
    updated_at = v_now
  WHERE id = v_grn.load_list_id;

  RETURN v_tx_code;
END;
$$;


