  p_sales_order_id UUID
)
RETURNS TABLE (
  manufacturing_order_id UUID,
  manufacturing_order_code TEXT
)
LANGUAGE plpgsql
SET search_path = public
AS $$
BEGIN
  RAISE EXCEPTION 'Manufacturing orders must be pushed from job orders';
END;
