-- Migration: 20260421114500_drop_duplicate_load_list_code_trigger.sql
-- ============================================================================

DROP TRIGGER IF EXISTS trigger_generate_load_list_number ON public.load_lists;


-- ============================================================================
-- Migration: 20260423093000_add_skip_inventory_to_sales_lines.sql
-- ============================================================================

ALTER TABLE public.sales_order_items
  ADD COLUMN IF NOT EXISTS skip_inventory BOOLEAN NOT NULL DEFAULT FALSE;

ALTER TABLE public.sales_invoice_items
  ADD COLUMN IF NOT EXISTS skip_inventory BOOLEAN NOT NULL DEFAULT FALSE;

COMMENT ON COLUMN public.sales_order_items.skip_inventory IS
  'When true, this sales order line is invoiced financially but must not trigger invoice stock validation or stock deduction.';

COMMENT ON COLUMN public.sales_invoice_items.skip_inventory IS
  'Copied from the source sales line. When true, this invoice line does not represent invoice-driven stock deduction.';

UPDATE public.sales_order_items soi
SET skip_inventory = TRUE
WHERE EXISTS (
  SELECT 1
  FROM public.sales_order_item_configurations cfg
  WHERE cfg.order_item_id = soi.id
    AND cfg.deleted_at IS NULL
)
  AND soi.deleted_at IS NULL;

CREATE OR REPLACE FUNCTION public.create_sales_order_transaction(
  p_quotation_id UUID,
  p_business_unit_id UUID
)
RETURNS TABLE (
  sales_order_id UUID,
  order_code TEXT
)
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_quotation RECORD;
  v_quote_item RECORD;
  v_configuration RECORD;
  v_sales_order_id UUID;
  v_order_item_id UUID;
  v_order_configuration_id UUID;
  v_order_code TEXT;
  v_item_count INTEGER;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF p_business_unit_id IS NULL THEN
    RAISE EXCEPTION 'Business unit context required';
  END IF;

  SELECT *
  INTO v_quotation
  FROM public.sales_quotations
  WHERE id = p_quotation_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_quotation.id IS NULL THEN
    RAISE EXCEPTION 'Quotation not found';
  END IF;

  IF v_quotation.status <> 'accepted' THEN
    RAISE EXCEPTION 'Only accepted quotations can be converted to sales orders';
  END IF;

  IF v_quotation.sales_order_id IS NOT NULL THEN
    RAISE EXCEPTION 'This quotation has already been converted to a sales order';
  END IF;

  SELECT COUNT(*) INTO v_item_count
  FROM public.sales_quotation_items
  WHERE quotation_id = p_quotation_id
    AND deleted_at IS NULL;

  IF v_item_count = 0 THEN
    RAISE EXCEPTION 'Quotation must have at least one item';
  END IF;

  INSERT INTO public.sales_orders (
    company_id,
    business_unit_id,
    customer_id,
    quotation_id,
    order_date,
    expected_delivery_date,
    status,
    subtotal,
    discount_amount,
    tax_amount,
    total_amount,
    payment_terms,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    v_quotation.company_id,
    p_business_unit_id,
    v_quotation.customer_id,
    p_quotation_id,
    CURRENT_DATE,
    COALESCE(v_quotation.valid_until, CURRENT_DATE + 14),
    'confirmed',
    v_quotation.subtotal,
    v_quotation.discount_amount,
    v_quotation.tax_amount,
    v_quotation.total_amount,
    COALESCE(v_quotation.terms_conditions, 'Payment due within 30 days'),
    COALESCE(v_quotation.notes, ''),
    v_user_id,
    v_user_id
  )
  RETURNING id, sales_orders.order_code INTO v_sales_order_id, v_order_code;

  FOR v_quote_item IN
    SELECT *
    FROM public.sales_quotation_items
    WHERE quotation_id = p_quotation_id
      AND deleted_at IS NULL
    ORDER BY sort_order ASC NULLS LAST, created_at ASC
  LOOP
    INSERT INTO public.sales_order_items (
      company_id,
      order_id,
      item_id,
      item_description,
      quantity,
      uom_id,
      rate,
      discount_percent,
      discount_amount,
      tax_percent,
      tax_amount,
      line_total,
      quantity_shipped,
      quantity_delivered,
      sort_order,
      notes,
      created_by,
      updated_by,
      skip_inventory
    )
    VALUES (
      v_quote_item.company_id,
      v_sales_order_id,
      v_quote_item.item_id,
      v_quote_item.item_description,
      v_quote_item.quantity,
      v_quote_item.uom_id,
      v_quote_item.rate,
      COALESCE(v_quote_item.discount_percent, 0),
      COALESCE(v_quote_item.discount_amount, 0),
      COALESCE(v_quote_item.tax_percent, 0),
      COALESCE(v_quote_item.tax_amount, 0),
      v_quote_item.line_total,
      0,
      0,
      v_quote_item.sort_order,
      v_quote_item.notes,
      v_user_id,
      v_user_id,
      FALSE
    )
    RETURNING id INTO v_order_item_id;

    SELECT *
    INTO v_configuration
    FROM public.sales_quotation_item_configurations
    WHERE quotation_item_id = v_quote_item.id
      AND deleted_at IS NULL;

    IF v_configuration.id IS NOT NULL THEN
      UPDATE public.sales_order_items
      SET skip_inventory = TRUE,
          updated_by = v_user_id,
          updated_at = CURRENT_TIMESTAMP
      WHERE id = v_order_item_id;

      INSERT INTO public.sales_order_item_configurations (
        company_id,
        order_item_id,
        quotation_configuration_id,
        width,
        height,
        fixed_allowance,
        molding_item_id,
        molding_stick_length,
        molding_sticks_required,
        service_fee_mode,
        service_type,
        service_fee_amount,
        total_service_fee,
        invoice_display_mode,
        created_by,
        updated_by
      )
      VALUES (
        v_configuration.company_id,
        v_order_item_id,
        v_configuration.id,
        v_configuration.width,
        v_configuration.height,
        v_configuration.fixed_allowance,
        v_configuration.molding_item_id,
        v_configuration.molding_stick_length,
        v_configuration.molding_sticks_required,
        v_configuration.service_fee_mode,
        v_configuration.service_type,
        v_configuration.service_fee_amount,
        v_configuration.total_service_fee,
        v_configuration.invoice_display_mode,
        v_user_id,
        v_user_id
      )
      RETURNING id INTO v_order_configuration_id;

      INSERT INTO public.sales_order_item_components (
        company_id,
        order_item_id,
        configuration_id,
        quotation_component_id,
        component_type,
        source,
        item_id,
        description,
        qty_per_frame,
        total_quantity,
        uom_id,
        unit_rate,
        total_amount,
        rounding_mode,
        sort_order,
        created_by,
        updated_by
      )
      SELECT
        company_id,
        v_order_item_id,
        v_order_configuration_id,
        id,
        component_type,
        source,
        item_id,
        description,
        qty_per_frame,
        total_quantity,
        uom_id,
        unit_rate,
        total_amount,
        rounding_mode,
        sort_order,
        v_user_id,
        v_user_id
      FROM public.sales_quotation_item_components
      WHERE quotation_item_id = v_quote_item.id
        AND deleted_at IS NULL
      ORDER BY sort_order ASC NULLS LAST, created_at ASC;
    END IF;
  END LOOP;

  UPDATE public.sales_quotations
  SET
    status = 'ordered',
    sales_order_id = v_sales_order_id,
    updated_by = v_user_id
  WHERE id = p_quotation_id;

  sales_order_id := v_sales_order_id;
  order_code := v_order_code;
  RETURN NEXT;
END;
$$;


-- ============================================================================
-- Migration: 20260423110000_require_completed_production_before_job_order_completion.sql
-- ============================================================================

-- Prevent frame job orders from completing before linked production completes.
-- This keeps inventory consumption aligned with the actual production lifecycle.

CREATE OR REPLACE FUNCTION public.complete_frame_job_order_transaction(
  p_job_order_id UUID
)
RETURNS UUID
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_job_order RECORD;
  v_manufacturing_order RECORD;
  v_reservation RECORD;
  v_stock RECORD;
  v_stock_transaction_id UUID;
  v_next_stock NUMERIC;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT *
  INTO v_job_order
  FROM public.frame_job_orders
  WHERE id = p_job_order_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_job_order.id IS NULL THEN
    RAISE EXCEPTION 'Frame job order not found';
  END IF;

  IF v_job_order.status = 'completed' THEN
    RETURN p_job_order_id;
  END IF;

  IF v_job_order.status NOT IN ('reserved', 'in_progress') THEN
    RAISE EXCEPTION 'Only reserved or in-progress frame job orders can be completed';
  END IF;

  SELECT id, manufacturing_order_code, status
  INTO v_manufacturing_order
  FROM public.manufacturing_orders
  WHERE frame_job_order_id = p_job_order_id
    AND deleted_at IS NULL
    AND status <> 'cancelled'
  ORDER BY created_at DESC
  LIMIT 1
  FOR UPDATE;

  IF v_manufacturing_order.id IS NOT NULL
     AND v_manufacturing_order.status <> 'completed' THEN
    RAISE EXCEPTION 'Production must be completed before the job order can be completed';
  END IF;

  FOR v_reservation IN
    SELECT *
    FROM public.inventory_reservations
    WHERE job_order_id = p_job_order_id
      AND status = 'active'
      AND deleted_at IS NULL
    ORDER BY created_at ASC
  LOOP
    IF v_stock_transaction_id IS NULL THEN
      INSERT INTO public.stock_transactions (
        company_id,
        business_unit_id,
        transaction_date,
        transaction_type,
        reference_type,
        reference_id,
        warehouse_id,
        status,
        notes,
        custom_fields,
        created_by,
        updated_by
      )
      VALUES (
        v_job_order.company_id,
        v_job_order.business_unit_id,
        CURRENT_DATE,
        'out',
        'frame_job_order',
        p_job_order_id,
        v_reservation.warehouse_id,
        'posted',
        'Frame job order material consumption',
        jsonb_build_object('frameJobOrderId', p_job_order_id),
        v_user_id,
        v_user_id
      )
      RETURNING id INTO v_stock_transaction_id;
    END IF;

    SELECT *
    INTO v_stock
    FROM public.item_warehouse
    WHERE company_id = v_job_order.company_id
      AND item_id = v_reservation.item_id
      AND warehouse_id = v_reservation.warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF v_stock.id IS NULL THEN
      RAISE EXCEPTION 'No stock record exists for a reserved frame component';
    END IF;

    IF COALESCE(v_stock.current_stock, 0) < v_reservation.quantity THEN
      RAISE EXCEPTION 'Insufficient stock to complete frame job order';
    END IF;

    v_next_stock := COALESCE(v_stock.current_stock, 0) - v_reservation.quantity;

    INSERT INTO public.stock_transaction_items (
      company_id,
      transaction_id,
      item_id,
      quantity,
      uom_id,
      unit_cost,
      total_cost,
      qty_before,
      qty_after,
      valuation_rate,
      stock_value_before,
      stock_value_after,
      posting_date,
      posting_time,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      v_job_order.company_id,
      v_stock_transaction_id,
      v_reservation.item_id,
      v_reservation.quantity,
      v_reservation.uom_id,
      0,
      0,
      COALESCE(v_stock.current_stock, 0),
      v_next_stock,
      0,
      0,
      0,
      CURRENT_DATE,
      CURRENT_TIME,
      'Consumed by frame job order',
      v_user_id,
      v_user_id
    );

    UPDATE public.item_warehouse
    SET
      current_stock = v_next_stock,
      reserved_stock = GREATEST(0, COALESCE(reserved_stock, 0) - v_reservation.quantity),
      updated_by = v_user_id
    WHERE id = v_stock.id;

    UPDATE public.inventory_reservations
    SET
      status = 'consumed',
      consumed_at = NOW(),
      updated_by = v_user_id
    WHERE id = v_reservation.id;
  END LOOP;

  UPDATE public.frame_job_orders
  SET
    status = 'completed',
    completed_at = NOW(),
    updated_by = v_user_id
  WHERE id = p_job_order_id;

  RETURN p_job_order_id;
END;
$$;


-- ============================================================================
-- Migration: 20260423114500_allow_job_order_creation_from_invoiced_sales_orders.sql
-- ============================================================================

-- Allow invoiced sales orders to create a job order when they still have
-- frame-configured items and no active job order has been created yet.

CREATE OR REPLACE FUNCTION public.create_frame_job_order_from_sales_order_transaction(
  p_sales_order_id UUID,
  p_warehouse_id UUID
)
RETURNS TABLE (
  job_order_id UUID,
  job_order_code TEXT
)
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_sales_order RECORD;
  v_has_frame_items BOOLEAN;
  v_existing_job RECORD;
  v_job_order_id UUID;
  v_job_order_code TEXT;
  v_component RECORD;
  v_stock RECORD;
  v_available NUMERIC;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF p_warehouse_id IS NULL THEN
    RAISE EXCEPTION 'Warehouse is required to reserve frame materials';
  END IF;

  SELECT *
  INTO v_sales_order
  FROM public.sales_orders
  WHERE id = p_sales_order_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_sales_order.id IS NULL THEN
    RAISE EXCEPTION 'Sales order not found';
  END IF;

  IF v_sales_order.status NOT IN ('confirmed', 'in_progress', 'invoiced') THEN
    RAISE EXCEPTION 'Only confirmed, in-progress, or invoiced sales orders can create frame job orders';
  END IF;

  SELECT *
  INTO v_existing_job
  FROM public.frame_job_orders
  WHERE sales_order_id = p_sales_order_id
    AND status <> 'cancelled'
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_existing_job.id IS NOT NULL THEN
    RAISE EXCEPTION 'This sales order already has a frame job order';
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM public.sales_order_item_configurations cfg
    JOIN public.sales_order_items soi ON soi.id = cfg.order_item_id
    WHERE soi.order_id = p_sales_order_id
      AND soi.deleted_at IS NULL
      AND cfg.deleted_at IS NULL
  ) INTO v_has_frame_items;

  IF NOT v_has_frame_items THEN
    RAISE EXCEPTION 'Sales order has no frame-configured items';
  END IF;

  INSERT INTO public.frame_job_orders (
    company_id,
    business_unit_id,
    quotation_id,
    sales_order_id,
    customer_id,
    status,
    order_date,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    v_sales_order.company_id,
    v_sales_order.business_unit_id,
    v_sales_order.quotation_id,
    p_sales_order_id,
    v_sales_order.customer_id,
    'reserved',
    CURRENT_DATE,
    v_sales_order.notes,
    v_user_id,
    v_user_id
  )
  RETURNING id, frame_job_orders.job_order_code INTO v_job_order_id, v_job_order_code;

  FOR v_component IN
    SELECT c.*
    FROM public.sales_order_item_components c
    JOIN public.sales_order_items soi ON soi.id = c.order_item_id
    WHERE soi.order_id = p_sales_order_id
      AND soi.deleted_at IS NULL
      AND c.deleted_at IS NULL
    ORDER BY soi.sort_order ASC NULLS LAST, c.sort_order ASC
  LOOP
    SELECT *
    INTO v_stock
    FROM public.item_warehouse
    WHERE company_id = v_sales_order.company_id
      AND item_id = v_component.item_id
      AND warehouse_id = p_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF v_stock.id IS NULL THEN
      RAISE EXCEPTION 'No stock record exists for a required frame component';
    END IF;

    v_available := COALESCE(v_stock.current_stock, 0) - COALESCE(v_stock.reserved_stock, 0);

    IF v_available < v_component.total_quantity THEN
      RAISE EXCEPTION 'Insufficient available stock for a required frame component';
    END IF;

    INSERT INTO public.frame_job_order_items (
      company_id,
      job_order_id,
      sales_order_item_id,
      sales_order_component_id,
      quotation_component_id,
      item_id,
      item_description,
      required_quantity,
      uom_id,
      unit_rate,
      total_amount,
      created_by,
      updated_by
    )
    VALUES (
      v_sales_order.company_id,
      v_job_order_id,
      v_component.order_item_id,
      v_component.id,
      v_component.quotation_component_id,
      v_component.item_id,
      v_component.description,
      v_component.total_quantity,
      v_component.uom_id,
      v_component.unit_rate,
      v_component.total_amount,
      v_user_id,
      v_user_id
    );

    INSERT INTO public.inventory_reservations (
      company_id,
      reservation_type,
      source_type,
      source_id,
      quotation_id,
      sales_order_id,
      sales_order_item_id,
      sales_order_component_id,
      quotation_component_id,
      job_order_id,
      item_id,
      warehouse_id,
      quantity,
      uom_id,
      status,
      created_by,
      updated_by
    )
    VALUES (
      v_sales_order.company_id,
      'frame_job_order',
      'sales_order',
      p_sales_order_id,
      v_sales_order.quotation_id,
      p_sales_order_id,
      v_component.order_item_id,
      v_component.id,
      v_component.quotation_component_id,
      v_job_order_id,
      v_component.item_id,
      p_warehouse_id,
      v_component.total_quantity,
      v_component.uom_id,
      'active',
      v_user_id,
      v_user_id
    );

    UPDATE public.item_warehouse
    SET
      reserved_stock = COALESCE(reserved_stock, 0) + v_component.total_quantity,
      updated_by = v_user_id
    WHERE id = v_stock.id;
  END LOOP;

  UPDATE public.sales_orders
  SET
    status = CASE WHEN status = 'confirmed' THEN 'in_progress' ELSE status END,
    updated_by = v_user_id
  WHERE id = p_sales_order_id;

  job_order_id := v_job_order_id;
  job_order_code := v_job_order_code;
  RETURN NEXT;
END;
$$;


-- ============================================================================
-- Migration: 20260423133000_convert_manufacturing_timestamps_to_timestamptz.sql
-- ============================================================================

-- Convert manufacturing timestamps to timestamptz and remove unsafe UTC coercion
-- from floor-action writes. Existing values are interpreted as UTC because the
-- current implementation wrote UTC clock values into timestamp columns.

ALTER TABLE public.manufacturing_workstations
  ALTER COLUMN created_at TYPE TIMESTAMPTZ USING created_at AT TIME ZONE 'UTC',
  ALTER COLUMN updated_at TYPE TIMESTAMPTZ USING updated_at AT TIME ZONE 'UTC',
  ALTER COLUMN deleted_at TYPE TIMESTAMPTZ USING deleted_at AT TIME ZONE 'UTC';

ALTER TABLE public.manufacturing_orders
  ALTER COLUMN started_at TYPE TIMESTAMPTZ USING started_at AT TIME ZONE 'UTC',
  ALTER COLUMN completed_at TYPE TIMESTAMPTZ USING completed_at AT TIME ZONE 'UTC',
  ALTER COLUMN created_at TYPE TIMESTAMPTZ USING created_at AT TIME ZONE 'UTC',
  ALTER COLUMN updated_at TYPE TIMESTAMPTZ USING updated_at AT TIME ZONE 'UTC',
  ALTER COLUMN deleted_at TYPE TIMESTAMPTZ USING deleted_at AT TIME ZONE 'UTC';

ALTER TABLE public.manufacturing_order_items
  ALTER COLUMN created_at TYPE TIMESTAMPTZ USING created_at AT TIME ZONE 'UTC',
  ALTER COLUMN updated_at TYPE TIMESTAMPTZ USING updated_at AT TIME ZONE 'UTC',
  ALTER COLUMN deleted_at TYPE TIMESTAMPTZ USING deleted_at AT TIME ZONE 'UTC';

ALTER TABLE public.manufacturing_order_materials
  ALTER COLUMN created_at TYPE TIMESTAMPTZ USING created_at AT TIME ZONE 'UTC',
  ALTER COLUMN updated_at TYPE TIMESTAMPTZ USING updated_at AT TIME ZONE 'UTC',
  ALTER COLUMN deleted_at TYPE TIMESTAMPTZ USING deleted_at AT TIME ZONE 'UTC';

ALTER TABLE public.manufacturing_operations
  ALTER COLUMN started_at TYPE TIMESTAMPTZ USING started_at AT TIME ZONE 'UTC',
  ALTER COLUMN completed_at TYPE TIMESTAMPTZ USING completed_at AT TIME ZONE 'UTC',
  ALTER COLUMN created_at TYPE TIMESTAMPTZ USING created_at AT TIME ZONE 'UTC',
  ALTER COLUMN updated_at TYPE TIMESTAMPTZ USING updated_at AT TIME ZONE 'UTC',
  ALTER COLUMN deleted_at TYPE TIMESTAMPTZ USING deleted_at AT TIME ZONE 'UTC';

ALTER TABLE public.manufacturing_order_events
  ALTER COLUMN created_at TYPE TIMESTAMPTZ USING created_at AT TIME ZONE 'UTC',
  ALTER COLUMN deleted_at TYPE TIMESTAMPTZ USING deleted_at AT TIME ZONE 'UTC';

CREATE OR REPLACE FUNCTION public.apply_manufacturing_floor_action_transaction(
  p_manufacturing_order_id UUID,
  p_action TEXT,
  p_note TEXT DEFAULT NULL
)
RETURNS UUID
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_order RECORD;
  v_current_operation RECORD;
  v_next_operation RECORD;
  v_event_operation_id UUID;
  v_from_status TEXT;
  v_to_status TEXT;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT *
  INTO v_order
  FROM public.manufacturing_orders
  WHERE id = p_manufacturing_order_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_order.id IS NULL THEN
    RAISE EXCEPTION 'Manufacturing order not found';
  END IF;

  IF v_order.status IN ('completed', 'cancelled') THEN
    RAISE EXCEPTION 'Completed or cancelled manufacturing orders cannot be changed';
  END IF;

  v_from_status := v_order.status;

  IF p_action = 'hold' THEN
    UPDATE public.manufacturing_orders
    SET status = 'on_hold', updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;
    v_to_status := 'on_hold';
  ELSIF p_action = 'resume' THEN
    SELECT *
    INTO v_current_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status = 'in_progress'
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF FOUND THEN
      v_to_status := 'in_progress';
      v_event_operation_id := v_current_operation.id;
    ELSE
      v_to_status := 'ready';
    END IF;

    UPDATE public.manufacturing_orders
    SET status = v_to_status, updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;
  ELSIF p_action = 'start' THEN
    SELECT *
    INTO v_current_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status IN ('pending', 'blocked')
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No pending operation found';
    END IF;

    v_event_operation_id := v_current_operation.id;

    UPDATE public.manufacturing_operations
    SET status = 'in_progress',
        started_at = COALESCE(started_at, now()),
        updated_by = v_user_id
    WHERE id = v_current_operation.id;

    UPDATE public.manufacturing_orders
    SET status = CASE WHEN v_current_operation.operation_type = 'quality_check' THEN 'quality_check' ELSE 'in_progress' END,
        started_at = COALESCE(started_at, now()),
        current_workstation_id = v_current_operation.workstation_id,
        updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;

    v_to_status := CASE WHEN v_current_operation.operation_type = 'quality_check' THEN 'quality_check' ELSE 'in_progress' END;
  ELSIF p_action = 'complete_step' THEN
    SELECT *
    INTO v_current_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status = 'in_progress'
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No in-progress operation found';
    END IF;

    v_event_operation_id := v_current_operation.id;

    UPDATE public.manufacturing_operations
    SET status = 'completed',
        completed_at = now(),
        updated_by = v_user_id
    WHERE id = v_current_operation.id;

    SELECT *
    INTO v_next_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status = 'pending'
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF NOT FOUND THEN
      UPDATE public.manufacturing_orders
      SET status = 'completed',
          completed_at = now(),
          updated_by = v_user_id
      WHERE id = p_manufacturing_order_id;
      v_to_status := 'completed';
    ELSE
      v_event_operation_id := v_next_operation.id;

      UPDATE public.manufacturing_operations
      SET status = 'in_progress',
          started_at = COALESCE(started_at, now()),
          updated_by = v_user_id
      WHERE id = v_next_operation.id;

      v_to_status := CASE WHEN v_next_operation.operation_type = 'quality_check' THEN 'quality_check' ELSE 'in_progress' END;

      UPDATE public.manufacturing_orders
      SET status = v_to_status,
          current_workstation_id = v_next_operation.workstation_id,
          updated_by = v_user_id
      WHERE id = p_manufacturing_order_id;
    END IF;
  ELSIF p_action = 'complete' THEN
    UPDATE public.manufacturing_operations
    SET status = 'completed',
        completed_at = COALESCE(completed_at, now()),
        updated_by = v_user_id
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status <> 'completed'
      AND deleted_at IS NULL;

    UPDATE public.manufacturing_orders
    SET status = 'completed',
        completed_at = now(),
        updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;
    v_to_status := 'completed';
  ELSE
    RAISE EXCEPTION 'Unsupported manufacturing floor action';
  END IF;

  INSERT INTO public.manufacturing_order_events (
    company_id,
    manufacturing_order_id,
    manufacturing_operation_id,
    event_type,
    event_note,
    from_status,
    to_status,
    created_by
  )
  VALUES (
    v_order.company_id,
    p_manufacturing_order_id,
    v_event_operation_id,
    p_action,
    p_note,
    v_from_status,
    v_to_status,
    v_user_id
  );

  RETURN p_manufacturing_order_id;
END;
$$;


-- ============================================================================
-- Migration: 20260423150000_sync_frame_job_order_status_with_production.sql
-- ============================================================================

-- Synchronize frame job order statuses with production status.
-- New workflow:
-- pending -> queued -> in_progress / on_hold -> completed (or cancelled)

ALTER TABLE public.frame_job_orders
  ALTER COLUMN status SET DEFAULT 'pending';

ALTER TABLE public.frame_job_orders
  DROP CONSTRAINT IF EXISTS chk_frame_job_order_status;

ALTER TABLE public.frame_job_orders
  ADD CONSTRAINT chk_frame_job_order_status
  CHECK (status IN ('pending', 'queued', 'in_progress', 'on_hold', 'completed', 'cancelled'));

WITH latest_manufacturing AS (
  SELECT DISTINCT ON (frame_job_order_id)
    frame_job_order_id,
    status,
    completed_at
  FROM public.manufacturing_orders
  WHERE frame_job_order_id IS NOT NULL
    AND deleted_at IS NULL
    AND status <> 'cancelled'
  ORDER BY frame_job_order_id, created_at DESC
)
UPDATE public.frame_job_orders job
SET
  status = CASE
    WHEN job.status = 'cancelled' THEN 'cancelled'
    WHEN job.status = 'completed' THEN 'completed'
    WHEN latest_manufacturing.status IN ('ready', 'queued') THEN 'queued'
    WHEN latest_manufacturing.status IN ('in_progress', 'quality_check') THEN 'in_progress'
    WHEN latest_manufacturing.status = 'on_hold' THEN 'on_hold'
    WHEN latest_manufacturing.status = 'completed' THEN 'completed'
    ELSE 'pending'
  END,
  completed_at = CASE
    WHEN job.status = 'completed' THEN job.completed_at
    WHEN latest_manufacturing.status = 'completed' THEN COALESCE(job.completed_at, latest_manufacturing.completed_at)
    ELSE job.completed_at
  END
FROM latest_manufacturing
WHERE job.id = latest_manufacturing.frame_job_order_id
  AND job.deleted_at IS NULL;

UPDATE public.frame_job_orders
SET status = 'pending'
WHERE deleted_at IS NULL
  AND status IN ('draft', 'reserved');

CREATE OR REPLACE FUNCTION public.prevent_frame_job_order_cancel_when_production_active()
RETURNS trigger
LANGUAGE plpgsql
SET search_path = public
AS $$
BEGIN
  IF NEW.status = 'cancelled'
     AND COALESCE(OLD.status, '') <> 'cancelled'
     AND EXISTS (
       SELECT 1
       FROM public.manufacturing_orders mo
       WHERE mo.frame_job_order_id = NEW.id
         AND mo.deleted_at IS NULL
         AND mo.status NOT IN ('completed', 'cancelled')
     ) THEN
    RAISE EXCEPTION 'Job orders already in production cannot be cancelled';
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS prevent_frame_job_order_cancel_when_production_active
ON public.frame_job_orders;

CREATE TRIGGER prevent_frame_job_order_cancel_when_production_active
  BEFORE UPDATE OF status ON public.frame_job_orders
  FOR EACH ROW
  EXECUTE FUNCTION public.prevent_frame_job_order_cancel_when_production_active();

CREATE OR REPLACE FUNCTION public.finalize_frame_job_order_completion_transaction(
  p_job_order_id UUID
)
RETURNS UUID
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_job_order RECORD;
  v_reservation RECORD;
  v_stock RECORD;
  v_stock_transaction_id UUID;
  v_next_stock NUMERIC;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT *
  INTO v_job_order
  FROM public.frame_job_orders
  WHERE id = p_job_order_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_job_order.id IS NULL THEN
    RAISE EXCEPTION 'Frame job order not found';
  END IF;

  IF v_job_order.status = 'completed' THEN
    RETURN p_job_order_id;
  END IF;

  IF v_job_order.status = 'cancelled' THEN
    RAISE EXCEPTION 'Cancelled job orders cannot be completed';
  END IF;

  FOR v_reservation IN
    SELECT *
    FROM public.inventory_reservations
    WHERE job_order_id = p_job_order_id
      AND status = 'active'
      AND deleted_at IS NULL
    ORDER BY created_at ASC
  LOOP
    IF v_stock_transaction_id IS NULL THEN
      INSERT INTO public.stock_transactions (
        company_id,
        business_unit_id,
        transaction_date,
        transaction_type,
        reference_type,
        reference_id,
        warehouse_id,
        status,
        notes,
        custom_fields,
        created_by,
        updated_by
      )
      VALUES (
        v_job_order.company_id,
        v_job_order.business_unit_id,
        CURRENT_DATE,
        'out',
        'frame_job_order',
        p_job_order_id,
        v_reservation.warehouse_id,
        'posted',
        'Frame job order material consumption',
        jsonb_build_object('frameJobOrderId', p_job_order_id),
        v_user_id,
        v_user_id
      )
      RETURNING id INTO v_stock_transaction_id;
    END IF;

    SELECT *
    INTO v_stock
    FROM public.item_warehouse
    WHERE company_id = v_job_order.company_id
      AND item_id = v_reservation.item_id
      AND warehouse_id = v_reservation.warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF v_stock.id IS NULL THEN
      RAISE EXCEPTION 'No stock record exists for a reserved frame component';
    END IF;

    IF COALESCE(v_stock.current_stock, 0) < v_reservation.quantity THEN
      RAISE EXCEPTION 'Insufficient stock to complete frame job order';
    END IF;

    v_next_stock := COALESCE(v_stock.current_stock, 0) - v_reservation.quantity;

    INSERT INTO public.stock_transaction_items (
      company_id,
      transaction_id,
      item_id,
      quantity,
      uom_id,
      unit_cost,
      total_cost,
      qty_before,
      qty_after,
      valuation_rate,
      stock_value_before,
      stock_value_after,
      posting_date,
      posting_time,
      notes,
      created_by,
      updated_by
    )
    VALUES (
      v_job_order.company_id,
      v_stock_transaction_id,
      v_reservation.item_id,
      v_reservation.quantity,
      v_reservation.uom_id,
      0,
      0,
      COALESCE(v_stock.current_stock, 0),
      v_next_stock,
      0,
      0,
      0,
      CURRENT_DATE,
      CURRENT_TIME,
      'Consumed by frame job order',
      v_user_id,
      v_user_id
    );

    UPDATE public.item_warehouse
    SET
      current_stock = v_next_stock,
      reserved_stock = GREATEST(0, COALESCE(reserved_stock, 0) - v_reservation.quantity),
      updated_by = v_user_id
    WHERE id = v_stock.id;

    UPDATE public.inventory_reservations
    SET
      status = 'consumed',
      consumed_at = now(),
      updated_by = v_user_id
    WHERE id = v_reservation.id;

    UPDATE public.frame_job_order_items
    SET
      issued_quantity = required_quantity,
      updated_by = v_user_id
    WHERE job_order_id = p_job_order_id
      AND (
        (v_reservation.sales_order_component_id IS NOT NULL AND sales_order_component_id = v_reservation.sales_order_component_id)
        OR (v_reservation.sales_order_component_id IS NULL AND quotation_component_id = v_reservation.quotation_component_id)
      )
      AND deleted_at IS NULL;
  END LOOP;

  UPDATE public.frame_job_orders
  SET
    status = 'completed',
    completed_at = COALESCE(completed_at, now()),
    updated_by = v_user_id
  WHERE id = p_job_order_id;

  RETURN p_job_order_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.create_frame_job_order_from_sales_order_transaction(
  p_sales_order_id UUID,
  p_warehouse_id UUID
)
RETURNS TABLE (
  job_order_id UUID,
  job_order_code TEXT
)
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_sales_order RECORD;
  v_has_frame_items BOOLEAN;
  v_existing_job RECORD;
  v_job_order_id UUID;
  v_job_order_code TEXT;
  v_component RECORD;
  v_stock RECORD;
  v_available NUMERIC;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF p_warehouse_id IS NULL THEN
    RAISE EXCEPTION 'Warehouse is required to reserve frame materials';
  END IF;

  SELECT *
  INTO v_sales_order
  FROM public.sales_orders
  WHERE id = p_sales_order_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_sales_order.id IS NULL THEN
    RAISE EXCEPTION 'Sales order not found';
  END IF;

  IF v_sales_order.status NOT IN ('confirmed', 'in_progress', 'invoiced') THEN
    RAISE EXCEPTION 'Only confirmed, in-progress, or invoiced sales orders can create frame job orders';
  END IF;

  SELECT *
  INTO v_existing_job
  FROM public.frame_job_orders
  WHERE sales_order_id = p_sales_order_id
    AND status <> 'cancelled'
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_existing_job.id IS NOT NULL THEN
    RAISE EXCEPTION 'This sales order already has a frame job order';
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM public.sales_order_item_configurations cfg
    JOIN public.sales_order_items soi ON soi.id = cfg.order_item_id
    WHERE soi.order_id = p_sales_order_id
      AND soi.deleted_at IS NULL
      AND cfg.deleted_at IS NULL
  ) INTO v_has_frame_items;

  IF NOT v_has_frame_items THEN
    RAISE EXCEPTION 'Sales order has no frame-configured items';
  END IF;

  INSERT INTO public.frame_job_orders (
    company_id,
    business_unit_id,
    quotation_id,
    sales_order_id,
    customer_id,
    status,
    order_date,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    v_sales_order.company_id,
    v_sales_order.business_unit_id,
    v_sales_order.quotation_id,
    p_sales_order_id,
    v_sales_order.customer_id,
    'pending',
    CURRENT_DATE,
    v_sales_order.notes,
    v_user_id,
    v_user_id
  )
  RETURNING id, frame_job_orders.job_order_code INTO v_job_order_id, v_job_order_code;

  FOR v_component IN
    SELECT c.*
    FROM public.sales_order_item_components c
    JOIN public.sales_order_items soi ON soi.id = c.order_item_id
    WHERE soi.order_id = p_sales_order_id
      AND soi.deleted_at IS NULL
      AND c.deleted_at IS NULL
    ORDER BY soi.sort_order ASC NULLS LAST, c.sort_order ASC
  LOOP
    SELECT *
    INTO v_stock
    FROM public.item_warehouse
    WHERE company_id = v_sales_order.company_id
      AND item_id = v_component.item_id
      AND warehouse_id = p_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF v_stock.id IS NULL THEN
      RAISE EXCEPTION 'No stock record exists for a required frame component';
    END IF;

    v_available := COALESCE(v_stock.current_stock, 0) - COALESCE(v_stock.reserved_stock, 0);

    IF v_available < v_component.total_quantity THEN
      RAISE EXCEPTION 'Insufficient available stock for a required frame component';
    END IF;

    INSERT INTO public.frame_job_order_items (
      company_id,
      job_order_id,
      sales_order_item_id,
      sales_order_component_id,
      quotation_component_id,
      item_id,
      item_description,
      required_quantity,
      uom_id,
      unit_rate,
      total_amount,
      created_by,
      updated_by
    )
    VALUES (
      v_sales_order.company_id,
      v_job_order_id,
      v_component.order_item_id,
      v_component.id,
      v_component.quotation_component_id,
      v_component.item_id,
      v_component.description,
      v_component.total_quantity,
      v_component.uom_id,
      v_component.unit_rate,
      v_component.total_amount,
      v_user_id,
      v_user_id
    );

    INSERT INTO public.inventory_reservations (
      company_id,
      reservation_type,
      source_type,
      source_id,
      quotation_id,
      sales_order_id,
      sales_order_item_id,
      sales_order_component_id,
      quotation_component_id,
      job_order_id,
      item_id,
      warehouse_id,
      quantity,
      uom_id,
      status,
      created_by,
      updated_by
    )
    VALUES (
      v_sales_order.company_id,
      'frame_job_order',
      'sales_order',
      p_sales_order_id,
      v_sales_order.quotation_id,
      p_sales_order_id,
      v_component.order_item_id,
      v_component.id,
      v_component.quotation_component_id,
      v_job_order_id,
      v_component.item_id,
      p_warehouse_id,
      v_component.total_quantity,
      v_component.uom_id,
      'active',
      v_user_id,
      v_user_id
    );

    UPDATE public.item_warehouse
    SET
      reserved_stock = COALESCE(reserved_stock, 0) + v_component.total_quantity,
      updated_by = v_user_id
    WHERE id = v_stock.id;
  END LOOP;

  UPDATE public.sales_orders
  SET
    status = CASE WHEN status = 'confirmed' THEN 'in_progress' ELSE status END,
    updated_by = v_user_id
  WHERE id = p_sales_order_id;

  job_order_id := v_job_order_id;
  job_order_code := v_job_order_code;
  RETURN NEXT;
END;
$$;

CREATE OR REPLACE FUNCTION public.create_manufacturing_order_from_frame_job_order_transaction(
  p_frame_job_order_id UUID
)
RETURNS TABLE (
  manufacturing_order_id UUID,
  manufacturing_order_code TEXT
)
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_job_order RECORD;
  v_existing RECORD;
  v_mo_id UUID;
  v_mo_code TEXT;
  v_mo_item_id UUID;
  v_frame_line RECORD;
  v_cutting_id UUID;
  v_joining_id UUID;
  v_assembly_id UUID;
  v_qc_id UUID;
  v_ready_id UUID;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT *
  INTO v_job_order
  FROM public.frame_job_orders
  WHERE id = p_frame_job_order_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_job_order.id IS NULL THEN
    RAISE EXCEPTION 'Frame job order not found';
  END IF;

  IF v_job_order.status <> 'pending' THEN
    RAISE EXCEPTION 'Only pending frame job orders can be pushed to production';
  END IF;

  SELECT *
  INTO v_existing
  FROM public.manufacturing_orders
  WHERE frame_job_order_id = p_frame_job_order_id
    AND status <> 'cancelled'
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_existing.id IS NOT NULL THEN
    RAISE EXCEPTION 'This job order is already in production';
  END IF;

  PERFORM public.ensure_default_manufacturing_workstations(
    v_job_order.company_id,
    v_job_order.business_unit_id
  );

  SELECT id INTO v_cutting_id FROM public.manufacturing_workstations WHERE company_id = v_job_order.company_id AND workstation_code = 'CUTTING' AND deleted_at IS NULL LIMIT 1;
  SELECT id INTO v_joining_id FROM public.manufacturing_workstations WHERE company_id = v_job_order.company_id AND workstation_code = 'JOINING' AND deleted_at IS NULL LIMIT 1;
  SELECT id INTO v_assembly_id FROM public.manufacturing_workstations WHERE company_id = v_job_order.company_id AND workstation_code = 'ASSEMBLY' AND deleted_at IS NULL LIMIT 1;
  SELECT id INTO v_qc_id FROM public.manufacturing_workstations WHERE company_id = v_job_order.company_id AND workstation_code = 'QC' AND deleted_at IS NULL LIMIT 1;
  SELECT id INTO v_ready_id FROM public.manufacturing_workstations WHERE company_id = v_job_order.company_id AND workstation_code = 'READY' AND deleted_at IS NULL LIMIT 1;

  INSERT INTO public.manufacturing_orders (
    company_id,
    business_unit_id,
    source_type,
    source_id,
    sales_order_id,
    frame_job_order_id,
    quotation_id,
    customer_id,
    production_type,
    status,
    priority,
    due_date,
    current_workstation_id,
    notes,
    custom_fields,
    created_by,
    updated_by
  )
  VALUES (
    v_job_order.company_id,
    v_job_order.business_unit_id,
    'frame_job_order',
    p_frame_job_order_id,
    v_job_order.sales_order_id,
    p_frame_job_order_id,
    v_job_order.quotation_id,
    v_job_order.customer_id,
    'frame_service',
    'ready',
    'normal',
    v_job_order.order_date,
    v_cutting_id,
    v_job_order.notes,
    jsonb_build_object(
      'source', 'frame_job_order',
      'frameJobOrderId', p_frame_job_order_id,
      'salesOrderId', v_job_order.sales_order_id
    ),
    v_user_id,
    v_user_id
  )
  RETURNING id, manufacturing_orders.manufacturing_order_code INTO v_mo_id, v_mo_code;

  FOR v_frame_line IN
    SELECT
      COALESCE(fjoi.sales_order_item_id, fjoi.quotation_item_id) AS source_line_id,
      MAX(fjoi.item_description) AS item_description
    FROM public.frame_job_order_items fjoi
    WHERE fjoi.job_order_id = p_frame_job_order_id
      AND fjoi.deleted_at IS NULL
    GROUP BY COALESCE(fjoi.sales_order_item_id, fjoi.quotation_item_id)
    ORDER BY MIN(fjoi.created_at)
  LOOP
    INSERT INTO public.manufacturing_order_items (
      company_id,
      manufacturing_order_id,
      sales_order_item_id,
      item_id,
      item_description,
      quantity,
      uom_id,
      sort_order,
      created_by,
      updated_by
    )
    SELECT
      v_job_order.company_id,
      v_mo_id,
      (ARRAY_AGG(fjoi.sales_order_item_id ORDER BY fjoi.created_at))[1],
      (ARRAY_AGG(COALESCE(soi.item_id, qi.item_id, fjoi.item_id) ORDER BY fjoi.created_at))[1],
      COALESCE(MAX(soi.item_description), MAX(qi.item_description), v_frame_line.item_description, 'Frame job order'),
      COALESCE(MAX(soi.quantity), MAX(qi.quantity), 1),
      (ARRAY_AGG(COALESCE(soi.uom_id, qi.uom_id, fjoi.uom_id) ORDER BY fjoi.created_at))[1],
      COALESCE(MAX(soi.sort_order), MAX(qi.sort_order), 0),
      v_user_id,
      v_user_id
    FROM public.frame_job_order_items fjoi
    LEFT JOIN public.sales_order_items soi ON soi.id = fjoi.sales_order_item_id
    LEFT JOIN public.sales_quotation_items qi ON qi.id = fjoi.quotation_item_id
    WHERE fjoi.job_order_id = p_frame_job_order_id
      AND fjoi.deleted_at IS NULL
      AND COALESCE(fjoi.sales_order_item_id, fjoi.quotation_item_id) = v_frame_line.source_line_id
    RETURNING id INTO v_mo_item_id;

    INSERT INTO public.manufacturing_order_materials (
      company_id,
      manufacturing_order_id,
      manufacturing_order_item_id,
      sales_order_item_id,
      sales_order_component_id,
      item_id,
      item_description,
      required_quantity,
      issued_quantity,
      uom_id,
      unit_rate,
      total_amount,
      material_status,
      sort_order,
      created_by,
      updated_by
    )
    SELECT
      v_job_order.company_id,
      v_mo_id,
      v_mo_item_id,
      fjoi.sales_order_item_id,
      fjoi.sales_order_component_id,
      fjoi.item_id,
      fjoi.item_description,
      fjoi.required_quantity,
      fjoi.issued_quantity,
      fjoi.uom_id,
      fjoi.unit_rate,
      fjoi.total_amount,
      CASE WHEN fjoi.issued_quantity >= fjoi.required_quantity THEN 'issued' ELSE 'reserved' END,
      ROW_NUMBER() OVER (ORDER BY fjoi.created_at)::INTEGER,
      v_user_id,
      v_user_id
    FROM public.frame_job_order_items fjoi
    WHERE fjoi.job_order_id = p_frame_job_order_id
      AND fjoi.deleted_at IS NULL
      AND COALESCE(fjoi.sales_order_item_id, fjoi.quotation_item_id) = v_frame_line.source_line_id
    ORDER BY fjoi.created_at;
  END LOOP;

  INSERT INTO public.manufacturing_operations (
    company_id,
    manufacturing_order_id,
    workstation_id,
    operation_code,
    operation_name,
    operation_type,
    status,
    sequence_no,
    created_by,
    updated_by
  )
  VALUES
    (v_job_order.company_id, v_mo_id, v_cutting_id, 'CUT', 'Cut molding', 'production', 'pending', 10, v_user_id, v_user_id),
    (v_job_order.company_id, v_mo_id, v_joining_id, 'JOIN', 'Join frame', 'production', 'pending', 20, v_user_id, v_user_id),
    (v_job_order.company_id, v_mo_id, v_assembly_id, 'ASSEMBLE', 'Fit materials', 'production', 'pending', 30, v_user_id, v_user_id),
    (v_job_order.company_id, v_mo_id, v_qc_id, 'QC', 'Quality check', 'quality_check', 'pending', 40, v_user_id, v_user_id),
    (v_job_order.company_id, v_mo_id, v_ready_id, 'READY', 'Ready for release', 'ready', 'pending', 50, v_user_id, v_user_id);

  INSERT INTO public.manufacturing_order_events (
    company_id,
    manufacturing_order_id,
    event_type,
    event_note,
    to_status,
    created_by
  )
  VALUES (
    v_job_order.company_id,
    v_mo_id,
    'pushed_to_production',
    'Frame job order pushed to production',
    'ready',
    v_user_id
  );

  UPDATE public.frame_job_orders
  SET
    status = 'queued',
    updated_by = v_user_id
  WHERE id = p_frame_job_order_id;

  manufacturing_order_id := v_mo_id;
  manufacturing_order_code := v_mo_code;
  RETURN NEXT;
END;
$$;

CREATE OR REPLACE FUNCTION public.complete_frame_job_order_transaction(
  p_job_order_id UUID
)
RETURNS UUID
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_job_order RECORD;
  v_manufacturing_order RECORD;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT *
  INTO v_job_order
  FROM public.frame_job_orders
  WHERE id = p_job_order_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_job_order.id IS NULL THEN
    RAISE EXCEPTION 'Frame job order not found';
  END IF;

  IF v_job_order.status = 'completed' THEN
    RETURN p_job_order_id;
  END IF;

  IF v_job_order.status = 'cancelled' THEN
    RAISE EXCEPTION 'Cancelled job orders cannot be completed';
  END IF;

  IF v_job_order.status NOT IN ('queued', 'in_progress', 'on_hold') THEN
    RAISE EXCEPTION 'Only queued, in-progress, or on-hold job orders can be completed';
  END IF;

  SELECT id, manufacturing_order_code, status
  INTO v_manufacturing_order
  FROM public.manufacturing_orders
  WHERE frame_job_order_id = p_job_order_id
    AND deleted_at IS NULL
    AND status <> 'cancelled'
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_manufacturing_order.id IS NULL THEN
    RAISE EXCEPTION 'Job order must be pushed to production before completion';
  END IF;

  IF v_manufacturing_order.status <> 'completed' THEN
    RAISE EXCEPTION 'Production must be completed before the job order can be completed';
  END IF;

  RETURN public.finalize_frame_job_order_completion_transaction(p_job_order_id);
END;
$$;

CREATE OR REPLACE FUNCTION public.apply_manufacturing_floor_action_transaction(
  p_manufacturing_order_id UUID,
  p_action TEXT,
  p_note TEXT DEFAULT NULL
)
RETURNS UUID
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_order RECORD;
  v_current_operation RECORD;
  v_next_operation RECORD;
  v_event_operation_id UUID;
  v_from_status TEXT;
  v_to_status TEXT;
  v_job_status TEXT;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT *
  INTO v_order
  FROM public.manufacturing_orders
  WHERE id = p_manufacturing_order_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_order.id IS NULL THEN
    RAISE EXCEPTION 'Manufacturing order not found';
  END IF;

  IF v_order.status IN ('completed', 'cancelled') THEN
    RAISE EXCEPTION 'Completed or cancelled manufacturing orders cannot be changed';
  END IF;

  v_from_status := v_order.status;

  IF p_action = 'hold' THEN
    UPDATE public.manufacturing_orders
    SET status = 'on_hold', updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;
    v_to_status := 'on_hold';
  ELSIF p_action = 'resume' THEN
    SELECT *
    INTO v_current_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status = 'in_progress'
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF FOUND THEN
      v_to_status := 'in_progress';
      v_event_operation_id := v_current_operation.id;
    ELSE
      v_to_status := 'ready';
    END IF;

    UPDATE public.manufacturing_orders
    SET status = v_to_status, updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;
  ELSIF p_action = 'start' THEN
    SELECT *
    INTO v_current_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status IN ('pending', 'blocked')
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No pending operation found';
    END IF;

    v_event_operation_id := v_current_operation.id;

    UPDATE public.manufacturing_operations
    SET status = 'in_progress',
        started_at = COALESCE(started_at, now()),
        updated_by = v_user_id
    WHERE id = v_current_operation.id;

    UPDATE public.manufacturing_orders
    SET status = CASE WHEN v_current_operation.operation_type = 'quality_check' THEN 'quality_check' ELSE 'in_progress' END,
        started_at = COALESCE(started_at, now()),
        current_workstation_id = v_current_operation.workstation_id,
        updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;

    v_to_status := CASE WHEN v_current_operation.operation_type = 'quality_check' THEN 'quality_check' ELSE 'in_progress' END;
  ELSIF p_action = 'complete_step' THEN
    SELECT *
    INTO v_current_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status = 'in_progress'
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No in-progress operation found';
    END IF;

    v_event_operation_id := v_current_operation.id;

    UPDATE public.manufacturing_operations
    SET status = 'completed',
        completed_at = now(),
        updated_by = v_user_id
    WHERE id = v_current_operation.id;

    SELECT *
    INTO v_next_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status = 'pending'
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF NOT FOUND THEN
      UPDATE public.manufacturing_orders
      SET status = 'completed',
          completed_at = now(),
          updated_by = v_user_id
      WHERE id = p_manufacturing_order_id;
      v_to_status := 'completed';
    ELSE
      v_event_operation_id := v_next_operation.id;

      UPDATE public.manufacturing_operations
      SET status = 'in_progress',
          started_at = COALESCE(started_at, now()),
          updated_by = v_user_id
      WHERE id = v_next_operation.id;

      v_to_status := CASE WHEN v_next_operation.operation_type = 'quality_check' THEN 'quality_check' ELSE 'in_progress' END;

      UPDATE public.manufacturing_orders
      SET status = v_to_status,
          current_workstation_id = v_next_operation.workstation_id,
          updated_by = v_user_id
      WHERE id = p_manufacturing_order_id;
    END IF;
  ELSIF p_action = 'complete' THEN
    UPDATE public.manufacturing_operations
    SET status = 'completed',
        completed_at = COALESCE(completed_at, now()),
        updated_by = v_user_id
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status <> 'completed'
      AND deleted_at IS NULL;

    UPDATE public.manufacturing_orders
    SET status = 'completed',
        completed_at = now(),
        updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;
    v_to_status := 'completed';
  ELSE
    RAISE EXCEPTION 'Unsupported manufacturing floor action';
  END IF;

  INSERT INTO public.manufacturing_order_events (
    company_id,
    manufacturing_order_id,
    manufacturing_operation_id,
    event_type,
    event_note,
    from_status,
    to_status,
    created_by
  )
  VALUES (
    v_order.company_id,
    p_manufacturing_order_id,
    v_event_operation_id,
    p_action,
    p_note,
    v_from_status,
    v_to_status,
    v_user_id
  );

  IF v_order.frame_job_order_id IS NOT NULL THEN
    IF v_to_status = 'completed' THEN
      PERFORM public.finalize_frame_job_order_completion_transaction(v_order.frame_job_order_id);
    ELSE
      v_job_status := CASE
        WHEN v_to_status IN ('ready', 'queued') THEN 'queued'
        WHEN v_to_status IN ('in_progress', 'quality_check') THEN 'in_progress'
        WHEN v_to_status = 'on_hold' THEN 'on_hold'
        ELSE NULL
      END;

      IF v_job_status IS NOT NULL THEN
        UPDATE public.frame_job_orders
        SET
          status = v_job_status,
          updated_by = v_user_id
        WHERE id = v_order.frame_job_order_id
          AND deleted_at IS NULL
          AND status <> 'cancelled';
      END IF;
    END IF;
  END IF;

  RETURN p_manufacturing_order_id;
END;
$$;


-- ============================================================================
-- Migration: 20260423170000_fix_quotation_conversion_skip_inventory.sql
-- ============================================================================

ALTER TABLE public.sales_order_items
  ADD COLUMN IF NOT EXISTS skip_inventory BOOLEAN NOT NULL DEFAULT FALSE;

UPDATE public.sales_order_items soi
SET skip_inventory = TRUE
WHERE soi.deleted_at IS NULL
  AND soi.skip_inventory = FALSE
  AND EXISTS (
    SELECT 1
    FROM public.sales_order_item_configurations cfg
    WHERE cfg.order_item_id = soi.id
      AND cfg.deleted_at IS NULL
  );

CREATE OR REPLACE FUNCTION public.convert_sales_quotation_to_order_transaction(
  p_quotation_id UUID,
  p_business_unit_id UUID
)
RETURNS TABLE (
  sales_order_id UUID,
  order_code TEXT
)
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_quotation RECORD;
  v_quote_item RECORD;
  v_configuration RECORD;
  v_sales_order_id UUID;
  v_order_item_id UUID;
  v_order_configuration_id UUID;
  v_order_code TEXT;
  v_item_count INTEGER;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF p_business_unit_id IS NULL THEN
    RAISE EXCEPTION 'Business unit context required';
  END IF;

  SELECT *
  INTO v_quotation
  FROM public.sales_quotations
  WHERE id = p_quotation_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_quotation.id IS NULL THEN
    RAISE EXCEPTION 'Quotation not found';
  END IF;

  IF v_quotation.status <> 'accepted' THEN
    RAISE EXCEPTION 'Only accepted quotations can be converted to sales orders';
  END IF;

  IF v_quotation.sales_order_id IS NOT NULL THEN
    RAISE EXCEPTION 'This quotation has already been converted to a sales order';
  END IF;

  SELECT COUNT(*) INTO v_item_count
  FROM public.sales_quotation_items
  WHERE quotation_id = p_quotation_id
    AND deleted_at IS NULL;

  IF v_item_count = 0 THEN
    RAISE EXCEPTION 'Quotation must have at least one item';
  END IF;

  INSERT INTO public.sales_orders (
    company_id,
    business_unit_id,
    customer_id,
    quotation_id,
    order_date,
    expected_delivery_date,
    status,
    subtotal,
    discount_amount,
    tax_amount,
    total_amount,
    payment_terms,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    v_quotation.company_id,
    p_business_unit_id,
    v_quotation.customer_id,
    p_quotation_id,
    CURRENT_DATE,
    COALESCE(v_quotation.valid_until, CURRENT_DATE + 14),
    'confirmed',
    v_quotation.subtotal,
    v_quotation.discount_amount,
    v_quotation.tax_amount,
    v_quotation.total_amount,
    COALESCE(v_quotation.terms_conditions, 'Payment due within 30 days'),
    COALESCE(v_quotation.notes, ''),
    v_user_id,
    v_user_id
  )
  RETURNING id, sales_orders.order_code INTO v_sales_order_id, v_order_code;

  FOR v_quote_item IN
    SELECT *
    FROM public.sales_quotation_items
    WHERE quotation_id = p_quotation_id
      AND deleted_at IS NULL
    ORDER BY sort_order ASC NULLS LAST, created_at ASC
  LOOP
    INSERT INTO public.sales_order_items (
      company_id,
      order_id,
      item_id,
      item_description,
      quantity,
      uom_id,
      rate,
      discount_percent,
      discount_amount,
      tax_percent,
      tax_amount,
      line_total,
      quantity_shipped,
      quantity_delivered,
      sort_order,
      notes,
      created_by,
      updated_by,
      skip_inventory
    )
    VALUES (
      v_quote_item.company_id,
      v_sales_order_id,
      v_quote_item.item_id,
      v_quote_item.item_description,
      v_quote_item.quantity,
      v_quote_item.uom_id,
      v_quote_item.rate,
      COALESCE(v_quote_item.discount_percent, 0),
      COALESCE(v_quote_item.discount_amount, 0),
      COALESCE(v_quote_item.tax_percent, 0),
      COALESCE(v_quote_item.tax_amount, 0),
      v_quote_item.line_total,
      0,
      0,
      v_quote_item.sort_order,
      v_quote_item.notes,
      v_user_id,
      v_user_id,
      FALSE
    )
    RETURNING id INTO v_order_item_id;

    SELECT *
    INTO v_configuration
    FROM public.sales_quotation_item_configurations
    WHERE quotation_item_id = v_quote_item.id
      AND deleted_at IS NULL;

    IF v_configuration.id IS NOT NULL THEN
      UPDATE public.sales_order_items
      SET skip_inventory = TRUE,
          updated_by = v_user_id,
          updated_at = CURRENT_TIMESTAMP
      WHERE id = v_order_item_id;

      INSERT INTO public.sales_order_item_configurations (
        company_id,
        order_item_id,
        quotation_configuration_id,
        width,
        height,
        fixed_allowance,
        molding_item_id,
        molding_stick_length,
        molding_sticks_required,
        service_fee_mode,
        service_type,
        service_fee_amount,
        total_service_fee,
        invoice_display_mode,
        created_by,
        updated_by
      )
      VALUES (
        v_configuration.company_id,
        v_order_item_id,
        v_configuration.id,
        v_configuration.width,
        v_configuration.height,
        v_configuration.fixed_allowance,
        v_configuration.molding_item_id,
        v_configuration.molding_stick_length,
        v_configuration.molding_sticks_required,
        v_configuration.service_fee_mode,
        v_configuration.service_type,
        v_configuration.service_fee_amount,
        v_configuration.total_service_fee,
        v_configuration.invoice_display_mode,
        v_user_id,
        v_user_id
      )
      RETURNING id INTO v_order_configuration_id;

      INSERT INTO public.sales_order_item_components (
        company_id,
        order_item_id,
        configuration_id,
        quotation_component_id,
        component_type,
        source,
        item_id,
        description,
        qty_per_frame,
        total_quantity,
        uom_id,
        unit_rate,
        total_amount,
        rounding_mode,
        sort_order,
        created_by,
        updated_by
      )
      SELECT
        company_id,
        v_order_item_id,
        v_order_configuration_id,
        id,
        component_type,
        source,
        item_id,
        description,
        qty_per_frame,
        total_quantity,
        uom_id,
        unit_rate,
        total_amount,
        rounding_mode,
        sort_order,
        v_user_id,
        v_user_id
      FROM public.sales_quotation_item_components
      WHERE quotation_item_id = v_quote_item.id
        AND deleted_at IS NULL
      ORDER BY sort_order ASC NULLS LAST, created_at ASC;
    END IF;
  END LOOP;

  UPDATE public.sales_quotations
  SET
    status = 'ordered',
    sales_order_id = v_sales_order_id,
    updated_by = v_user_id
  WHERE id = p_quotation_id;

  sales_order_id := v_sales_order_id;
  order_code := v_order_code;
  RETURN NEXT;
END;
$$;


-- ============================================================================
-- Migration: 20260423173000_require_manufacturing_start_before_hold.sql
-- ============================================================================

CREATE OR REPLACE FUNCTION public.apply_manufacturing_floor_action_transaction(
  p_manufacturing_order_id UUID,
  p_action TEXT,
  p_note TEXT DEFAULT NULL
)
RETURNS UUID
LANGUAGE plpgsql
SET search_path = public
AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_order RECORD;
  v_current_operation RECORD;
  v_next_operation RECORD;
  v_event_operation_id UUID;
  v_from_status TEXT;
  v_to_status TEXT;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT *
  INTO v_order
  FROM public.manufacturing_orders
  WHERE id = p_manufacturing_order_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF v_order.id IS NULL THEN
    RAISE EXCEPTION 'Manufacturing order not found';
  END IF;

  IF v_order.status IN ('completed', 'cancelled') THEN
    RAISE EXCEPTION 'Completed or cancelled manufacturing orders cannot be changed';
  END IF;

  v_from_status := v_order.status;

  IF p_action = 'hold' THEN
    IF v_order.status NOT IN ('in_progress', 'quality_check') THEN
      RAISE EXCEPTION 'Manufacturing order must be started before it can be placed on hold';
    END IF;

    UPDATE public.manufacturing_orders
    SET status = 'on_hold', updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;
    v_to_status := 'on_hold';
  ELSIF p_action = 'resume' THEN
    SELECT *
    INTO v_current_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status = 'in_progress'
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF FOUND THEN
      v_to_status := 'in_progress';
      v_event_operation_id := v_current_operation.id;
    ELSE
      v_to_status := 'ready';
    END IF;

    UPDATE public.manufacturing_orders
    SET status = v_to_status, updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;
  ELSIF p_action = 'start' THEN
    SELECT *
    INTO v_current_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status IN ('pending', 'blocked')
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No pending operation found';
    END IF;

    v_event_operation_id := v_current_operation.id;

    UPDATE public.manufacturing_operations
    SET status = 'in_progress',
        started_at = COALESCE(started_at, now()),
        updated_by = v_user_id
    WHERE id = v_current_operation.id;

    UPDATE public.manufacturing_orders
    SET status = CASE WHEN v_current_operation.operation_type = 'quality_check' THEN 'quality_check' ELSE 'in_progress' END,
        started_at = COALESCE(started_at, now()),
        current_workstation_id = v_current_operation.workstation_id,
        updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;

    v_to_status := CASE WHEN v_current_operation.operation_type = 'quality_check' THEN 'quality_check' ELSE 'in_progress' END;
  ELSIF p_action = 'complete_step' THEN
    SELECT *
    INTO v_current_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status = 'in_progress'
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No in-progress operation found';
    END IF;

    v_event_operation_id := v_current_operation.id;

    UPDATE public.manufacturing_operations
    SET status = 'completed',
        completed_at = now(),
        updated_by = v_user_id
    WHERE id = v_current_operation.id;

    SELECT *
    INTO v_next_operation
    FROM public.manufacturing_operations
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status = 'pending'
      AND deleted_at IS NULL
    ORDER BY sequence_no ASC
    LIMIT 1;

    IF NOT FOUND THEN
      UPDATE public.manufacturing_orders
      SET status = 'completed',
          completed_at = now(),
          updated_by = v_user_id
      WHERE id = p_manufacturing_order_id;
      v_to_status := 'completed';
    ELSE
      v_event_operation_id := v_next_operation.id;

      UPDATE public.manufacturing_operations
      SET status = 'in_progress',
          started_at = COALESCE(started_at, now()),
          updated_by = v_user_id
      WHERE id = v_next_operation.id;

      v_to_status := CASE WHEN v_next_operation.operation_type = 'quality_check' THEN 'quality_check' ELSE 'in_progress' END;

      UPDATE public.manufacturing_orders
      SET status = v_to_status,
          current_workstation_id = v_next_operation.workstation_id,
          updated_by = v_user_id
      WHERE id = p_manufacturing_order_id;
    END IF;
  ELSIF p_action = 'complete' THEN
    UPDATE public.manufacturing_operations
    SET status = 'completed',
        completed_at = COALESCE(completed_at, now()),
        updated_by = v_user_id
    WHERE manufacturing_order_id = p_manufacturing_order_id
      AND status <> 'completed'
      AND deleted_at IS NULL;

    UPDATE public.manufacturing_orders
    SET status = 'completed',
        completed_at = now(),
        updated_by = v_user_id
    WHERE id = p_manufacturing_order_id;
    v_to_status := 'completed';
  ELSE
    RAISE EXCEPTION 'Unsupported manufacturing floor action';
  END IF;

  INSERT INTO public.manufacturing_order_events (
    company_id,
    manufacturing_order_id,
    manufacturing_operation_id,
    event_type,
    event_note,
    from_status,
    to_status,
    created_by
  )
  VALUES (
    v_order.company_id,
    p_manufacturing_order_id,
    v_event_operation_id,
    p_action,
    p_note,
    v_from_status,
    v_to_status,
    v_user_id
  );

  RETURN p_manufacturing_order_id;
END;
$$;


-- ============================================================================
-- Migration: 20260425153000_fix_item_unit_option_barcode_collisions.sql
-- ============================================================================

-- ============================================================================
-- Migration: Fix Item Unit Option Barcode Collisions
-- Version: 20260425153000
-- Description: Prevent barcode collisions after seeded/manual item_unit_options
--              inserts and retry barcode generation inside the trigger.
-- Date: 2026-04-25
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.apply_item_unit_option_defaults_and_validate()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_item_company_id UUID;
  v_item_base_uom_id UUID;
  v_uom_company_id UUID;
  v_barcode_attempts INTEGER := 0;
  v_max_barcode_attempts CONSTANT INTEGER := 25;
BEGIN
  IF NEW.barcode IS NULL OR BTRIM(NEW.barcode) = '' THEN
    LOOP
      v_barcode_attempts := v_barcode_attempts + 1;

      IF v_barcode_attempts > v_max_barcode_attempts THEN
        RAISE EXCEPTION 'Unable to generate a unique item unit option barcode after % attempts', v_max_barcode_attempts;
      END IF;

      NEW.barcode := public.generate_item_unit_option_barcode();

      EXIT WHEN NOT EXISTS (
        SELECT 1
        FROM public.item_unit_options iuo
        WHERE iuo.company_id = NEW.company_id
          AND iuo.barcode = NEW.barcode
          AND iuo.deleted_at IS NULL
          AND (TG_OP = 'INSERT' OR iuo.id <> NEW.id)
      );
    END LOOP;
  END IF;

  IF NEW.barcode !~ '^[0-9]{10}$' THEN
    RAISE EXCEPTION 'Barcode must be exactly 10 numeric digits';
  END IF;

  SELECT i.company_id, i.uom_id
    INTO v_item_company_id, v_item_base_uom_id
  FROM public.items i
  WHERE i.id = NEW.item_id
    AND i.deleted_at IS NULL;

  IF v_item_company_id IS NULL THEN
    RAISE EXCEPTION 'Item % does not exist or has been deleted', NEW.item_id;
  END IF;

  IF v_item_company_id <> NEW.company_id THEN
    RAISE EXCEPTION 'Item % does not belong to company %', NEW.item_id, NEW.company_id;
  END IF;

  SELECT u.company_id
    INTO v_uom_company_id
  FROM public.units_of_measure u
  WHERE u.id = NEW.uom_id
    AND u.deleted_at IS NULL;

  IF v_uom_company_id IS NULL THEN
    RAISE EXCEPTION 'Unit of measure % does not exist or has been deleted', NEW.uom_id;
  END IF;

  IF v_uom_company_id <> NEW.company_id THEN
    RAISE EXCEPTION 'Unit of measure % does not belong to company %', NEW.uom_id, NEW.company_id;
  END IF;

  IF NEW.is_base AND NEW.uom_id <> v_item_base_uom_id THEN
    RAISE EXCEPTION 'Base item unit option must use the item base uom_id';
  END IF;

  IF NEW.deleted_at IS NOT NULL AND NEW.is_base THEN
    RAISE EXCEPTION 'Base item unit option cannot be soft-deleted';
  END IF;

  IF NEW.deleted_at IS NOT NULL AND NEW.is_default THEN
    RAISE EXCEPTION 'Default item unit option cannot be soft-deleted while marked default';
  END IF;

  RETURN NEW;
END;
$$;

DO $$
DECLARE
  v_row_count BIGINT;
BEGIN
  SELECT COUNT(*) INTO v_row_count
  FROM public.item_unit_options;

  PERFORM setval(
    'public.item_unit_option_barcode_seq',
    GREATEST(v_row_count, 1),
    v_row_count > 0
  );
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260429110000_add_customer_ledger_rpcs.sql
-- ============================================================================

-- Migration: Add customer ledger RPCs
-- Description: Provides customer account statement rows and summary metrics derived from invoices, payments, and POS transactions.
-- Date: 2026-04-29

-- ============================================================================
-- FUNCTION: get_customer_ledger_summary
-- ============================================================================

CREATE OR REPLACE FUNCTION public.get_customer_ledger_summary(
  p_company_id UUID,
  p_customer_id UUID,
  p_date_from DATE DEFAULT NULL,
  p_date_to DATE DEFAULT NULL
)
RETURNS TABLE (
  opening_balance NUMERIC,
  closing_balance NUMERIC,
  period_debits NUMERIC,
  period_credits NUMERIC,
  invoice_charges NUMERIC,
  payments_received NUMERIC,
  pos_sales NUMERIC,
  active_invoice_count BIGINT,
  overdue_invoice_count BIGINT,
  last_activity_at TIMESTAMPTZ
)
LANGUAGE sql
STABLE
AS $$
  WITH invoice_entries AS (
    SELECT
      (si.invoice_date::timestamp AT TIME ZONE 'UTC') AS event_at,
      si.total_amount::numeric AS debit,
      0::numeric AS credit,
      si.total_amount::numeric AS balance_effect,
      'invoice'::text AS source_type,
      si.status
    FROM public.sales_invoices si
    WHERE si.company_id = p_company_id
      AND si.customer_id = p_customer_id
      AND si.deleted_at IS NULL
      AND si.status NOT IN ('draft', 'cancelled')
  ),
  payment_entries AS (
    SELECT
      (ip.payment_date::timestamp AT TIME ZONE 'UTC') AS event_at,
      0::numeric AS debit,
      ip.amount::numeric AS credit,
      -ip.amount::numeric AS balance_effect,
      'payment'::text AS source_type,
      si.status
    FROM public.invoice_payments ip
    INNER JOIN public.sales_invoices si ON si.id = ip.invoice_id
    WHERE ip.company_id = p_company_id
      AND si.company_id = p_company_id
      AND si.customer_id = p_customer_id
      AND ip.deleted_at IS NULL
      AND si.deleted_at IS NULL
      AND si.status <> 'cancelled'
  ),
  pos_entries AS (
    SELECT
      pt.transaction_date AS event_at,
      pt.total_amount::numeric AS debit,
      LEAST(pt.amount_paid::numeric, pt.total_amount::numeric) AS credit,
      (pt.total_amount::numeric - LEAST(pt.amount_paid::numeric, pt.total_amount::numeric)) AS balance_effect,
      'pos'::text AS source_type,
      pt.status
    FROM public.pos_transactions pt
    WHERE pt.company_id = p_company_id
      AND pt.customer_id = p_customer_id
      AND pt.status = 'completed'
      AND NOT EXISTS (
        SELECT 1
        FROM public.sales_invoices linked_si
        WHERE linked_si.company_id = p_company_id
          AND linked_si.deleted_at IS NULL
          AND linked_si.status <> 'cancelled'
          AND linked_si.custom_fields ->> 'posTransactionId' = pt.id::text
      )
  ),
  entries AS (
    SELECT * FROM invoice_entries
    UNION ALL
    SELECT * FROM payment_entries
    UNION ALL
    SELECT * FROM pos_entries
  ),
  dated_entries AS (
    SELECT *
    FROM entries
    WHERE (p_date_from IS NULL OR event_at::date >= p_date_from)
      AND (p_date_to IS NULL OR event_at::date <= p_date_to)
  ),
  opening AS (
    SELECT COALESCE(SUM(balance_effect), 0)::numeric AS amount
    FROM entries
    WHERE p_date_from IS NOT NULL
      AND event_at::date < p_date_from
  ),
  active_invoices AS (
    SELECT
      COUNT(*)::bigint AS active_count,
      COUNT(*) FILTER (
        WHERE si.due_date < CURRENT_DATE
          AND si.amount_due > 0
          AND si.status IN ('sent', 'partially_paid', 'overdue')
      )::bigint AS overdue_count
    FROM public.sales_invoices si
    WHERE si.company_id = p_company_id
      AND si.customer_id = p_customer_id
      AND si.deleted_at IS NULL
      AND si.status NOT IN ('draft', 'paid', 'cancelled')
      AND si.amount_due > 0
  )
  SELECT
    opening.amount AS opening_balance,
    (opening.amount + COALESCE(SUM(dated_entries.balance_effect), 0))::numeric AS closing_balance,
    COALESCE(SUM(dated_entries.debit), 0)::numeric AS period_debits,
    COALESCE(SUM(dated_entries.credit), 0)::numeric AS period_credits,
    COALESCE(SUM(dated_entries.debit) FILTER (WHERE dated_entries.source_type = 'invoice'), 0)::numeric AS invoice_charges,
    COALESCE(SUM(dated_entries.credit) FILTER (WHERE dated_entries.source_type = 'payment'), 0)::numeric AS payments_received,
    COALESCE(SUM(dated_entries.debit) FILTER (WHERE dated_entries.source_type = 'pos'), 0)::numeric AS pos_sales,
    active_invoices.active_count AS active_invoice_count,
    active_invoices.overdue_count AS overdue_invoice_count,
    MAX(dated_entries.event_at) AS last_activity_at
  FROM opening
  CROSS JOIN active_invoices
  LEFT JOIN dated_entries ON TRUE
  GROUP BY opening.amount, active_invoices.active_count, active_invoices.overdue_count;
$$;

COMMENT ON FUNCTION public.get_customer_ledger_summary(UUID, UUID, DATE, DATE) IS
  'Summarizes a customer ledger from sales invoices, invoice payments, and completed POS cash-sale activity.';

-- ============================================================================
-- FUNCTION: get_customer_ledger_entries
-- ============================================================================

CREATE OR REPLACE FUNCTION public.get_customer_ledger_entries(
  p_company_id UUID,
  p_customer_id UUID,
  p_date_from DATE DEFAULT NULL,
  p_date_to DATE DEFAULT NULL,
  p_source_type TEXT DEFAULT NULL,
  p_search TEXT DEFAULT NULL,
  p_page INTEGER DEFAULT 1,
  p_limit INTEGER DEFAULT 20
)
RETURNS TABLE (
  entry_id TEXT,
  sort_key TEXT,
  source_type TEXT,
  source_id UUID,
  document_number TEXT,
  event_at TIMESTAMPTZ,
  due_date DATE,
  status TEXT,
  description TEXT,
  debit NUMERIC,
  credit NUMERIC,
  amount NUMERIC,
  balance_effect NUMERIC,
  running_balance NUMERIC,
  payment_method TEXT,
  reference TEXT,
  total_count BIGINT
)
LANGUAGE sql
STABLE
AS $$
  WITH settings AS (
    SELECT
      GREATEST(COALESCE(p_page, 1), 1) AS page_number,
      LEAST(GREATEST(COALESCE(p_limit, 20), 1), 50) AS page_limit
  ),
  invoice_entries AS (
    SELECT
      ('invoice:' || si.id::text) AS entry_id,
      ('invoice:' || si.id::text) AS sort_key,
      'invoice'::text AS source_type,
      si.id AS source_id,
      si.invoice_code::text AS document_number,
      (si.invoice_date::timestamp AT TIME ZONE 'UTC') AS event_at,
      si.due_date,
      si.status::text AS status,
      ('Sales invoice ' || si.invoice_code)::text AS description,
      si.total_amount::numeric AS debit,
      0::numeric AS credit,
      si.total_amount::numeric AS amount,
      si.total_amount::numeric AS balance_effect,
      NULL::text AS payment_method,
      NULL::text AS reference
    FROM public.sales_invoices si
    WHERE si.company_id = p_company_id
      AND si.customer_id = p_customer_id
      AND si.deleted_at IS NULL
      AND si.status NOT IN ('draft', 'cancelled')
  ),
  payment_entries AS (
    SELECT
      ('payment:' || ip.id::text) AS entry_id,
      ('payment:' || ip.id::text) AS sort_key,
      'payment'::text AS source_type,
      ip.id AS source_id,
      COALESCE(ip.payment_code, si.invoice_code)::text AS document_number,
      (ip.payment_date::timestamp AT TIME ZONE 'UTC') AS event_at,
      NULL::date AS due_date,
      si.status::text AS status,
      ('Payment for invoice ' || si.invoice_code)::text AS description,
      0::numeric AS debit,
      ip.amount::numeric AS credit,
      ip.amount::numeric AS amount,
      -ip.amount::numeric AS balance_effect,
      ip.payment_method::text AS payment_method,
      ip.reference::text AS reference
    FROM public.invoice_payments ip
    INNER JOIN public.sales_invoices si ON si.id = ip.invoice_id
    WHERE ip.company_id = p_company_id
      AND si.company_id = p_company_id
      AND si.customer_id = p_customer_id
      AND ip.deleted_at IS NULL
      AND si.deleted_at IS NULL
      AND si.status <> 'cancelled'
  ),
  pos_entries AS (
    SELECT
      ('pos:' || pt.id::text) AS entry_id,
      ('pos:' || pt.id::text) AS sort_key,
      'pos'::text AS source_type,
      pt.id AS source_id,
      pt.transaction_code::text AS document_number,
      pt.transaction_date AS event_at,
      NULL::date AS due_date,
      pt.status::text AS status,
      ('POS cash sale ' || pt.transaction_code)::text AS description,
      pt.total_amount::numeric AS debit,
      LEAST(pt.amount_paid::numeric, pt.total_amount::numeric) AS credit,
      pt.total_amount::numeric AS amount,
      (pt.total_amount::numeric - LEAST(pt.amount_paid::numeric, pt.total_amount::numeric)) AS balance_effect,
      payment_summary.payment_methods AS payment_method,
      payment_summary.references AS reference
    FROM public.pos_transactions pt
    LEFT JOIN LATERAL (
      SELECT
        STRING_AGG(DISTINCT pp.payment_method, ', ' ORDER BY pp.payment_method) AS payment_methods,
        STRING_AGG(DISTINCT pp.reference, ', ' ORDER BY pp.reference) FILTER (WHERE pp.reference IS NOT NULL AND pp.reference <> '') AS references
      FROM public.pos_transaction_payments pp
      WHERE pp.pos_transaction_id = pt.id
    ) payment_summary ON TRUE
    WHERE pt.company_id = p_company_id
      AND pt.customer_id = p_customer_id
      AND pt.status = 'completed'
      AND NOT EXISTS (
        SELECT 1
        FROM public.sales_invoices linked_si
        WHERE linked_si.company_id = p_company_id
          AND linked_si.deleted_at IS NULL
          AND linked_si.status <> 'cancelled'
          AND linked_si.custom_fields ->> 'posTransactionId' = pt.id::text
      )
  ),
  entries AS (
    SELECT * FROM invoice_entries
    UNION ALL
    SELECT * FROM payment_entries
    UNION ALL
    SELECT * FROM pos_entries
  ),
  opening AS (
    SELECT COALESCE(SUM(balance_effect), 0)::numeric AS amount
    FROM entries
    WHERE p_date_from IS NOT NULL
      AND event_at::date < p_date_from
  ),
  dated_entries AS (
    SELECT *
    FROM entries
    WHERE (p_date_from IS NULL OR event_at::date >= p_date_from)
      AND (p_date_to IS NULL OR event_at::date <= p_date_to)
  ),
  balanced_entries AS (
    SELECT
      dated_entries.*,
      opening.amount
        + SUM(dated_entries.balance_effect) OVER (
            ORDER BY dated_entries.event_at ASC, dated_entries.sort_key ASC
            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
          ) AS running_balance
    FROM dated_entries
    CROSS JOIN opening
  ),
  visible_entries AS (
    SELECT *
    FROM balanced_entries
    WHERE (p_source_type IS NULL OR p_source_type = 'all' OR source_type = p_source_type)
      AND (
        NULLIF(TRIM(COALESCE(p_search, '')), '') IS NULL
        OR document_number ILIKE '%' || TRIM(p_search) || '%'
        OR description ILIKE '%' || TRIM(p_search) || '%'
        OR COALESCE(payment_method, '') ILIKE '%' || TRIM(p_search) || '%'
        OR COALESCE(reference, '') ILIKE '%' || TRIM(p_search) || '%'
      )
  ),
  numbered_entries AS (
    SELECT
      visible_entries.*,
      ROW_NUMBER() OVER (ORDER BY event_at DESC, sort_key DESC) AS row_number,
      COUNT(*) OVER () AS total_remaining
    FROM visible_entries
  )
  SELECT
    numbered_entries.entry_id,
    numbered_entries.sort_key,
    numbered_entries.source_type,
    numbered_entries.source_id,
    numbered_entries.document_number,
    numbered_entries.event_at,
    numbered_entries.due_date,
    numbered_entries.status,
    numbered_entries.description,
    numbered_entries.debit,
    numbered_entries.credit,
    numbered_entries.amount,
    numbered_entries.balance_effect,
    numbered_entries.running_balance,
    numbered_entries.payment_method,
    numbered_entries.reference,
    numbered_entries.total_remaining AS total_count
  FROM numbered_entries
  CROSS JOIN settings
  WHERE numbered_entries.row_number > ((settings.page_number - 1) * settings.page_limit)
    AND numbered_entries.row_number <= (settings.page_number * settings.page_limit)
  ORDER BY numbered_entries.event_at DESC, numbered_entries.sort_key DESC;
$$;

