DROP FUNCTION IF EXISTS public.get_items_enhanced_page(
  UUID,
  TEXT,
  UUID,
  UUID,
  TEXT,
  TEXT,
  UUID,
  INTEGER,
  INTEGER
);

CREATE OR REPLACE FUNCTION public.get_items_enhanced_page(
  p_company_id UUID,
  p_search TEXT DEFAULT NULL,
  p_category_id UUID DEFAULT NULL,
  p_warehouse_id UUID DEFAULT NULL,
  p_item_type TEXT DEFAULT NULL,
  p_status TEXT DEFAULT NULL,
  p_business_unit_id UUID DEFAULT NULL,
  p_page INTEGER DEFAULT 1,
  p_limit INTEGER DEFAULT 10
)
RETURNS TABLE (
  id UUID,
  item_code TEXT,
  item_name TEXT,
  item_name_cn TEXT,
  category_id UUID,
  category_name TEXT,
  uom_id UUID,
  uom_code TEXT,
  cost_price NUMERIC,
  purchase_price NUMERIC,
  import_cost NUMERIC,
  import_currency TEXT,
  sales_price NUMERIC,
  item_type TEXT,
  custom_fields JSONB,
  is_active BOOLEAN,
  image_url TEXT,
  on_hand NUMERIC,
  allocated NUMERIC,
  available NUMERIC,
  reorder_point NUMERIC,
  max_stock_level NUMERIC,
  in_transit NUMERIC,
  estimated_arrival_date TIMESTAMP,
  status TEXT,
  total_count BIGINT
)
LANGUAGE sql
STABLE
AS $$
WITH filtered_items AS (
  SELECT
    i.id,
    i.item_code,
    i.item_name,
    i.item_name_cn,
    i.category_id,
    ic.name AS category_name,
    i.uom_id,
    u.code AS uom_code,
    i.cost_price,
    i.purchase_price,
    i.import_cost,
    i.import_currency,
    i.sales_price,
    i.item_type,
    i.custom_fields,
    COALESCE(i.is_active, true) AS is_active,
    i.image_url
  FROM public.items i
  LEFT JOIN public.item_categories ic ON ic.id = i.category_id
  LEFT JOIN public.units_of_measure u ON u.id = i.uom_id
  WHERE i.company_id = p_company_id
    AND i.deleted_at IS NULL
    AND (
      p_search IS NULL
      OR p_search = ''
      OR i.item_code ILIKE ('%' || p_search || '%')
      OR i.item_name ILIKE ('%' || p_search || '%')
      OR COALESCE(i.item_name_cn, '') ILIKE ('%' || p_search || '%')
      OR EXISTS (
        SELECT 1
        FROM public.item_unit_options iuo
        WHERE iuo.company_id = i.company_id
          AND iuo.item_id = i.id
          AND iuo.deleted_at IS NULL
          AND COALESCE(iuo.barcode, '') ILIKE ('%' || p_search || '%')
      )
    )
    AND (p_category_id IS NULL OR i.category_id = p_category_id)
    AND (p_item_type IS NULL OR i.item_type = p_item_type)
),
warehouse_scope AS (
  SELECT
    iw.item_id,
    iw.current_stock,
    iw.reserved_stock,
    iw.available_stock AS available,
    iw.reorder_level,
    iw.max_quantity,
    iw.in_transit,
    iw.estimated_arrival_date
  FROM public.item_warehouse iw
  INNER JOIN public.warehouses w ON w.id = iw.warehouse_id
  WHERE iw.company_id = p_company_id
    AND iw.deleted_at IS NULL
    AND w.deleted_at IS NULL
    AND (p_warehouse_id IS NULL OR iw.warehouse_id = p_warehouse_id)
    AND (
      p_warehouse_id IS NOT NULL
      OR p_business_unit_id IS NULL
      OR w.business_unit_id = p_business_unit_id
    )
),
stock_agg AS (
  SELECT
    ws.item_id,
    SUM(COALESCE(ws.current_stock, 0)) AS on_hand,
    SUM(COALESCE(ws.reserved_stock, 0)) AS allocated,
    SUM(COALESCE(ws.available, 0)) AS available,
    MAX(COALESCE(ws.reorder_level, 0)) AS reorder_point,
    SUM(COALESCE(ws.max_quantity, 0)) AS max_stock_level,
    SUM(COALESCE(ws.in_transit, 0)) AS in_transit,
    MIN(ws.estimated_arrival_date) FILTER (WHERE ws.estimated_arrival_date IS NOT NULL)
      AS estimated_arrival_date
  FROM warehouse_scope ws
  GROUP BY ws.item_id
),
enriched AS (
  SELECT
    fi.id,
    fi.item_code,
    fi.item_name,
    fi.item_name_cn,
    fi.category_id,
    fi.category_name,
    fi.uom_id,
    fi.uom_code,
    fi.cost_price,
    fi.purchase_price,
    fi.import_cost,
    fi.import_currency,
    fi.sales_price,
    fi.item_type,
    fi.custom_fields,
    fi.is_active,
    fi.image_url,
    COALESCE(sa.on_hand, 0) AS on_hand,
    COALESCE(sa.allocated, 0) AS allocated,
    COALESCE(sa.available, 0) AS available,
    COALESCE(sa.reorder_point, 0) AS reorder_point,
    COALESCE(sa.max_stock_level, 0) AS max_stock_level,
    COALESCE(sa.in_transit, 0) AS in_transit,
    sa.estimated_arrival_date,
    CASE
      WHEN NOT fi.is_active THEN 'discontinued'
      WHEN COALESCE(sa.available, 0) <= 0 THEN 'out_of_stock'
      WHEN COALESCE(sa.reorder_point, 0) > 0
        AND COALESCE(sa.available, 0) <= COALESCE(sa.reorder_point, 0)
        THEN 'low_stock'
      WHEN COALESCE(sa.max_stock_level, 0) > 0
        AND COALESCE(sa.available, 0) > COALESCE(sa.max_stock_level, 0)
        THEN 'overstock'
      ELSE 'normal'
    END AS status
  FROM filtered_items fi
  LEFT JOIN stock_agg sa ON sa.item_id = fi.id
),
status_filtered AS (
  SELECT *
  FROM enriched e
  WHERE p_status IS NULL
    OR p_status = ''
    OR p_status = 'all'
    OR e.status = p_status
)
SELECT
  sf.id,
  sf.item_code,
  sf.item_name,
  sf.item_name_cn,
  sf.category_id,
  sf.category_name,
  sf.uom_id,
  sf.uom_code,
  sf.cost_price,
  sf.purchase_price,
  sf.import_cost,
  sf.import_currency,
  sf.sales_price,
  sf.item_type,
  sf.custom_fields,
  sf.is_active,
  sf.image_url,
  sf.on_hand,
  sf.allocated,
  sf.available,
  sf.reorder_point,
  sf.max_stock_level,
  sf.in_transit,
  sf.estimated_arrival_date,
  sf.status,
  COUNT(*) OVER() AS total_count
FROM status_filtered sf
ORDER BY sf.item_name ASC
OFFSET (GREATEST(p_page, 1) - 1) * GREATEST(p_limit, 1)
LIMIT GREATEST(p_limit, 1);
$$;

DROP FUNCTION IF EXISTS public.get_items_enhanced_stats(
  UUID,
  TEXT,
  UUID,
  UUID,
  TEXT,
  TEXT,
  UUID
);

CREATE OR REPLACE FUNCTION public.get_items_enhanced_stats(
  p_company_id UUID,
  p_search TEXT DEFAULT NULL,
  p_category_id UUID DEFAULT NULL,
  p_warehouse_id UUID DEFAULT NULL,
  p_item_type TEXT DEFAULT NULL,
  p_status TEXT DEFAULT NULL,
  p_business_unit_id UUID DEFAULT NULL
)
RETURNS TABLE (
  total_available_value NUMERIC,
  low_stock_count BIGINT,
  out_of_stock_count BIGINT,
  total_count BIGINT
)
LANGUAGE sql
STABLE
AS $$
WITH filtered_items AS (
  SELECT
    i.id,
    COALESCE(i.is_active, true) AS is_active,
    COALESCE(i.sales_price, 0) AS sales_price
  FROM public.items i
  WHERE i.company_id = p_company_id
    AND i.deleted_at IS NULL
    AND (
      p_search IS NULL
      OR p_search = ''
      OR i.item_code ILIKE ('%' || p_search || '%')
      OR i.item_name ILIKE ('%' || p_search || '%')
      OR COALESCE(i.item_name_cn, '') ILIKE ('%' || p_search || '%')
      OR EXISTS (
        SELECT 1
        FROM public.item_unit_options iuo
        WHERE iuo.company_id = i.company_id
          AND iuo.item_id = i.id
          AND iuo.deleted_at IS NULL
          AND COALESCE(iuo.barcode, '') ILIKE ('%' || p_search || '%')
      )
    )
    AND (p_category_id IS NULL OR i.category_id = p_category_id)
    AND (p_item_type IS NULL OR i.item_type = p_item_type)
),
warehouse_scope AS (
  SELECT
    iw.item_id,
    iw.available_stock AS available,
    iw.reorder_level,
    iw.max_quantity
  FROM public.item_warehouse iw
  INNER JOIN public.warehouses w ON w.id = iw.warehouse_id
  WHERE iw.company_id = p_company_id
    AND iw.deleted_at IS NULL
    AND w.deleted_at IS NULL
    AND (p_warehouse_id IS NULL OR iw.warehouse_id = p_warehouse_id)
    AND (
      p_warehouse_id IS NOT NULL
      OR p_business_unit_id IS NULL
      OR w.business_unit_id = p_business_unit_id
    )
),
stock_agg AS (
  SELECT
    ws.item_id,
    SUM(COALESCE(ws.available, 0)) AS available,
    MAX(COALESCE(ws.reorder_level, 0)) AS reorder_point,
    SUM(COALESCE(ws.max_quantity, 0)) AS max_stock_level
  FROM warehouse_scope ws
  GROUP BY ws.item_id
),
enriched AS (
  SELECT
    fi.id,
    fi.sales_price,
    CASE
      WHEN NOT fi.is_active THEN 'discontinued'
      WHEN COALESCE(sa.available, 0) <= 0 THEN 'out_of_stock'
      WHEN COALESCE(sa.reorder_point, 0) > 0
        AND COALESCE(sa.available, 0) <= COALESCE(sa.reorder_point, 0)
        THEN 'low_stock'
      WHEN COALESCE(sa.max_stock_level, 0) > 0
        AND COALESCE(sa.available, 0) > COALESCE(sa.max_stock_level, 0)
        THEN 'overstock'
      ELSE 'normal'
    END AS status,
    COALESCE(sa.available, 0) AS available
  FROM filtered_items fi
  LEFT JOIN stock_agg sa ON sa.item_id = fi.id
),
status_filtered AS (
  SELECT *
  FROM enriched e
  WHERE p_status IS NULL
    OR p_status = ''
    OR p_status = 'all'
    OR e.status = p_status
)
SELECT
  COALESCE(SUM(sf.available * sf.sales_price), 0) AS total_available_value,
  COUNT(*) FILTER (WHERE sf.status = 'low_stock') AS low_stock_count,
  COUNT(*) FILTER (WHERE sf.status = 'out_of_stock') AS out_of_stock_count,
  COUNT(*) AS total_count
FROM status_filtered sf;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260512140000_delivery_note_scan_receiving.sql
-- ============================================================================

-- ============================================================================
-- Migration: Delivery Note Scan Receiving
-- Description: Adds scan-audited receiving for internal delivery notes.
-- ============================================================================

BEGIN;

ALTER TABLE public.delivery_notes
  ADD COLUMN IF NOT EXISTS receiving_started_at TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS receiving_started_by UUID REFERENCES public.users(id),
  ADD COLUMN IF NOT EXISTS receiving_completed_at TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS receiving_completed_by UUID REFERENCES public.users(id),
  ADD COLUMN IF NOT EXISTS received_by UUID REFERENCES public.users(id),
  ADD COLUMN IF NOT EXISTS receiving_notes TEXT;

ALTER TABLE public.delivery_note_items
  ADD COLUMN IF NOT EXISTS received_qty NUMERIC(20, 4) NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS receiving_discrepancy_flag BOOLEAN NOT NULL DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS receiving_notes TEXT;

CREATE TABLE IF NOT EXISTS public.delivery_note_item_receiving_scans (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id UUID NOT NULL REFERENCES public.companies(id),
  business_unit_id UUID REFERENCES public.business_units(id),
  dn_id UUID NOT NULL REFERENCES public.delivery_notes(id) ON DELETE CASCADE,
  dn_item_id UUID NOT NULL REFERENCES public.delivery_note_items(id) ON DELETE CASCADE,
  item_id UUID NOT NULL REFERENCES public.items(id),
  item_unit_option_id UUID REFERENCES public.item_unit_options(id),
  uom_id UUID NOT NULL REFERENCES public.units_of_measure(id),
  box_id TEXT NOT NULL,
  qr_code TEXT NOT NULL,
  qr_qty NUMERIC(20, 4) NOT NULL,
  accepted_qty NUMERIC(20, 4) NOT NULL,
  adjustment_reason TEXT,
  notes TEXT,
  scanned_by UUID NOT NULL REFERENCES public.users(id),
  scanned_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  voided_at TIMESTAMPTZ,
  voided_by UUID REFERENCES public.users(id),
  void_reason TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT delivery_note_item_receiving_scans_qty_chk
    CHECK (qr_qty > 0 AND accepted_qty > 0),
  CONSTRAINT delivery_note_item_receiving_scans_adjustment_reason_chk
    CHECK (accepted_qty = qr_qty OR NULLIF(BTRIM(adjustment_reason), '') IS NOT NULL),
  CONSTRAINT delivery_note_item_receiving_scans_box_unique
    UNIQUE (company_id, dn_id, box_id)
);

CREATE TABLE IF NOT EXISTS public.delivery_note_receiving_exceptions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id UUID NOT NULL REFERENCES public.companies(id),
  business_unit_id UUID REFERENCES public.business_units(id),
  dn_id UUID NOT NULL REFERENCES public.delivery_notes(id) ON DELETE CASCADE,
  item_id UUID NOT NULL REFERENCES public.items(id),
  item_unit_option_id UUID REFERENCES public.item_unit_options(id),
  uom_id UUID NOT NULL REFERENCES public.units_of_measure(id),
  box_id TEXT NOT NULL,
  qr_code TEXT NOT NULL,
  qr_qty NUMERIC(20, 4) NOT NULL,
  accepted_qty NUMERIC(20, 4) NOT NULL,
  batch_number TEXT,
  location_id UUID REFERENCES public.warehouse_locations(id),
  reason TEXT,
  notes TEXT,
  status TEXT NOT NULL DEFAULT 'pending_review'
    CHECK (status IN ('pending_review', 'accepted', 'rejected', 'resolved')),
  scanned_by UUID NOT NULL REFERENCES public.users(id),
  scanned_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  reviewed_by UUID REFERENCES public.users(id),
  reviewed_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT delivery_note_receiving_exceptions_qty_chk
    CHECK (qr_qty > 0 AND accepted_qty > 0),
  CONSTRAINT delivery_note_receiving_exceptions_box_unique
    UNIQUE (company_id, dn_id, box_id)
);

CREATE INDEX IF NOT EXISTS idx_dn_receiving_status
  ON public.delivery_notes(status, requesting_warehouse_id, receiving_started_at)
  WHERE deleted_at IS NULL AND status IN ('dispatched', 'received');

CREATE INDEX IF NOT EXISTS idx_dn_receiving_scans_dn
  ON public.delivery_note_item_receiving_scans(company_id, dn_id, dn_item_id)
  WHERE voided_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_dn_receiving_exceptions_dn
  ON public.delivery_note_receiving_exceptions(company_id, dn_id, status);

CREATE OR REPLACE FUNCTION public.refresh_delivery_note_item_received_qty(
  p_company_id UUID,
  p_dn_item_id UUID
)
RETURNS NUMERIC
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_received_qty NUMERIC;
  v_dispatched_qty NUMERIC;
BEGIN
  SELECT COALESCE(SUM(accepted_qty), 0)
  INTO v_received_qty
  FROM public.delivery_note_item_receiving_scans
  WHERE company_id = p_company_id
    AND dn_item_id = p_dn_item_id
    AND voided_at IS NULL;

  SELECT COALESCE(dispatched_qty, 0)
  INTO v_dispatched_qty
  FROM public.delivery_note_items
  WHERE company_id = p_company_id
    AND id = p_dn_item_id;

  UPDATE public.delivery_note_items
  SET
    received_qty = v_received_qty,
    receiving_discrepancy_flag = v_received_qty <> COALESCE(v_dispatched_qty, 0),
    updated_at = now()
  WHERE company_id = p_company_id
    AND id = p_dn_item_id;

  RETURN v_received_qty;
END;
$$;

CREATE OR REPLACE FUNCTION public.record_delivery_note_receiving_scan(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_qr_code TEXT,
  p_box_id TEXT,
  p_item_id UUID,
  p_qr_qty NUMERIC,
  p_accepted_qty NUMERIC DEFAULT NULL,
  p_item_unit_option_id UUID DEFAULT NULL,
  p_adjustment_reason TEXT DEFAULT NULL,
  p_notes TEXT DEFAULT NULL,
  p_batch_number TEXT DEFAULT NULL,
  p_location_id UUID DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn public.delivery_notes%ROWTYPE;
  v_dn_item public.delivery_note_items%ROWTYPE;
  v_item public.items%ROWTYPE;
  v_item_unit_option_id UUID;
  v_uom_id UUID;
  v_match_count INTEGER;
  v_existing_received NUMERIC;
  v_next_received NUMERIC;
  v_accepted_qty NUMERIC;
  v_scan_id UUID;
  v_exception_id UUID;
BEGIN
  IF NULLIF(BTRIM(p_box_id), '') IS NULL THEN
    RAISE EXCEPTION 'Box ID is required';
  END IF;

  IF p_qr_qty IS NULL OR p_qr_qty <= 0 THEN
    RAISE EXCEPTION 'Scanned quantity must be greater than zero';
  END IF;

  v_accepted_qty := COALESCE(p_accepted_qty, p_qr_qty);
  IF v_accepted_qty <= 0 THEN
    RAISE EXCEPTION 'Accepted quantity must be greater than zero';
  END IF;

  IF v_accepted_qty <> p_qr_qty AND NULLIF(BTRIM(p_adjustment_reason), '') IS NULL THEN
    RAISE EXCEPTION 'Manual quantity adjustment requires a reason';
  END IF;

  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be received';
  END IF;

  SELECT *
  INTO v_item
  FROM public.items
  WHERE id = p_item_id
    AND company_id = p_company_id
    AND deleted_at IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Item not found';
  END IF;

  SELECT iuo.id, iuo.uom_id
  INTO v_item_unit_option_id, v_uom_id
  FROM public.item_unit_options iuo
  WHERE iuo.company_id = p_company_id
    AND iuo.item_id = p_item_id
    AND iuo.deleted_at IS NULL
    AND (
      (p_item_unit_option_id IS NOT NULL AND iuo.id = p_item_unit_option_id)
      OR (p_item_unit_option_id IS NULL AND iuo.is_default)
      OR (p_item_unit_option_id IS NULL AND iuo.is_base)
    )
  ORDER BY
    CASE
      WHEN p_item_unit_option_id IS NOT NULL AND iuo.id = p_item_unit_option_id THEN 0
      WHEN iuo.is_default THEN 1
      WHEN iuo.is_base THEN 2
      ELSE 3
    END,
    iuo.sort_order,
    iuo.created_at
  LIMIT 1;

  v_item_unit_option_id := COALESCE(v_item_unit_option_id, p_item_unit_option_id);
  v_uom_id := COALESCE(v_uom_id, v_item.uom_id);

  SELECT COUNT(*)
  INTO v_match_count
  FROM public.delivery_note_items dni
  WHERE dni.company_id = p_company_id
    AND dni.dn_id = p_dn_id
    AND dni.item_id = p_item_id
    AND COALESCE(dni.is_voided, FALSE) = FALSE
    AND (
      p_item_unit_option_id IS NULL
      OR dni.item_unit_option_id = p_item_unit_option_id
      OR dni.item_unit_option_id IS NULL
    );

  IF v_match_count > 1 AND p_item_unit_option_id IS NULL THEN
    RAISE EXCEPTION 'Multiple delivery note lines match this item. Scan a unit-specific barcode.';
  END IF;

  IF v_match_count > 0 THEN
    SELECT *
    INTO v_dn_item
    FROM public.delivery_note_items dni
    WHERE dni.company_id = p_company_id
      AND dni.dn_id = p_dn_id
      AND dni.item_id = p_item_id
      AND COALESCE(dni.is_voided, FALSE) = FALSE
      AND (
        p_item_unit_option_id IS NULL
        OR dni.item_unit_option_id = p_item_unit_option_id
        OR dni.item_unit_option_id IS NULL
      )
    ORDER BY dni.created_at, dni.id
    LIMIT 1
    FOR UPDATE;

    SELECT COALESCE(SUM(accepted_qty), 0)
    INTO v_existing_received
    FROM public.delivery_note_item_receiving_scans
    WHERE company_id = p_company_id
      AND dn_item_id = v_dn_item.id
      AND voided_at IS NULL;

    v_next_received := v_existing_received + v_accepted_qty;
    IF v_next_received > COALESCE(v_dn_item.dispatched_qty, 0) THEN
      RAISE EXCEPTION 'Expected item quantity would exceed dispatched quantity';
    END IF;

    IF v_dn.receiving_started_at IS NULL THEN
      UPDATE public.delivery_notes
      SET
        receiving_started_at = now(),
        receiving_started_by = p_user_id,
        updated_by = p_user_id,
        updated_at = now()
      WHERE id = p_dn_id
        AND company_id = p_company_id;
    END IF;

    INSERT INTO public.delivery_note_item_receiving_scans (
      company_id,
      business_unit_id,
      dn_id,
      dn_item_id,
      item_id,
      item_unit_option_id,
      uom_id,
      box_id,
      qr_code,
      qr_qty,
      accepted_qty,
      adjustment_reason,
      notes,
      scanned_by
    )
    VALUES (
      p_company_id,
      p_business_unit_id,
      p_dn_id,
      v_dn_item.id,
      p_item_id,
      COALESCE(v_dn_item.item_unit_option_id, v_item_unit_option_id),
      COALESCE(v_dn_item.uom_id, v_uom_id),
      BTRIM(p_box_id),
      COALESCE(p_qr_code, ''),
      p_qr_qty,
      v_accepted_qty,
      NULLIF(BTRIM(p_adjustment_reason), ''),
      NULLIF(BTRIM(p_notes), ''),
      p_user_id
    )
    RETURNING id INTO v_scan_id;

    PERFORM public.refresh_delivery_note_item_received_qty(p_company_id, v_dn_item.id);

    RETURN jsonb_build_object(
      'type', 'scan',
      'scanId', v_scan_id,
      'deliveryNoteItemId', v_dn_item.id,
      'isUnexpected', FALSE
    );
  END IF;

  IF v_dn.receiving_started_at IS NULL THEN
    UPDATE public.delivery_notes
    SET
      receiving_started_at = now(),
      receiving_started_by = p_user_id,
      updated_by = p_user_id,
      updated_at = now()
    WHERE id = p_dn_id
      AND company_id = p_company_id;
  END IF;

  INSERT INTO public.delivery_note_receiving_exceptions (
    company_id,
    business_unit_id,
    dn_id,
    item_id,
    item_unit_option_id,
    uom_id,
    box_id,
    qr_code,
    qr_qty,
    accepted_qty,
    batch_number,
    location_id,
    reason,
    notes,
    scanned_by
  )
  VALUES (
    p_company_id,
    p_business_unit_id,
    p_dn_id,
    p_item_id,
    v_item_unit_option_id,
    v_uom_id,
    BTRIM(p_box_id),
    COALESCE(p_qr_code, ''),
    p_qr_qty,
    v_accepted_qty,
    NULLIF(BTRIM(p_batch_number), ''),
    p_location_id,
    'Item scanned during receiving but not found in the delivery note',
    NULLIF(BTRIM(p_notes), ''),
    p_user_id
  )
  RETURNING id INTO v_exception_id;

  RETURN jsonb_build_object(
    'type', 'exception',
    'exceptionId', v_exception_id,
    'isUnexpected', TRUE
  );
END;
$$;

CREATE OR REPLACE FUNCTION public.void_delivery_note_receiving_scan(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_scan_id UUID,
  p_reason TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_scan public.delivery_note_item_receiving_scans%ROWTYPE;
  v_dn public.delivery_notes%ROWTYPE;
BEGIN
  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only in-progress dispatched delivery notes can have scans voided';
  END IF;

  SELECT *
  INTO v_scan
  FROM public.delivery_note_item_receiving_scans
  WHERE id = p_scan_id
    AND company_id = p_company_id
    AND dn_id = p_dn_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Receiving scan not found';
  END IF;

  IF v_scan.voided_at IS NOT NULL THEN
    RETURN;
  END IF;

  UPDATE public.delivery_note_item_receiving_scans
  SET
    voided_at = now(),
    voided_by = p_user_id,
    void_reason = NULLIF(BTRIM(p_reason), ''),
    updated_at = now()
  WHERE id = p_scan_id;

  PERFORM public.refresh_delivery_note_item_received_qty(p_company_id, v_scan.dn_item_id);
END;
$$;

CREATE OR REPLACE FUNCTION public.submit_delivery_note_receiving(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_received_date DATE DEFAULT NULL,
  p_notes TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn public.delivery_notes%ROWTYPE;
  v_item RECORD;
  v_items JSONB := '[]'::jsonb;
  v_has_received BOOLEAN := FALSE;
BEGIN
  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be submitted for receiving';
  END IF;

  IF v_dn.receiving_started_at IS NULL THEN
    RAISE EXCEPTION 'Receiving has not been started';
  END IF;

  FOR v_item IN
    SELECT
      dni.id,
      COALESCE(SUM(scans.accepted_qty) FILTER (WHERE scans.voided_at IS NULL), 0) AS received_qty
    FROM public.delivery_note_items dni
    LEFT JOIN public.delivery_note_item_receiving_scans scans
      ON scans.company_id = dni.company_id
     AND scans.dn_item_id = dni.id
    WHERE dni.company_id = p_company_id
      AND dni.dn_id = p_dn_id
      AND COALESCE(dni.is_voided, FALSE) = FALSE
    GROUP BY dni.id
    ORDER BY dni.id
  LOOP
    PERFORM public.refresh_delivery_note_item_received_qty(p_company_id, v_item.id);

    IF v_item.received_qty > 0 THEN
      v_has_received := TRUE;
      v_items := v_items || jsonb_build_array(
        jsonb_build_object(
          'deliveryNoteItemId', v_item.id,
          'receivedQty', v_item.received_qty,
          'locationId', NULL
        )
      );
    END IF;
  END LOOP;

  IF NOT v_has_received THEN
    RAISE EXCEPTION 'No receiving scans have been recorded';
  END IF;

  PERFORM public.post_delivery_note_receive(
    p_company_id,
    p_user_id,
    p_dn_id,
    p_business_unit_id,
    COALESCE(p_received_date, now()::DATE),
    p_notes,
    v_items
  );

  UPDATE public.delivery_notes
  SET
    receiving_completed_at = now(),
    receiving_completed_by = p_user_id,
    received_by = p_user_id,
    receiving_notes = COALESCE(NULLIF(BTRIM(p_notes), ''), receiving_notes),
    updated_by = p_user_id,
    updated_at = now()
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260512152000_add_suggested_batch_location_sku_to_delivery_note_items.sql
-- ============================================================================

-- ============================================================================
-- Migration: Add Suggested Batch Location SKU to Delivery Note Items
-- Description: Persists the selected item_location_batch.batch_location_sku
--              alongside DN pick source suggestions.
-- ============================================================================

BEGIN;

DROP TRIGGER IF EXISTS trigger_delivery_note_items_set_qr_code ON public.delivery_note_items;
DROP FUNCTION IF EXISTS public.set_delivery_note_item_qr_code();

ALTER TABLE public.delivery_note_items
  ADD COLUMN IF NOT EXISTS suggested_batch_location_sku TEXT;

ALTER TABLE public.delivery_note_items
  DROP COLUMN IF EXISTS qr_code;

COMMENT ON COLUMN public.delivery_note_items.suggested_batch_location_sku IS
  'Persisted item_location_batch.batch_location_sku for the suggested or picker-selected source.';

CREATE INDEX IF NOT EXISTS idx_delivery_note_items_suggested_batch_location_sku
  ON public.delivery_note_items(company_id, dn_id, suggested_batch_location_sku)
  WHERE suggested_batch_location_sku IS NOT NULL;

DROP INDEX IF EXISTS public.idx_delivery_note_items_qr_code;

CREATE OR REPLACE FUNCTION public.reserve_delivery_note_inventory(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY INVOKER
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dni delivery_note_items%ROWTYPE;
  v_wh item_warehouse%ROWTYPE;
  v_available NUMERIC;
  v_suggested_pick_location_id UUID;
  v_suggested_pick_batch_code TEXT;
  v_suggested_pick_batch_received_at TIMESTAMP;
  v_suggested_batch_location_sku TEXT;
  v_total_allocated NUMERIC := 0;
  v_qty_per_unit NUMERIC := 1;
  v_allocated_base_qty NUMERIC := 0;
BEGIN
  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'draft' THEN
    RAISE EXCEPTION 'Inventory reservation only allowed while delivery note is in draft status';
  END IF;

  FOR v_dni IN
    SELECT *
    FROM delivery_note_items
    WHERE company_id = p_company_id
      AND dn_id = p_dn_id
    ORDER BY created_at ASC, id ASC
    FOR UPDATE
  LOOP
    IF v_dni.item_unit_option_id IS NOT NULL THEN
      SELECT COALESCE(qty_per_unit, 1)
      INTO v_qty_per_unit
      FROM public.item_unit_options
      WHERE id = v_dni.item_unit_option_id
        AND deleted_at IS NULL;
    ELSE
      v_qty_per_unit := 1;
    END IF;

    v_allocated_base_qty := COALESCE(v_dni.allocated_qty, 0) * COALESCE(v_qty_per_unit, 1);
    v_total_allocated := v_total_allocated + v_allocated_base_qty;

    SELECT *
    INTO v_wh
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_dni.item_id
      AND warehouse_id = v_dni.fulfilling_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Insufficient stock for item % in warehouse %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id;
    END IF;

    v_available := GREATEST(0, COALESCE(v_wh.current_stock, 0) - COALESCE(v_wh.reserved_stock, 0));
    IF v_available < v_allocated_base_qty THEN
      RAISE EXCEPTION 'Insufficient available stock for item % in warehouse %. Available %, requested %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id, v_available, v_allocated_base_qty;
    END IF;

    UPDATE item_warehouse
    SET
      reserved_stock = COALESCE(reserved_stock, 0) + v_allocated_base_qty,
      updated_by = p_user_id,
      updated_at = NOW()
    WHERE id = v_wh.id;

    v_suggested_pick_location_id := NULL;
    v_suggested_pick_batch_code := NULL;
    v_suggested_pick_batch_received_at := NULL;
    v_suggested_batch_location_sku := NULL;

    SELECT
      ilb.location_id,
      ib.batch_code,
      ib.received_at,
      ilb.batch_location_sku
    INTO
      v_suggested_pick_location_id,
      v_suggested_pick_batch_code,
      v_suggested_pick_batch_received_at,
      v_suggested_batch_location_sku
    FROM item_location_batch ilb
    JOIN item_batch ib
      ON ib.id = ilb.item_batch_id
     AND ib.company_id = ilb.company_id
     AND ib.deleted_at IS NULL
    WHERE ilb.company_id = p_company_id
      AND ilb.item_id = v_dni.item_id
      AND ilb.warehouse_id = v_dni.fulfilling_warehouse_id
      AND ilb.deleted_at IS NULL
      AND GREATEST(0, COALESCE(ilb.qty_on_hand, 0) - COALESCE(ilb.qty_reserved, 0)) > 0
    ORDER BY ib.received_at ASC, ilb.created_at ASC, ilb.id ASC
    LIMIT 1;

    UPDATE delivery_note_items
    SET
      suggested_pick_location_id = COALESCE(v_suggested_pick_location_id, suggested_pick_location_id),
      suggested_pick_batch_code = COALESCE(v_suggested_pick_batch_code, suggested_pick_batch_code),
      suggested_pick_batch_received_at = COALESCE(v_suggested_pick_batch_received_at, suggested_pick_batch_received_at),
      suggested_batch_location_sku = COALESCE(v_suggested_batch_location_sku, suggested_batch_location_sku),
      updated_at = NOW()
    WHERE id = v_dni.id
      AND company_id = p_company_id;
  END LOOP;

  IF v_total_allocated <= 0 THEN
    RAISE EXCEPTION 'Delivery note has no allocatable line quantities';
  END IF;
END;
$$;

CREATE OR REPLACE FUNCTION public.reserve_delivery_note_inventory_lines(
  p_company_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_line_ids UUID[]
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn delivery_notes%ROWTYPE;
  v_dni delivery_note_items%ROWTYPE;
  v_wh item_warehouse%ROWTYPE;
  v_available NUMERIC;
  v_suggested_pick_location_id UUID;
  v_suggested_pick_batch_code TEXT;
  v_suggested_pick_batch_received_at TIMESTAMP;
  v_suggested_batch_location_sku TEXT;
  v_qty_per_unit NUMERIC := 1;
  v_allocated_base_qty NUMERIC := 0;
BEGIN
  IF COALESCE(array_length(p_line_ids, 1), 0) = 0 THEN
    RAISE EXCEPTION 'At least one delivery note line id is required';
  END IF;

  SELECT *
  INTO v_dn
  FROM delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status IN ('received', 'voided') THEN
    RAISE EXCEPTION 'Cannot reserve delivery note lines for received or voided delivery notes';
  END IF;

  FOR v_dni IN
    SELECT *
    FROM delivery_note_items
    WHERE company_id = p_company_id
      AND dn_id = p_dn_id
      AND id = ANY(p_line_ids)
    ORDER BY created_at ASC, id ASC
    FOR UPDATE
  LOOP
    IF COALESCE(v_dni.is_voided, FALSE) THEN
      RAISE EXCEPTION 'Cannot reserve inventory for voided delivery note line %', v_dni.id;
    END IF;

    IF v_dni.item_unit_option_id IS NOT NULL THEN
      SELECT COALESCE(qty_per_unit, 1)
      INTO v_qty_per_unit
      FROM public.item_unit_options
      WHERE id = v_dni.item_unit_option_id
        AND deleted_at IS NULL;
    ELSE
      v_qty_per_unit := 1;
    END IF;

    v_allocated_base_qty := COALESCE(v_dni.allocated_qty, 0) * COALESCE(v_qty_per_unit, 1);

    SELECT *
    INTO v_wh
    FROM item_warehouse
    WHERE company_id = p_company_id
      AND item_id = v_dni.item_id
      AND warehouse_id = v_dni.fulfilling_warehouse_id
      AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Insufficient stock for item % in warehouse %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id;
    END IF;

    v_available := GREATEST(0, COALESCE(v_wh.current_stock, 0) - COALESCE(v_wh.reserved_stock, 0));
    IF v_available < v_allocated_base_qty THEN
      RAISE EXCEPTION 'Insufficient available stock for item % in warehouse %. Available %, requested %',
        v_dni.item_id, v_dni.fulfilling_warehouse_id, v_available, v_allocated_base_qty;
    END IF;

    UPDATE item_warehouse
    SET
      reserved_stock = COALESCE(reserved_stock, 0) + v_allocated_base_qty,
      updated_by = p_user_id,
      updated_at = NOW()
    WHERE id = v_wh.id;

    v_suggested_pick_location_id := NULL;
    v_suggested_pick_batch_code := NULL;
    v_suggested_pick_batch_received_at := NULL;
    v_suggested_batch_location_sku := NULL;

    SELECT
      ilb.location_id,
      ib.batch_code,
      ib.received_at,
      ilb.batch_location_sku
    INTO
      v_suggested_pick_location_id,
      v_suggested_pick_batch_code,
      v_suggested_pick_batch_received_at,
      v_suggested_batch_location_sku
    FROM item_location_batch ilb
    JOIN item_batch ib
      ON ib.id = ilb.item_batch_id
     AND ib.company_id = ilb.company_id
     AND ib.deleted_at IS NULL
    WHERE ilb.company_id = p_company_id
      AND ilb.item_id = v_dni.item_id
      AND ilb.warehouse_id = v_dni.fulfilling_warehouse_id
      AND ilb.deleted_at IS NULL
      AND GREATEST(0, COALESCE(ilb.qty_on_hand, 0) - COALESCE(ilb.qty_reserved, 0)) > 0
    ORDER BY ib.received_at ASC, ilb.created_at ASC, ilb.id ASC
    LIMIT 1;

    UPDATE delivery_note_items
    SET
      suggested_pick_location_id = COALESCE(v_suggested_pick_location_id, suggested_pick_location_id),
      suggested_pick_batch_code = COALESCE(v_suggested_pick_batch_code, suggested_pick_batch_code),
      suggested_pick_batch_received_at = COALESCE(v_suggested_pick_batch_received_at, suggested_pick_batch_received_at),
      suggested_batch_location_sku = COALESCE(v_suggested_batch_location_sku, suggested_batch_location_sku),
      updated_at = NOW()
    WHERE id = v_dni.id
      AND company_id = p_company_id;
  END LOOP;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260513100000_generate_stock_requisition_number_in_db.sql
-- ============================================================================

-- ============================================================================
-- Migration: Generate stock requisition numbers in the database
-- Description:
--   - Moves stock_requisitions.sr_number generation to the shared document code
--     trigger pattern.
--   - Keeps stock requisitions on their own sequence namespace instead of
--     sharing the stock_requests SR sequence.
-- ============================================================================

DROP TRIGGER IF EXISTS trigger_generate_stock_requisition_number ON public.stock_requisitions;
CREATE TRIGGER trigger_generate_stock_requisition_number
  BEFORE INSERT ON public.stock_requisitions
  FOR EACH ROW
  EXECUTE FUNCTION public.apply_generated_document_code('sr_number', 'SRQ', '9');

COMMENT ON TRIGGER trigger_generate_stock_requisition_number ON public.stock_requisitions IS
  'Assigns sr_number from the shared company-scoped document code generator.';

COMMENT ON COLUMN public.stock_requisitions.sr_number IS
  'Database-generated stock requisition number assigned by trigger_generate_stock_requisition_number.';


-- ============================================================================
-- Migration: 20260513103000_count_delivery_note_receiving_scans_as_one.sql
-- ============================================================================

-- ============================================================================
-- Migration: Count delivery note receiving scans as one item each
-- Description:
--   - Treats QR quantity as informational metadata only.
--   - Counts every valid, non-voided expected scan as one received item.
--   - Allows over-receiving scans and flags the DN line as discrepant instead of
--     blocking the scan.
-- ============================================================================

BEGIN;

ALTER TABLE public.delivery_note_item_receiving_scans
  DROP CONSTRAINT IF EXISTS delivery_note_item_receiving_scans_adjustment_reason_chk;

CREATE OR REPLACE FUNCTION public.refresh_delivery_note_item_received_qty(
  p_company_id UUID,
  p_dn_item_id UUID
)
RETURNS NUMERIC
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_received_qty NUMERIC;
  v_dispatched_qty NUMERIC;
BEGIN
  SELECT COALESCE(COUNT(*), 0)::NUMERIC
  INTO v_received_qty
  FROM public.delivery_note_item_receiving_scans
  WHERE company_id = p_company_id
    AND dn_item_id = p_dn_item_id
    AND voided_at IS NULL;

  SELECT COALESCE(dispatched_qty, 0)
  INTO v_dispatched_qty
  FROM public.delivery_note_items
  WHERE company_id = p_company_id
    AND id = p_dn_item_id;

  UPDATE public.delivery_note_items
  SET
    received_qty = v_received_qty,
    receiving_discrepancy_flag = v_received_qty <> COALESCE(v_dispatched_qty, 0),
    updated_at = now()
  WHERE company_id = p_company_id
    AND id = p_dn_item_id;

  RETURN v_received_qty;
END;
$$;

CREATE OR REPLACE FUNCTION public.record_delivery_note_receiving_scan(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_qr_code TEXT,
  p_box_id TEXT,
  p_item_id UUID,
  p_qr_qty NUMERIC,
  p_accepted_qty NUMERIC DEFAULT NULL,
  p_item_unit_option_id UUID DEFAULT NULL,
  p_adjustment_reason TEXT DEFAULT NULL,
  p_notes TEXT DEFAULT NULL,
  p_batch_number TEXT DEFAULT NULL,
  p_location_id UUID DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn public.delivery_notes%ROWTYPE;
  v_dn_item public.delivery_note_items%ROWTYPE;
  v_item public.items%ROWTYPE;
  v_item_unit_option_id UUID;
  v_uom_id UUID;
  v_match_count INTEGER;
  v_existing_scan_count NUMERIC;
  v_next_scan_count NUMERIC;
  v_accepted_qty NUMERIC := 1;
  v_scan_id UUID;
  v_exception_id UUID;
  v_notes TEXT;
  v_adjustment_reason TEXT;
  v_is_over_received BOOLEAN := FALSE;
BEGIN
  IF NULLIF(BTRIM(p_box_id), '') IS NULL THEN
    RAISE EXCEPTION 'Box ID is required';
  END IF;

  IF p_qr_qty IS NULL OR p_qr_qty <= 0 THEN
    RAISE EXCEPTION 'Scanned quantity must be greater than zero';
  END IF;

  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be received';
  END IF;

  SELECT *
  INTO v_item
  FROM public.items
  WHERE id = p_item_id
    AND company_id = p_company_id
    AND deleted_at IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Item not found';
  END IF;

  SELECT iuo.id, iuo.uom_id
  INTO v_item_unit_option_id, v_uom_id
  FROM public.item_unit_options iuo
  WHERE iuo.company_id = p_company_id
    AND iuo.item_id = p_item_id
    AND iuo.deleted_at IS NULL
    AND (
      (p_item_unit_option_id IS NOT NULL AND iuo.id = p_item_unit_option_id)
      OR (p_item_unit_option_id IS NULL AND iuo.is_default)
      OR (p_item_unit_option_id IS NULL AND iuo.is_base)
    )
  ORDER BY
    CASE
      WHEN p_item_unit_option_id IS NOT NULL AND iuo.id = p_item_unit_option_id THEN 0
      WHEN iuo.is_default THEN 1
      WHEN iuo.is_base THEN 2
      ELSE 3
    END,
    iuo.sort_order,
    iuo.created_at
  LIMIT 1;

  v_item_unit_option_id := COALESCE(v_item_unit_option_id, p_item_unit_option_id);
  v_uom_id := COALESCE(v_uom_id, v_item.uom_id);

  SELECT COUNT(*)
  INTO v_match_count
  FROM public.delivery_note_items dni
  WHERE dni.company_id = p_company_id
    AND dni.dn_id = p_dn_id
    AND dni.item_id = p_item_id
    AND COALESCE(dni.is_voided, FALSE) = FALSE
    AND (
      p_item_unit_option_id IS NULL
      OR dni.item_unit_option_id = p_item_unit_option_id
      OR dni.item_unit_option_id IS NULL
    );

  IF v_match_count > 1 AND p_item_unit_option_id IS NULL THEN
    RAISE EXCEPTION 'Multiple delivery note lines match this item. Scan a unit-specific barcode.';
  END IF;

  IF v_match_count > 0 THEN
    SELECT *
    INTO v_dn_item
    FROM public.delivery_note_items dni
    WHERE dni.company_id = p_company_id
      AND dni.dn_id = p_dn_id
      AND dni.item_id = p_item_id
      AND COALESCE(dni.is_voided, FALSE) = FALSE
      AND (
        p_item_unit_option_id IS NULL
        OR dni.item_unit_option_id = p_item_unit_option_id
        OR dni.item_unit_option_id IS NULL
      )
    ORDER BY dni.created_at, dni.id
    LIMIT 1
    FOR UPDATE;

    SELECT COALESCE(COUNT(*), 0)::NUMERIC
    INTO v_existing_scan_count
    FROM public.delivery_note_item_receiving_scans
    WHERE company_id = p_company_id
      AND dn_item_id = v_dn_item.id
      AND voided_at IS NULL;

    v_next_scan_count := v_existing_scan_count + 1;
    v_is_over_received := v_next_scan_count > COALESCE(v_dn_item.dispatched_qty, 0);
    v_notes := NULLIF(BTRIM(p_notes), '');
    v_adjustment_reason := NULLIF(BTRIM(p_adjustment_reason), '');

    IF v_is_over_received THEN
      v_adjustment_reason := COALESCE(v_adjustment_reason, 'Over-received scan recorded');
      v_notes := CONCAT_WS(
        E'\n',
        v_notes,
        FORMAT(
          'Over-received scan: scan count %s exceeds dispatched quantity %s.',
          v_next_scan_count,
          COALESCE(v_dn_item.dispatched_qty, 0)
        )
      );
    END IF;

    IF v_dn.receiving_started_at IS NULL THEN
      UPDATE public.delivery_notes
      SET
        receiving_started_at = now(),
        receiving_started_by = p_user_id,
        updated_by = p_user_id,
        updated_at = now()
      WHERE id = p_dn_id
        AND company_id = p_company_id;
    END IF;

    INSERT INTO public.delivery_note_item_receiving_scans (
      company_id,
      business_unit_id,
      dn_id,
      dn_item_id,
      item_id,
      item_unit_option_id,
      uom_id,
      box_id,
      qr_code,
      qr_qty,
      accepted_qty,
      adjustment_reason,
      notes,
      scanned_by
    )
    VALUES (
      p_company_id,
      p_business_unit_id,
      p_dn_id,
      v_dn_item.id,
      p_item_id,
      COALESCE(v_dn_item.item_unit_option_id, v_item_unit_option_id),
      COALESCE(v_dn_item.uom_id, v_uom_id),
      BTRIM(p_box_id),
      COALESCE(p_qr_code, ''),
      p_qr_qty,
      v_accepted_qty,
      v_adjustment_reason,
      v_notes,
      p_user_id
    )
    RETURNING id INTO v_scan_id;

    PERFORM public.refresh_delivery_note_item_received_qty(p_company_id, v_dn_item.id);

    RETURN jsonb_build_object(
      'type', 'scan',
      'scanId', v_scan_id,
      'deliveryNoteItemId', v_dn_item.id,
      'isUnexpected', FALSE,
      'isOverReceived', v_is_over_received
    );
  END IF;

  IF v_dn.receiving_started_at IS NULL THEN
    UPDATE public.delivery_notes
    SET
      receiving_started_at = now(),
      receiving_started_by = p_user_id,
      updated_by = p_user_id,
      updated_at = now()
    WHERE id = p_dn_id
      AND company_id = p_company_id;
  END IF;

  INSERT INTO public.delivery_note_receiving_exceptions (
    company_id,
    business_unit_id,
    dn_id,
    item_id,
    item_unit_option_id,
    uom_id,
    box_id,
    qr_code,
    qr_qty,
    accepted_qty,
    batch_number,
    location_id,
    reason,
    notes,
    scanned_by
  )
  VALUES (
    p_company_id,
    p_business_unit_id,
    p_dn_id,
    p_item_id,
    v_item_unit_option_id,
    v_uom_id,
    BTRIM(p_box_id),
    COALESCE(p_qr_code, ''),
    p_qr_qty,
    v_accepted_qty,
    NULLIF(BTRIM(p_batch_number), ''),
    p_location_id,
    'Item scanned during receiving but not found in the delivery note',
    NULLIF(BTRIM(p_notes), ''),
    p_user_id
  )
  RETURNING id INTO v_exception_id;

  RETURN jsonb_build_object(
    'type', 'exception',
    'exceptionId', v_exception_id,
    'isUnexpected', TRUE
  );
END;
$$;

CREATE OR REPLACE FUNCTION public.submit_delivery_note_receiving(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_received_date DATE DEFAULT NULL,
  p_notes TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn public.delivery_notes%ROWTYPE;
  v_item RECORD;
  v_items JSONB := '[]'::jsonb;
  v_has_postable_received_qty BOOLEAN := FALSE;
BEGIN
  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be submitted for receiving';
  END IF;

  IF v_dn.receiving_started_at IS NULL THEN
    RAISE EXCEPTION 'Receiving has not been started';
  END IF;

  FOR v_item IN
    SELECT
      dni.id,
      COALESCE(dni.dispatched_qty, 0) AS dispatched_qty,
      COALESCE(COUNT(scans.id) FILTER (WHERE scans.voided_at IS NULL), 0)::NUMERIC AS received_scan_count,
      LEAST(
        COALESCE(COUNT(scans.id) FILTER (WHERE scans.voided_at IS NULL), 0)::NUMERIC,
        COALESCE(dni.dispatched_qty, 0)
      ) AS post_received_qty
    FROM public.delivery_note_items dni
    LEFT JOIN public.delivery_note_item_receiving_scans scans
      ON scans.company_id = dni.company_id
     AND scans.dn_item_id = dni.id
    WHERE dni.company_id = p_company_id
      AND dni.dn_id = p_dn_id
      AND COALESCE(dni.is_voided, FALSE) = FALSE
    GROUP BY dni.id, dni.dispatched_qty
    ORDER BY dni.id
  LOOP
    PERFORM public.refresh_delivery_note_item_received_qty(p_company_id, v_item.id);

    IF v_item.received_scan_count > 0 AND v_item.post_received_qty > 0 THEN
      v_has_postable_received_qty := TRUE;
      v_items := v_items || jsonb_build_array(
        jsonb_build_object(
          'deliveryNoteItemId', v_item.id,
          'receivedQty', v_item.post_received_qty,
          'locationId', NULL
        )
      );
    END IF;
  END LOOP;

  IF NOT v_has_postable_received_qty THEN
    RAISE EXCEPTION 'No receiving scans have been recorded';
  END IF;

  PERFORM public.post_delivery_note_receive(
    p_company_id,
    p_user_id,
    p_dn_id,
    p_business_unit_id,
    COALESCE(p_received_date, now()::DATE),
    p_notes,
    v_items
  );

  UPDATE public.delivery_notes
  SET
    receiving_completed_at = now(),
    receiving_completed_by = p_user_id,
    received_by = p_user_id,
    receiving_notes = COALESCE(NULLIF(BTRIM(p_notes), ''), receiving_notes),
    updated_by = p_user_id,
    updated_at = now()
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260513110000_allow_repeated_delivery_note_receiving_scans.sql
-- ============================================================================

-- ============================================================================
-- Migration: Allow repeated delivery note receiving scans
-- Description:
--   - Receiving now counts one valid scan as one received item.
--   - The same physical box/QR may be scanned multiple times when the box
--     contains multiple item quantities, so box_id cannot be unique per DN.
-- ============================================================================

ALTER TABLE public.delivery_note_item_receiving_scans
  DROP CONSTRAINT IF EXISTS delivery_note_item_receiving_scans_box_unique;

ALTER TABLE public.delivery_note_receiving_exceptions
  DROP CONSTRAINT IF EXISTS delivery_note_receiving_exceptions_box_unique;


-- ============================================================================
-- Migration: 20260513113000_delivery_note_receiving_variance_workflow.sql
-- ============================================================================

-- ============================================================================
-- Migration: Delivery note receiving variance workflow
-- Description:
--   - Stores exact/short/over receiving variance on delivery note lines.
--   - Requires discrepancy acknowledgement before final receiving submit.
--   - Posts stock only for the approved receivable quantity while keeping scan
--     count and variance visible for audit.
-- ============================================================================

BEGIN;

ALTER TABLE public.delivery_notes
  ADD COLUMN IF NOT EXISTS receiving_has_discrepancy BOOLEAN NOT NULL DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS receiving_discrepancy_notes TEXT;

ALTER TABLE public.delivery_note_items
  ADD COLUMN IF NOT EXISTS receiving_variance_qty NUMERIC(20, 4) NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS receiving_status TEXT NOT NULL DEFAULT 'pending';

ALTER TABLE public.delivery_note_items
  DROP CONSTRAINT IF EXISTS chk_delivery_note_items_receiving_status,
  ADD CONSTRAINT chk_delivery_note_items_receiving_status
    CHECK (receiving_status IN ('pending', 'exact', 'short', 'over'));

CREATE OR REPLACE FUNCTION public.refresh_delivery_note_item_received_qty(
  p_company_id UUID,
  p_dn_item_id UUID
)
RETURNS NUMERIC
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_received_qty NUMERIC;
  v_dispatched_qty NUMERIC;
  v_variance_qty NUMERIC;
  v_receiving_status TEXT;
BEGIN
  SELECT COALESCE(COUNT(*), 0)::NUMERIC
  INTO v_received_qty
  FROM public.delivery_note_item_receiving_scans
  WHERE company_id = p_company_id
    AND dn_item_id = p_dn_item_id
    AND voided_at IS NULL;

  SELECT COALESCE(dispatched_qty, 0)
  INTO v_dispatched_qty
  FROM public.delivery_note_items
  WHERE company_id = p_company_id
    AND id = p_dn_item_id;

  v_variance_qty := v_received_qty - COALESCE(v_dispatched_qty, 0);
  v_receiving_status := CASE
    WHEN v_received_qty = 0 THEN 'pending'
    WHEN v_variance_qty = 0 THEN 'exact'
    WHEN v_variance_qty < 0 THEN 'short'
    ELSE 'over'
  END;

  UPDATE public.delivery_note_items
  SET
    received_qty = v_received_qty,
    receiving_variance_qty = v_variance_qty,
    receiving_status = v_receiving_status,
    receiving_discrepancy_flag = v_variance_qty <> 0,
    updated_at = now()
  WHERE company_id = p_company_id
    AND id = p_dn_item_id;

  RETURN v_received_qty;
END;
$$;

CREATE OR REPLACE FUNCTION public.submit_delivery_note_receiving(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_received_date DATE DEFAULT NULL,
  p_notes TEXT DEFAULT NULL,
  p_acknowledge_discrepancy BOOLEAN DEFAULT FALSE,
  p_discrepancy_notes TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn public.delivery_notes%ROWTYPE;
  v_item RECORD;
  v_items JSONB := '[]'::jsonb;
  v_has_postable_received_qty BOOLEAN := FALSE;
  v_has_any_scan BOOLEAN := FALSE;
  v_has_discrepancy BOOLEAN := FALSE;
  v_discrepancy_notes TEXT := NULLIF(BTRIM(p_discrepancy_notes), '');
  v_line_note TEXT;
  v_line_status TEXT;
  v_line_variance NUMERIC;
BEGIN
  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be submitted for receiving';
  END IF;

  IF v_dn.receiving_started_at IS NULL THEN
    RAISE EXCEPTION 'Receiving has not been started';
  END IF;

  FOR v_item IN
    SELECT
      dni.id,
      COALESCE(dni.dispatched_qty, 0) AS dispatched_qty,
      COALESCE(COUNT(scans.id) FILTER (WHERE scans.voided_at IS NULL), 0)::NUMERIC AS received_scan_count,
      LEAST(
        COALESCE(COUNT(scans.id) FILTER (WHERE scans.voided_at IS NULL), 0)::NUMERIC,
        COALESCE(dni.dispatched_qty, 0)
      ) AS post_received_qty
    FROM public.delivery_note_items dni
    LEFT JOIN public.delivery_note_item_receiving_scans scans
      ON scans.company_id = dni.company_id
     AND scans.dn_item_id = dni.id
    WHERE dni.company_id = p_company_id
      AND dni.dn_id = p_dn_id
      AND COALESCE(dni.is_voided, FALSE) = FALSE
    GROUP BY dni.id, dni.dispatched_qty
    ORDER BY dni.id
  LOOP
    v_line_variance := v_item.received_scan_count - v_item.dispatched_qty;
    v_line_status := CASE
      WHEN v_line_variance = 0 THEN 'exact'
      WHEN v_line_variance < 0 THEN 'short'
      ELSE 'over'
    END;
    v_line_note := CASE
      WHEN v_line_variance = 0 THEN
        FORMAT('Exact receive: scanned %s of %s.', v_item.received_scan_count, v_item.dispatched_qty)
      WHEN v_line_variance < 0 THEN
        FORMAT(
          'Short receive: scanned %s of %s. Short %s.',
          v_item.received_scan_count,
          v_item.dispatched_qty,
          ABS(v_line_variance)
        )
      ELSE
        FORMAT(
          'Over receive: scanned %s of %s. Over %s.',
          v_item.received_scan_count,
          v_item.dispatched_qty,
          v_line_variance
        )
    END;

    v_has_any_scan := v_has_any_scan OR v_item.received_scan_count > 0;
    v_has_discrepancy := v_has_discrepancy OR v_line_variance <> 0;

    UPDATE public.delivery_note_items
    SET
      received_qty = v_item.received_scan_count,
      receiving_variance_qty = v_line_variance,
      receiving_status = v_line_status,
      receiving_discrepancy_flag = v_line_variance <> 0,
      receiving_notes = CONCAT_WS(E'\n', v_line_note, v_discrepancy_notes),
      updated_at = now()
    WHERE company_id = p_company_id
      AND id = v_item.id;

    IF v_item.post_received_qty > 0 THEN
      v_has_postable_received_qty := TRUE;
      v_items := v_items || jsonb_build_array(
        jsonb_build_object(
          'deliveryNoteItemId', v_item.id,
          'receivedQty', v_item.post_received_qty,
          'locationId', NULL
        )
      );
    END IF;
  END LOOP;

  IF NOT v_has_any_scan THEN
    RAISE EXCEPTION 'No receiving scans have been recorded';
  END IF;

  IF v_has_discrepancy AND NOT COALESCE(p_acknowledge_discrepancy, FALSE) THEN
    RAISE EXCEPTION 'Receiving discrepancy acknowledgement is required';
  END IF;

  IF v_has_discrepancy AND v_discrepancy_notes IS NULL THEN
    RAISE EXCEPTION 'Receiving discrepancy notes are required';
  END IF;

  IF NOT v_has_postable_received_qty THEN
    RAISE EXCEPTION 'No receiving scans have been recorded';
  END IF;

  PERFORM public.post_delivery_note_receive(
    p_company_id,
    p_user_id,
    p_dn_id,
    p_business_unit_id,
    COALESCE(p_received_date, now()::DATE),
    p_notes,
    v_items
  );

  UPDATE public.delivery_notes
  SET
    receiving_completed_at = now(),
    receiving_completed_by = p_user_id,
    received_by = p_user_id,
    receiving_notes = COALESCE(NULLIF(BTRIM(p_notes), ''), receiving_notes),
    receiving_has_discrepancy = v_has_discrepancy,
    receiving_discrepancy_notes = CASE
      WHEN v_has_discrepancy THEN v_discrepancy_notes
      ELSE receiving_discrepancy_notes
    END,
    updated_by = p_user_id,
    updated_at = now()
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260514110000_add_delivery_note_receiving_exception_review.sql
-- ============================================================================

-- ============================================================================
-- Migration: Delivery note receiving exception review
-- Description:
--   Adds explicit review actions for unexpected delivery note receiving scans.
--   Accepted exceptions post stock through a separate inventory transaction.
--   Rejected exceptions create no stock movement.
-- ============================================================================

BEGIN;

CREATE OR REPLACE FUNCTION public.reject_delivery_note_receiving_exception(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_exception_id UUID,
  p_notes TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_exception public.delivery_note_receiving_exceptions%ROWTYPE;
  v_dn public.delivery_notes%ROWTYPE;
BEGIN
  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  SELECT *
  INTO v_exception
  FROM public.delivery_note_receiving_exceptions
  WHERE id = p_exception_id
    AND company_id = p_company_id
    AND dn_id = p_dn_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Receiving exception not found';
  END IF;

  IF v_exception.status <> 'pending_review' THEN
    RAISE EXCEPTION 'Only pending receiving exceptions can be reviewed';
  END IF;

  UPDATE public.delivery_note_receiving_exceptions
  SET
    status = 'rejected',
    notes = CONCAT_WS(E'\n', NULLIF(BTRIM(notes), ''), NULLIF(BTRIM(p_notes), '')),
    reviewed_by = p_user_id,
    reviewed_at = now(),
    updated_at = now()
  WHERE id = p_exception_id
    AND company_id = p_company_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.accept_delivery_note_receiving_exception(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_exception_id UUID,
  p_notes TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_exception public.delivery_note_receiving_exceptions%ROWTYPE;
  v_dn public.delivery_notes%ROWTYPE;
  v_item public.items%ROWTYPE;
  v_warehouse_id UUID;
  v_location_id UUID;
  v_stock_tx_id UUID;
  v_now TIMESTAMPTZ := now();
  v_posting_date DATE := CURRENT_DATE;
  v_posting_time TIME := now()::TIME;
  v_qty NUMERIC;
  v_current_stock NUMERIC := 0;
  v_next_stock NUMERIC := 0;
  v_item_batch public.item_batch%ROWTYPE;
BEGIN
  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  SELECT *
  INTO v_exception
  FROM public.delivery_note_receiving_exceptions
  WHERE id = p_exception_id
    AND company_id = p_company_id
    AND dn_id = p_dn_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Receiving exception not found';
  END IF;

  IF v_exception.status <> 'pending_review' THEN
    RAISE EXCEPTION 'Only pending receiving exceptions can be reviewed';
  END IF;

  v_qty := COALESCE(v_exception.accepted_qty, 0);
  IF v_qty <= 0 THEN
    RAISE EXCEPTION 'Accepted quantity must be greater than zero';
  END IF;

  SELECT *
  INTO v_item
  FROM public.items
  WHERE id = v_exception.item_id
    AND company_id = p_company_id
    AND deleted_at IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Item not found';
  END IF;

  v_warehouse_id := v_dn.requesting_warehouse_id;
  IF v_warehouse_id IS NULL THEN
    RAISE EXCEPTION 'Delivery note receiving warehouse is missing';
  END IF;

  INSERT INTO public.warehouse_locations (
    company_id,
    warehouse_id,
    code,
    name,
    location_type,
    is_pickable,
    is_storable,
    is_active,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_warehouse_id,
    'MAIN',
    'Main',
    'bin',
    TRUE,
    TRUE,
    TRUE,
    p_user_id,
    p_user_id
  )
  ON CONFLICT (company_id, warehouse_id, code) DO UPDATE
  SET updated_by = EXCLUDED.updated_by
  RETURNING id INTO v_location_id;

  v_location_id := COALESCE(v_exception.location_id, v_location_id);

  SELECT COALESCE(current_stock, 0)
  INTO v_current_stock
  FROM public.item_warehouse
  WHERE company_id = p_company_id
    AND item_id = v_exception.item_id
    AND warehouse_id = v_warehouse_id
    AND deleted_at IS NULL
  FOR UPDATE;

  v_current_stock := COALESCE(v_current_stock, 0);
  v_next_stock := v_current_stock + v_qty;

  INSERT INTO public.stock_transactions (
    company_id,
    business_unit_id,
    transaction_type,
    transaction_date,
    warehouse_id,
    to_location_id,
    reference_type,
    reference_id,
    reference_code,
    status,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    p_business_unit_id,
    'in',
    v_posting_date,
    v_warehouse_id,
    v_location_id,
    'delivery_note_receiving_exception',
    v_exception.id,
    v_dn.dn_no,
    'posted',
    COALESCE(NULLIF(BTRIM(p_notes), ''), 'Accepted unexpected item from delivery note ' || v_dn.dn_no),
    p_user_id,
    p_user_id
  )
  RETURNING id INTO v_stock_tx_id;

  INSERT INTO public.stock_transaction_items (
    company_id,
    transaction_id,
    item_id,
    quantity,
    uom_id,
    unit_cost,
    total_cost,
    qty_before,
    qty_after,
    valuation_rate,
    stock_value_before,
    stock_value_after,
    posting_date,
    posting_time,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_stock_tx_id,
    v_exception.item_id,
    v_qty,
    v_exception.uom_id,
    0,
    0,
    v_current_stock,
    v_next_stock,
    0,
    0,
    0,
    v_posting_date,
    v_posting_time,
    COALESCE(NULLIF(BTRIM(p_notes), ''), 'Accepted unexpected receiving exception'),
    p_user_id,
    p_user_id
  );

  INSERT INTO public.item_warehouse (
    company_id,
    item_id,
    warehouse_id,
    current_stock,
    default_location_id,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_exception.item_id,
    v_warehouse_id,
    v_qty,
    v_location_id,
    p_user_id,
    p_user_id
  )
  ON CONFLICT (company_id, item_id, warehouse_id) DO UPDATE
  SET
    current_stock = public.item_warehouse.current_stock + EXCLUDED.current_stock,
    default_location_id = COALESCE(public.item_warehouse.default_location_id, EXCLUDED.default_location_id),
    updated_by = EXCLUDED.updated_by,
    updated_at = v_now;

  INSERT INTO public.item_location (
    company_id,
    item_id,
    warehouse_id,
    location_id,
    qty_on_hand,
    qty_reserved,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_exception.item_id,
    v_warehouse_id,
    v_location_id,
    v_qty,
    0,
    p_user_id,
    p_user_id
  )
  ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
  SET
    qty_on_hand = public.item_location.qty_on_hand + EXCLUDED.qty_on_hand,
    updated_by = EXCLUDED.updated_by,
    updated_at = v_now;

  IF NULLIF(BTRIM(v_exception.batch_number), '') IS NOT NULL THEN
    SELECT *
    INTO v_item_batch
    FROM public.item_batch
    WHERE company_id = p_company_id
      AND item_id = v_exception.item_id
      AND warehouse_id = v_warehouse_id
      AND batch_code = v_exception.batch_number
      AND deleted_at IS NULL
    FOR UPDATE;

    IF FOUND THEN
      UPDATE public.item_batch
      SET
        qty_on_hand = qty_on_hand + v_qty,
        updated_by = p_user_id,
        updated_at = v_now
      WHERE id = v_item_batch.id
      RETURNING * INTO v_item_batch;
    ELSE
      INSERT INTO public.item_batch (
        company_id,
        item_id,
        warehouse_id,
        batch_code,
        received_at,
        qty_on_hand,
        qty_reserved,
        created_by,
        updated_by
      )
      VALUES (
        p_company_id,
        v_exception.item_id,
        v_warehouse_id,
        v_exception.batch_number,
        v_now,
        v_qty,
        0,
        p_user_id,
        p_user_id
      )
      RETURNING * INTO v_item_batch;
    END IF;

    INSERT INTO public.item_location_batch (
      company_id,
      item_id,
      warehouse_id,
      location_id,
      item_batch_id,
      qty_on_hand,
      qty_reserved,
      created_by,
      updated_by
    )
    VALUES (
      p_company_id,
      v_exception.item_id,
      v_warehouse_id,
      v_location_id,
      v_item_batch.id,
      v_qty,
      0,
      p_user_id,
      p_user_id
    )
    ON CONFLICT (company_id, item_id, warehouse_id, location_id, item_batch_id) DO UPDATE
    SET
      qty_on_hand = public.item_location_batch.qty_on_hand + EXCLUDED.qty_on_hand,
      updated_by = EXCLUDED.updated_by,
      updated_at = v_now;
  END IF;

  UPDATE public.delivery_note_receiving_exceptions
  SET
    status = 'accepted',
    notes = CONCAT_WS(E'\n', NULLIF(BTRIM(notes), ''), NULLIF(BTRIM(p_notes), '')),
    reviewed_by = p_user_id,
    reviewed_at = v_now,
    updated_at = v_now
  WHERE id = p_exception_id
    AND company_id = p_company_id;
END;
$$;

COMMIT;


-- ============================================================================
-- Migration: 20260514123000_add_delivery_note_overage_review.sql
-- ============================================================================

-- ============================================================================
-- Migration: Delivery note overage review
-- Description:
--   Records over-received delivery note line quantities as reviewable overages.
--   Accepted overages post stock through a separate inventory transaction.
--   Rejected overages create no stock movement.
-- ============================================================================

BEGIN;

ALTER TABLE public.delivery_note_items
  ADD COLUMN IF NOT EXISTS receiving_overage_review_status TEXT,
  ADD COLUMN IF NOT EXISTS receiving_overage_posted_qty NUMERIC(20, 4) NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS receiving_overage_review_notes TEXT,
  ADD COLUMN IF NOT EXISTS receiving_overage_reviewed_by UUID REFERENCES public.users(id),
  ADD COLUMN IF NOT EXISTS receiving_overage_reviewed_at TIMESTAMPTZ;

ALTER TABLE public.delivery_note_items
  DROP CONSTRAINT IF EXISTS chk_delivery_note_items_overage_review_status,
  ADD CONSTRAINT chk_delivery_note_items_overage_review_status
    CHECK (
      receiving_overage_review_status IS NULL
      OR receiving_overage_review_status IN ('pending_review', 'accepted', 'rejected')
    );

CREATE OR REPLACE FUNCTION public.submit_delivery_note_receiving(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_received_date DATE DEFAULT NULL,
  p_notes TEXT DEFAULT NULL,
  p_acknowledge_discrepancy BOOLEAN DEFAULT FALSE,
  p_discrepancy_notes TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn public.delivery_notes%ROWTYPE;
  v_item RECORD;
  v_items JSONB := '[]'::jsonb;
  v_has_postable_received_qty BOOLEAN := FALSE;
  v_has_any_scan BOOLEAN := FALSE;
  v_has_discrepancy BOOLEAN := FALSE;
  v_discrepancy_notes TEXT := NULLIF(BTRIM(p_discrepancy_notes), '');
  v_line_note TEXT;
  v_line_status TEXT;
  v_line_variance NUMERIC;
BEGIN
  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  IF v_dn.status <> 'dispatched' THEN
    RAISE EXCEPTION 'Only dispatched delivery notes can be submitted for receiving';
  END IF;

  IF v_dn.receiving_started_at IS NULL THEN
    RAISE EXCEPTION 'Receiving has not been started';
  END IF;

  FOR v_item IN
    SELECT
      dni.id,
      COALESCE(dni.dispatched_qty, 0) AS dispatched_qty,
      COALESCE(COUNT(scans.id) FILTER (WHERE scans.voided_at IS NULL), 0)::NUMERIC AS received_scan_count,
      LEAST(
        COALESCE(COUNT(scans.id) FILTER (WHERE scans.voided_at IS NULL), 0)::NUMERIC,
        COALESCE(dni.dispatched_qty, 0)
      ) AS post_received_qty
    FROM public.delivery_note_items dni
    LEFT JOIN public.delivery_note_item_receiving_scans scans
      ON scans.company_id = dni.company_id
     AND scans.dn_item_id = dni.id
    WHERE dni.company_id = p_company_id
      AND dni.dn_id = p_dn_id
      AND COALESCE(dni.is_voided, FALSE) = FALSE
    GROUP BY dni.id, dni.dispatched_qty
    ORDER BY dni.id
  LOOP
    v_line_variance := v_item.received_scan_count - v_item.dispatched_qty;
    v_line_status := CASE
      WHEN v_line_variance = 0 THEN 'exact'
      WHEN v_line_variance < 0 THEN 'short'
      ELSE 'over'
    END;
    v_line_note := CASE
      WHEN v_line_variance = 0 THEN
        FORMAT('Exact receive: scanned %s of %s.', v_item.received_scan_count, v_item.dispatched_qty)
      WHEN v_line_variance < 0 THEN
        FORMAT(
          'Short receive: scanned %s of %s. Short %s.',
          v_item.received_scan_count,
          v_item.dispatched_qty,
          ABS(v_line_variance)
        )
      ELSE
        FORMAT(
          'Over receive: scanned %s of %s. Over %s.',
          v_item.received_scan_count,
          v_item.dispatched_qty,
          v_line_variance
        )
    END;

    v_has_any_scan := v_has_any_scan OR v_item.received_scan_count > 0;
    v_has_discrepancy := v_has_discrepancy OR v_line_variance <> 0;

    UPDATE public.delivery_note_items
    SET
      received_qty = v_item.received_scan_count,
      receiving_variance_qty = v_line_variance,
      receiving_status = v_line_status,
      receiving_discrepancy_flag = v_line_variance <> 0,
      receiving_notes = CONCAT_WS(E'\n', v_line_note, v_discrepancy_notes),
      receiving_overage_review_status = CASE
        WHEN v_line_variance > 0 THEN 'pending_review'
        ELSE NULL
      END,
      receiving_overage_posted_qty = CASE
        WHEN v_line_variance > 0 THEN receiving_overage_posted_qty
        ELSE 0
      END,
      receiving_overage_review_notes = CASE
        WHEN v_line_variance > 0 THEN receiving_overage_review_notes
        ELSE NULL
      END,
      receiving_overage_reviewed_by = CASE
        WHEN v_line_variance > 0 THEN receiving_overage_reviewed_by
        ELSE NULL
      END,
      receiving_overage_reviewed_at = CASE
        WHEN v_line_variance > 0 THEN receiving_overage_reviewed_at
        ELSE NULL
      END,
      updated_at = now()
    WHERE company_id = p_company_id
      AND id = v_item.id;

    IF v_item.post_received_qty > 0 THEN
      v_has_postable_received_qty := TRUE;
      v_items := v_items || jsonb_build_array(
        jsonb_build_object(
          'deliveryNoteItemId', v_item.id,
          'receivedQty', v_item.post_received_qty,
          'locationId', NULL
        )
      );
    END IF;
  END LOOP;

  IF NOT v_has_any_scan THEN
    RAISE EXCEPTION 'No receiving scans have been recorded';
  END IF;

  IF v_has_discrepancy AND NOT COALESCE(p_acknowledge_discrepancy, FALSE) THEN
    RAISE EXCEPTION 'Receiving discrepancy acknowledgement is required';
  END IF;

  IF v_has_discrepancy AND v_discrepancy_notes IS NULL THEN
    RAISE EXCEPTION 'Receiving discrepancy notes are required';
  END IF;

  IF NOT v_has_postable_received_qty THEN
    RAISE EXCEPTION 'No receiving scans have been recorded';
  END IF;

  PERFORM public.post_delivery_note_receive(
    p_company_id,
    p_user_id,
    p_dn_id,
    p_business_unit_id,
    COALESCE(p_received_date, now()::DATE),
    p_notes,
    v_items
  );

  UPDATE public.delivery_notes
  SET
    receiving_completed_at = now(),
    receiving_completed_by = p_user_id,
    received_by = p_user_id,
    receiving_notes = COALESCE(NULLIF(BTRIM(p_notes), ''), receiving_notes),
    receiving_has_discrepancy = v_has_discrepancy,
    receiving_discrepancy_notes = CASE
      WHEN v_has_discrepancy THEN v_discrepancy_notes
      ELSE receiving_discrepancy_notes
    END,
    updated_by = p_user_id,
    updated_at = now()
  WHERE id = p_dn_id
    AND company_id = p_company_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.accept_delivery_note_receiving_overage(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_dn_item_id UUID,
  p_notes TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn public.delivery_notes%ROWTYPE;
  v_dn_item public.delivery_note_items%ROWTYPE;
  v_warehouse_id UUID;
  v_location_id UUID;
  v_stock_tx_id UUID;
  v_now TIMESTAMPTZ := now();
  v_posting_date DATE := CURRENT_DATE;
  v_posting_time TIME := now()::TIME;
  v_overage_qty NUMERIC;
  v_overage_base_qty NUMERIC;
  v_qty_per_unit NUMERIC := 1;
  v_item_base_uom_id UUID;
  v_current_stock NUMERIC := 0;
  v_next_stock NUMERIC := 0;
BEGIN
  SELECT *
  INTO v_dn
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  SELECT *
  INTO v_dn_item
  FROM public.delivery_note_items
  WHERE id = p_dn_item_id
    AND company_id = p_company_id
    AND dn_id = p_dn_id
    AND COALESCE(is_voided, FALSE) = FALSE
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note item not found';
  END IF;

  IF v_dn_item.receiving_overage_review_status <> 'pending_review' THEN
    RAISE EXCEPTION 'Only pending receiving overages can be reviewed';
  END IF;

  v_overage_qty := GREATEST(
    0,
    COALESCE(v_dn_item.received_qty, 0)
      - COALESCE(v_dn_item.dispatched_qty, 0)
      - COALESCE(v_dn_item.receiving_overage_posted_qty, 0)
  );

  IF v_overage_qty <= 0 THEN
    RAISE EXCEPTION 'No receiving overage is available to post';
  END IF;

  SELECT
    COALESCE(iuo.qty_per_unit, 1),
    i.uom_id
  INTO
    v_qty_per_unit,
    v_item_base_uom_id
  FROM public.items i
  LEFT JOIN public.item_unit_options iuo
    ON iuo.id = v_dn_item.item_unit_option_id
   AND iuo.deleted_at IS NULL
  WHERE i.id = v_dn_item.item_id
    AND i.company_id = p_company_id
    AND i.deleted_at IS NULL;

  IF v_item_base_uom_id IS NULL THEN
    RAISE EXCEPTION 'Item not found';
  END IF;

  v_overage_base_qty := v_overage_qty * COALESCE(v_qty_per_unit, 1);

  v_warehouse_id := v_dn.requesting_warehouse_id;
  IF v_warehouse_id IS NULL THEN
    RAISE EXCEPTION 'Delivery note receiving warehouse is missing';
  END IF;

  INSERT INTO public.warehouse_locations (
    company_id,
    warehouse_id,
    code,
    name,
    location_type,
    is_pickable,
    is_storable,
    is_active,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_warehouse_id,
    'MAIN',
    'Main',
    'bin',
    TRUE,
    TRUE,
    TRUE,
    p_user_id,
    p_user_id
  )
  ON CONFLICT (company_id, warehouse_id, code) DO UPDATE
  SET updated_by = EXCLUDED.updated_by
  RETURNING id INTO v_location_id;

  SELECT COALESCE(current_stock, 0)
  INTO v_current_stock
  FROM public.item_warehouse
  WHERE company_id = p_company_id
    AND item_id = v_dn_item.item_id
    AND warehouse_id = v_warehouse_id
    AND deleted_at IS NULL
  FOR UPDATE;

  v_current_stock := COALESCE(v_current_stock, 0);
  v_next_stock := v_current_stock + v_overage_base_qty;

  INSERT INTO public.stock_transactions (
    company_id,
    business_unit_id,
    transaction_type,
    transaction_date,
    warehouse_id,
    to_location_id,
    reference_type,
    reference_id,
    reference_code,
    status,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    p_business_unit_id,
    'in',
    v_posting_date,
    v_warehouse_id,
    v_location_id,
    'delivery_note_receiving_overage',
    v_dn_item.id,
    v_dn.dn_no,
    'posted',
    COALESCE(NULLIF(BTRIM(p_notes), ''), 'Accepted over-received quantity from delivery note ' || v_dn.dn_no),
    p_user_id,
    p_user_id
  )
  RETURNING id INTO v_stock_tx_id;

  INSERT INTO public.stock_transaction_items (
    company_id,
    transaction_id,
    item_id,
    quantity,
    uom_id,
    unit_cost,
    total_cost,
    qty_before,
    qty_after,
    valuation_rate,
    stock_value_before,
    stock_value_after,
    posting_date,
    posting_time,
    notes,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_stock_tx_id,
    v_dn_item.item_id,
    v_overage_base_qty,
    v_item_base_uom_id,
    0,
    0,
    v_current_stock,
    v_next_stock,
    0,
    0,
    0,
    v_posting_date,
    v_posting_time,
    COALESCE(NULLIF(BTRIM(p_notes), ''), 'Accepted delivery note receiving overage'),
    p_user_id,
    p_user_id
  );

  INSERT INTO public.item_warehouse (
    company_id,
    item_id,
    warehouse_id,
    current_stock,
    default_location_id,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_dn_item.item_id,
    v_warehouse_id,
    v_overage_base_qty,
    v_location_id,
    p_user_id,
    p_user_id
  )
  ON CONFLICT (company_id, item_id, warehouse_id) DO UPDATE
  SET
    current_stock = public.item_warehouse.current_stock + EXCLUDED.current_stock,
    default_location_id = COALESCE(public.item_warehouse.default_location_id, EXCLUDED.default_location_id),
    updated_by = EXCLUDED.updated_by,
    updated_at = v_now;

  INSERT INTO public.item_location (
    company_id,
    item_id,
    warehouse_id,
    location_id,
    qty_on_hand,
    qty_reserved,
    created_by,
    updated_by
  )
  VALUES (
    p_company_id,
    v_dn_item.item_id,
    v_warehouse_id,
    v_location_id,
    v_overage_base_qty,
    0,
    p_user_id,
    p_user_id
  )
  ON CONFLICT (company_id, item_id, warehouse_id, location_id) DO UPDATE
  SET
    qty_on_hand = public.item_location.qty_on_hand + EXCLUDED.qty_on_hand,
    updated_by = EXCLUDED.updated_by,
    updated_at = v_now;

  UPDATE public.delivery_note_items
  SET
    receiving_overage_review_status = 'accepted',
    receiving_overage_posted_qty = COALESCE(receiving_overage_posted_qty, 0) + v_overage_qty,
    receiving_overage_review_notes = CONCAT_WS(E'\n', NULLIF(BTRIM(receiving_overage_review_notes), ''), NULLIF(BTRIM(p_notes), '')),
    receiving_overage_reviewed_by = p_user_id,
    receiving_overage_reviewed_at = v_now,
    updated_at = v_now
  WHERE id = p_dn_item_id
    AND company_id = p_company_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.reject_delivery_note_receiving_overage(
  p_company_id UUID,
  p_business_unit_id UUID,
  p_user_id UUID,
  p_dn_id UUID,
  p_dn_item_id UUID,
  p_notes TEXT DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_dn_item public.delivery_note_items%ROWTYPE;
BEGIN
  IF p_business_unit_id IS NULL THEN
    RAISE EXCEPTION 'Business unit context required';
  END IF;

  PERFORM 1
  FROM public.delivery_notes
  WHERE id = p_dn_id
    AND company_id = p_company_id
    AND deleted_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note not found';
  END IF;

  SELECT *
  INTO v_dn_item
  FROM public.delivery_note_items
  WHERE id = p_dn_item_id
    AND company_id = p_company_id
    AND dn_id = p_dn_id
    AND COALESCE(is_voided, FALSE) = FALSE
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Delivery note item not found';
  END IF;

  IF v_dn_item.receiving_overage_review_status <> 'pending_review' THEN
    RAISE EXCEPTION 'Only pending receiving overages can be reviewed';
  END IF;

  UPDATE public.delivery_note_items
  SET
    receiving_overage_review_status = 'rejected',
    receiving_overage_review_notes = CONCAT_WS(E'\n', NULLIF(BTRIM(receiving_overage_review_notes), ''), NULLIF(BTRIM(p_notes), '')),
    receiving_overage_reviewed_by = p_user_id,
    receiving_overage_reviewed_at = now(),
    updated_at = now()
  WHERE id = p_dn_item_id
    AND company_id = p_company_id;
END;
$$;

COMMIT;


