CREATE OR REPLACE FUNCTION public.get_items_enhanced_stats(
  p_company_id UUID,
  p_search TEXT DEFAULT NULL,
  p_category_id UUID DEFAULT NULL,
  p_warehouse_id UUID DEFAULT NULL,
  p_item_type TEXT DEFAULT NULL,
  p_status TEXT DEFAULT NULL,
  p_business_unit_id UUID DEFAULT NULL
)
RETURNS TABLE (
  total_available_value NUMERIC,
  low_stock_count BIGINT,
  out_of_stock_count BIGINT,
  total_count BIGINT
)
LANGUAGE sql
STABLE
AS $$
WITH filtered_items AS (
  SELECT
    i.id,
    COALESCE(i.is_active, true) AS is_active,
    COALESCE(i.sales_price, 0) AS sales_price
  FROM public.items i
  WHERE i.company_id = p_company_id
    AND i.deleted_at IS NULL
    AND (
      p_search IS NULL
      OR p_search = ''
      OR i.item_code ILIKE ('%' || p_search || '%')
      OR i.item_name ILIKE ('%' || p_search || '%')
      OR COALESCE(i.item_name_cn, '') ILIKE ('%' || p_search || '%')
      OR EXISTS (
        SELECT 1
        FROM public.item_unit_options iuo
        WHERE iuo.company_id = i.company_id
          AND iuo.item_id = i.id
          AND iuo.deleted_at IS NULL
          AND COALESCE(iuo.barcode, '') ILIKE ('%' || p_search || '%')
      )
    )
    AND (p_category_id IS NULL OR i.category_id = p_category_id)
    AND (p_item_type IS NULL OR i.item_type = p_item_type)
),
warehouse_scope AS (
  SELECT
    iw.item_id,
    iw.available_stock AS available,
    iw.reorder_level,
    iw.max_quantity
  FROM public.item_warehouse iw
  INNER JOIN public.warehouses w ON w.id = iw.warehouse_id
  WHERE iw.company_id = p_company_id
    AND iw.deleted_at IS NULL
    AND w.deleted_at IS NULL
    AND (p_warehouse_id IS NULL OR iw.warehouse_id = p_warehouse_id)
    AND (
      p_warehouse_id IS NOT NULL
      OR p_business_unit_id IS NULL
      OR w.business_unit_id = p_business_unit_id
    )
),
stock_agg AS (
  SELECT
    ws.item_id,
    SUM(COALESCE(ws.available, 0)) AS available,
    MAX(COALESCE(ws.reorder_level, 0)) AS reorder_point,
    SUM(COALESCE(ws.max_quantity, 0)) AS max_stock_level
  FROM warehouse_scope ws
  GROUP BY ws.item_id
),
enriched AS (
  SELECT
    fi.id,
    fi.sales_price,
    CASE
      WHEN NOT fi.is_active THEN 'discontinued'
      WHEN COALESCE(sa.available, 0) <= 0 THEN 'out_of_stock'
      WHEN COALESCE(sa.reorder_point, 0) > 0
        AND COALESCE(sa.available, 0) <= COALESCE(sa.reorder_point, 0)
        THEN 'low_stock'
      WHEN COALESCE(sa.max_stock_level, 0) > 0
        AND COALESCE(sa.available, 0) > COALESCE(sa.max_stock_level, 0)
        THEN 'overstock'
      ELSE 'normal'
    END AS status,
    COALESCE(sa.available, 0) AS available
  FROM filtered_items fi
  LEFT JOIN stock_agg sa ON sa.item_id = fi.id
),
status_filtered AS (
  SELECT *
  FROM enriched e
  WHERE p_status IS NULL
    OR p_status = ''
    OR p_status = 'all'
    OR e.status = p_status
)
SELECT
  COALESCE(SUM(sf.available * sf.sales_price), 0) AS total_available_value,
  COUNT(*) FILTER (WHERE sf.status = 'low_stock') AS low_stock_count,
  COUNT(*) FILTER (WHERE sf.status = 'out_of_stock') AS out_of_stock_count,
  COUNT(*) AS total_count
FROM status_filtered sf;
$$;

DO $$
DECLARE
  v_function_sql TEXT;
BEGIN
  IF to_regprocedure('public.get_product_movement_report(uuid, uuid, text, date, date, uuid, text, integer, integer)') IS NULL THEN
    RAISE EXCEPTION 'Function public.get_product_movement_report(uuid, uuid, text, date, date, uuid, text, integer, integer) not found';
  END IF;

  v_function_sql := pg_get_functiondef(
    'public.get_product_movement_report(uuid, uuid, text, date, date, uuid, text, integer, integer)'::REGPROCEDURE
  );
  v_function_sql := REGEXP_REPLACE(
    v_function_sql,
    'COALESCE\(i\.' || 'cost_' || 'price,[[:space:]]*i\.purchase_price,[[:space:]]*0\)',
    'COALESCE(i.purchase_price, 0)',
    'g'
  );

  IF v_function_sql LIKE '%' || 'cost_' || 'price' || '%' THEN
    RAISE EXCEPTION 'Failed to remove legacy item cost column from get_product_movement_report';
  END IF;

  EXECUTE v_function_sql;
END;
$$;

DO $$
DECLARE
  v_function_sql TEXT;
BEGIN
  IF to_regprocedure('public.approve_grn_with_batch_inventory_apply_inventory(uuid, uuid, uuid, text)') IS NULL THEN
    RAISE EXCEPTION 'Function public.approve_grn_with_batch_inventory_apply_inventory(uuid, uuid, uuid, text) not found';
  END IF;

  v_function_sql := pg_get_functiondef(
    'public.approve_grn_with_batch_inventory_apply_inventory(uuid, uuid, uuid, text)'::REGPROCEDURE
  );
  v_function_sql := REGEXP_REPLACE(
    v_function_sql,
    'NULLIF\(i\.' || 'cost_' || 'price,[[:space:]]*0\),[[:space:]]*',
    '',
    'g'
  );

  IF v_function_sql LIKE '%' || 'cost_' || 'price' || '%' THEN
    RAISE EXCEPTION 'Failed to remove legacy item cost column from approve_grn_with_batch_inventory_apply_inventory';
  END IF;

  EXECUTE v_function_sql;
END;
$$;

COMMIT;


